diffs.replacement:
{
  "name": "VistoriaPro AI",
  "description": "Professional real estate inspection tool with AI-powered room analysis and automated PDF reports.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface Photo {
  id: string;
  data: string; // base64
  mimeType: string;
}

export interface Room {
  id: string;
  type: string;
  customName?: string;
  description: string;
  photos: Photo[];
  condition: 'Novo' | 'Bom' | 'Regular' | 'Ruim';
}

export interface Inspection {
  id: string;
  clientName: string;
  address: string;
  date: string;
  rooms: Room[];
  status: 'draft' | 'completed';
}

export const COMMON_ROOMS = [
  "Sala de Estar",
  "Cozinha",
  "Dormitório",
  "Suíte",
  "Banheiro Social",
  "Varanda/Sacada",
  "Área de Serviço",
  "Garagem",
  "Escritório",
  "Lavabo",
  "Quintal",
  "Corredor"
];

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Photo } from "../types";

export const analyzeRoomWithAI = async (roomType: string, photos: Photo[], notes?: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const textPart = {
    text: `Você é um perito em vistorias imobiliárias profissional. 
    Analise as imagens e as notas abaixo de um(a) ${roomType} e gere uma descrição técnica detalhada para um laudo de vistoria.
    Foque no estado de conservação de: paredes, piso, teto, janelas, portas e instalações elétricas/hidráulicas visíveis.
    Seja objetivo, profissional e use terminologia técnica adequada. 
    Idioma: Português do Brasil.

    Notas adicionais do vistoriador: ${notes || 'Nenhuma nota adicional fornecida.'}`
  };

  const imageParts = photos.slice(0, 3).map(photo => ({
    inlineData: {
      data: photo.data.split(',')[1],
      mimeType: photo.mimeType
    }
  }));

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { 
        parts: [textPart, ...imageParts] 
      },
    });

    return response.text || "Não foi possível gerar a descrição automaticamente.";
  } catch (error) {
    console.error("Erro ao analisar com Gemini:", error);
    return "Erro ao processar análise de IA. Verifique sua conexão e tente novamente.";
  }
};

import React from 'react';
import { Photo } from '../types';

interface PhotoUploaderProps {
  onPhotosAdded: (newPhotos: Photo[]) => void;
}

const PhotoUploader: React.FC<PhotoUploaderProps> = ({ onPhotosAdded }) => {
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newPhotos: Photo[] = [];
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const reader = new FileReader();
      const photoPromise = new Promise<Photo>((resolve) => {
        reader.onloadend = () => {
          resolve({
            id: Math.random().toString(36).substr(2, 9),
            data: reader.result as string,
            mimeType: file.type,
          });
        };
      });
      reader.readAsDataURL(file);
      newPhotos.push(await photoPromise);
    }
    onPhotosAdded(newPhotos);
    // Reset input
    e.target.value = '';
  };

  return (
    <div className="flex items-center justify-center w-full">
      <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-slate-300 rounded-xl cursor-pointer bg-white hover:bg-slate-50 transition-colors">
        <div className="flex flex-col items-center justify-center pt-5 pb-6">
          <svg className="w-8 h-8 mb-4 text-slate-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
            <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
          </svg>
          <p className="mb-2 text-sm text-slate-500 font-semibold">Clique para enviar ou tirar fotos</p>
          <p className="text-xs text-slate-400">PNG, JPG ou GIF</p>
        </div>
        <input 
          type="file" 
          multiple 
          accept="image/*" 
          capture="environment"
          className="hidden" 
          onChange={handleFileChange} 
        />
      </label>
    </div>
  );
};

export default PhotoUploader;

import React from 'react';
import { Inspection } from '../types';

