          <p className="text-lg font-medium">{inspection.clientName}</p>
        </div>
      </div>

      <div className="space-y-12">
        {inspection.rooms.map((room, idx) => (
          <div key={room.id} className="break-inside-avoid">
            <h2 className="text-xl font-bold text-slate-800 border-l-4 border-indigo-600 pl-3 mb-4 flex items-center gap-2">
              <span className="text-slate-400 text-sm">{idx + 1}.</span> {room.customName || room.type}
              <span className={`ml-auto text-xs px-2 py-1 rounded ${
                room.condition === 'Novo' ? 'bg-green-100 text-green-700' :
                room.condition === 'Bom' ? 'bg-blue-100 text-blue-700' :
                room.condition === 'Regular' ? 'bg-yellow-100 text-yellow-700' :
                'bg-red-100 text-red-700'
