            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
              {room.photos.map((photo) => (
                <div key={photo.id} className="aspect-square rounded-lg overflow-hidden border border-slate-100">
                  <img src={photo.data} alt="Evidência" className="w-full h-full object-cover" />
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>

      <div className="mt-16 pt-8 border-t border-slate-200 grid grid-cols-2 gap-12">
        <div className="text-center">
          <div className="h-px bg-slate-300 mb-2"></div>
          <p className="text-xs text-slate-500 uppercase">Assinatura do Vistoriador</p>
        </div>
        <div className="text-center">
          <div className="h-px bg-slate-300 mb-2"></div>
          <p className="text-xs text-slate-500 uppercase">Assinatura do Responsável</p>
        </div>
      </div>
    </div>
  );
};

export default InspectionReport;

import React, { useState, useEffect, useCallback } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('vistorias_pro_data');
    if (saved) setInspections(JSON.parse(saved));
  }, []);

  useEffect(() => {
    if (inspections.length > 0) {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(inspections));
    }
  }, [inspections]);

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;
    setInspections(prev => {
      const exists = prev.find(i => i.id === currentInspection.id);
      if (exists) return prev.map(i => i.id === currentInspection.id ? currentInspection : i);
      return [currentInspection, ...prev];
    });
    setView('list');
    setCurrentInspection(null);
  };

  const handlePrint = () => {
    window.print();
  };

  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-10">
        <div className="max-w-4xl mx-auto mb-6 flex justify-between items-center no-print px-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-indigo-600 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3">
            <button 
              onClick={handlePrint}
              className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir / PDF
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  return (
    <div className="min-h-screen">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-10 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-slate-900">VistoriaPro <span className="text-indigo-600">AI</span></h1>
              <p className="text-xs text-slate-500 font-medium">Smart Real Estate Inspection</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-semibold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200 flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"/></svg>
              Nova Vistoria
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-20 text-center">
                <div className="bg-slate-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-lg font-semibold text-slate-700">Nenhuma vistoria encontrada</h3>
                <p className="text-slate-500 max-w-xs mx-auto mt-2">Comece criando sua primeira vistoria profissional agora mesmo.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-6 text-indigo-600 font-semibold hover:text-indigo-700"
                >
                  + Adicionar novo laudo
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-2xl border border-slate-200 p-6 hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer group" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
                      {ins.rooms.length} Ambientes
                    </div>
                    <span className="text-xs text-slate-400 font-medium">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                  </div>
                  <h3 className="text-lg font-bold text-slate-900 mb-1 group-hover:text-indigo-600 transition-colors truncate">{ins.address || 'Endereço não informado'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate">{ins.clientName || 'Cliente não informado'}</p>
                  <div className="flex items-center justify-between border-t pt-4">
                    <button className="text-indigo-600 text-sm font-semibold flex items-center gap-1">
                      Editar
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="text-slate-400 hover:text-slate-600 transition-colors"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Header Form */}
            <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    placeholder="Rua, Número, Bairro, Cidade..."
                    className="w-full px-5 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-indigo-600 transition-all"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    placeholder="Nome completo"
                    className="w-full px-5 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-indigo-600 transition-all"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
              </div>
            </div>

            {/* Room Addition Area */}
            <div className="flex flex-col gap-6">
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-slate-900">Ambientes</h2>
                <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                  {COMMON_ROOMS.map(roomType => (
                    <button 
                      key={roomType}
                      onClick={() => addRoom(roomType)}
                      className="whitespace-nowrap bg-white border border-slate-200 text-slate-700 px-4 py-2 rounded-full text-sm font-medium hover:bg-slate-50 hover:border-indigo-200 transition-all active:scale-95"
                    >
                      + {roomType}
                    </button>
                  ))}
                  <button 
                    onClick={() => {
                      const name = prompt("Nome do ambiente:");
                      if (name) addRoom(name);
                    }}
                    className="whitespace-nowrap bg-indigo-50 text-indigo-700 px-4 py-2 rounded-full text-sm font-bold hover:bg-indigo-100 transition-all"
                  >
                    + Personalizado
                  </button>
                </div>
              </div>

              <div className="space-y-4">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm transition-all">
                    <div 
                      className="p-6 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-green-100 text-green-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-bold text-slate-900">{room.customName || room.type}</h4>
                          <p className="text-xs text-slate-500 font-medium">
                            {room.photos.length} fotos • {room.description ? 'Descrição preenchida' : 'Sem descrição'}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center gap-3">
                        <select 
                          className="text-xs font-bold border-none bg-slate-100 rounded-lg px-2 py-1 focus:ring-0"
                          value={room.condition}
                          onClick={(e) => e.stopPropagation()}
                          onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                        >
                          <option>Novo</option>
                          <option>Bom</option>
                          <option>Regular</option>
                          <option>Ruim</option>
                        </select>
                        <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180' : ''}`}>
                          <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/></svg>
                        </button>
                      </div>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 pt-0 border-t bg-slate-50/50 border-slate-100 space-y-6 animate-in slide-in-from-top-2">
                        <div className="pt-6">
                          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Evidências Fotográficas</label>
                          <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-3 mb-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-xl overflow-hidden group border border-slate-200 shadow-sm">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-3">
                          <div className="flex justify-between items-end">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Descrição Detalhada</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all shadow-sm ${
                                isAnalyzing ? 'bg-slate-200 text-slate-500 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
                              }`}
                            >
                              <svg className={`w-4 h-4 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Analisando...' : 'Descrever com IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-5 py-4 bg-white rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-indigo-600 transition-all text-sm leading-relaxed"
                            placeholder="Descreva o estado do ambiente ou use a IA para gerar automaticamente baseado nas fotos..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <button 
                          onClick={() => {
                            if(confirm("Deseja realmente remover este ambiente?")) {
                              setCurrentInspection({
                                ...currentInspection!,
                                rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                              });
                            }
                          }}
                          className="text-xs font-bold text-red-500 hover:text-red-700 transition-colors uppercase tracking-widest pt-4"
                        >
                          Remover Ambiente
                        </button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Sticky Actions */}
            <div className="sticky bottom-6 flex justify-between items-center bg-white/80 backdrop-blur-xl border border-slate-200 p-4 rounded-3xl shadow-2xl z-20">
              <button 
                onClick={() => setView('list')}
                className="px-6 py-3 text-slate-500 font-bold hover:text-slate-800 transition-colors"
              >
                Cancelar
              </button>
              <div className="flex gap-4">
                <button 
                  onClick={() => setView('report')}
                  className="px-6 py-3 bg-slate-100 text-slate-700 rounded-2xl font-bold hover:bg-slate-200 transition-all flex items-center gap-2"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"/></svg>
                  Visualizar Laudo
                </button>
                <button 
                  onClick={saveInspection}
                  className="px-10 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all active:scale-95"
                >
                  Salvar Vistoria
                </button>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer Info */}
      {view === 'list' && (
        <footer className="text-center py-10 text-slate-400 text-xs no-print">
          <p>© 2024 VistoriaPro AI • Desenvolvido para Peritos Profissionais</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('vistorias_pro_data');
    if (saved) setInspections(JSON.parse(saved));
  }, []);

  useEffect(() => {
    if (inspections.length > 0) {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(inspections));
    }
  }, [inspections]);

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;
    setInspections(prev => {
      const exists = prev.find(i => i.id === currentInspection.id);
      if (exists) return prev.map(i => i.id === currentInspection.id ? currentInspection : i);
      return [currentInspection, ...prev];
    });
    setView('list');
    setCurrentInspection(null);
  };

  const handlePrint = () => {
    window.print();
  };

  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-10">
        <div className="max-w-4xl mx-auto mb-6 flex justify-between items-center no-print px-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Editar Vistoria
          </button>
          <div className="flex gap-3">
            <button 
              onClick={handlePrint}
              className="bg-amber-600 text-white px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Gerar PDF / Imprimir
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-10 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg shadow-amber-900/20">
              <span className="text-slate-900 font-black text-xl">DO</span>
            </div>
            <div>
              <h1 className="text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-6 py-2.5 rounded-xl font-black uppercase text-xs tracking-widest hover:bg-amber-500 transition-all shadow-lg shadow-amber-900/20 flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Nova Vistoria
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-12 h-12 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Pronto para começar?</h3>
                <p className="text-slate-500 max-w-xs mx-auto mt-2 font-medium">Inicie um novo laudo profissional com inteligência artificial.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Criar Primeiro Laudo
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-2xl hover:-translate-y-1 transition-all cursor-pointer group" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                      {ins.rooms.length} Ambientes
                    </div>
                    <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 group-hover:text-amber-600 transition-colors truncate uppercase tracking-tighter">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">{ins.clientName || 'Cliente não identificado'}</p>
                  <div className="flex items-center justify-between border-t border-slate-50 pt-4">
                    <button className="text-amber-600 text-[10px] font-black uppercase tracking-widest flex items-center gap-1">
                      Editar
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
            {/* Header Form */}
            <div className="bg-white rounded-[2rem] border border-slate-200 p-10 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-32 h-32 bg-amber-50 rounded-full -mr-16 -mt-16 opacity-50"></div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative z-10">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    placeholder="Ex: Rua das Flores, 123..."
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    placeholder="Nome completo do interessado"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
              </div>
            </div>

            {/* Room Addition Area */}
            <div className="flex flex-col gap-6">
              <div className="flex items-center justify-between px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes para Vistoria</h2>
                <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar max-w-[60%]">
                  {COMMON_ROOMS.map(roomType => (
                    <button 
                      key={roomType}
                      onClick={() => addRoom(roomType)}
                      className="whitespace-nowrap bg-white border border-slate-200 text-slate-700 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest hover:border-amber-500 hover:text-amber-600 transition-all active:scale-95 shadow-sm"
                    >
                      + {roomType}
                    </button>
                  ))}
                  <button 
                    onClick={() => {
                      const name = prompt("Nome do ambiente:");
                      if (name) addRoom(name);
                    }}
                    className="whitespace-nowrap bg-slate-900 text-amber-500 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md"
                  >
                    + Novo
                  </button>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-all">
                    <div 
                      className="p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50/50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-5">
                        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-colors ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600 shadow-inner' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase tracking-tight text-lg">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">
                            {room.photos.length} fotos • {room.description ? 'Análise Concluída' : 'Aguardando Descrição'}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center gap-4" onClick={e => e.stopPropagation()}>
                        <select 
                          className="text-[10px] font-black uppercase tracking-widest border-none bg-slate-100 rounded-xl px-4 py-2 focus:ring-2 focus:ring-amber-500 transition-all appearance-none pr-8 cursor-pointer"
                          value={room.condition}
                          onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                        >
                          <option>Novo</option>
                          <option>Bom</option>
                          <option>Regular</option>
                          <option>Ruim</option>
                        </select>
                        <button className={`p-2 rounded-full bg-slate-50 text-slate-400 transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                        </button>
                      </div>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-8 pt-0 border-t bg-slate-50/30 border-slate-100 space-y-8 animate-in slide-in-from-top-4 duration-300">
                        <div className="pt-8">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 block">Captura de Imagens</label>
                          <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-4 mb-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden group border-2 border-white shadow-lg">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                  <button 
                                    onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                    className="bg-red-500 text-white p-2 rounded-xl shadow-xl hover:scale-110 transition-transform"
                                  >
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                                  </button>
                                </div>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Laudo Técnico do Ambiente</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' : 'bg-slate-900 text-amber-500 hover:bg-slate-800 active:scale-95 shadow-slate-900/10'
                              }`}
                            >
                              <svg className={`w-4 h-4 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Analisando...' : 'Analisar com IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-48 px-6 py-5 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium shadow-inner"
                            placeholder="Descreva as condições de conservação ou use a inteligência artificial para descrever automaticamente através das fotos capturadas..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end pt-4">
                          <button 
                            onClick={() => {
                              if(confirm("Deseja remover este ambiente do laudo?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 transition-colors uppercase tracking-[0.2em]"
                          >
                            Excluir Ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Sticky Actions */}
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-20">
              <div className="bg-slate-900/90 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-4">
                <button 
                  onClick={() => setView('list')}
                  className="px-6 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white transition-colors"
                >
                  Sair
                </button>
                <div className="flex gap-3">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 transition-all flex items-center gap-2 border border-white/5"
                  >
                    Visualizar
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl shadow-amber-900/20 transition-all active:scale-95"
                  >
                    Salvar Laudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer Info */}
      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Photo } from '../types';

interface PhotoUploaderProps {
  onPhotosAdded: (newPhotos: Photo[]) => void;
}

const PhotoUploader: React.FC<PhotoUploaderProps> = ({ onPhotosAdded }) => {
  const resizeImage = (file: File): Promise<Photo> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          let width = img.width;
          let height = img.height;

          // Redimensionar para no máximo 1200px de largura/altura para economizar espaço
          const MAX_SIZE = 1200;
          if (width > height) {
            if (width > MAX_SIZE) {
              height *= MAX_SIZE / width;
              width = MAX_SIZE;
            }
          } else {
            if (height > MAX_SIZE) {
              width *= MAX_SIZE / height;
              height = MAX_SIZE;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0, width, height);

          // Comprimir qualidade para 0.7 (70%)
          const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
          resolve({
            id: Math.random().toString(36).substr(2, 9),
            data: dataUrl,
            mimeType: 'image/jpeg',
          });
        };
        img.src = e.target?.result as string;
      };
      reader.readAsDataURL(file);
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newPhotos: Photo[] = [];
    for (let i = 0; i < files.length; i++) {
      const photo = await resizeImage(files[i]);
      newPhotos.push(photo);
    }
    onPhotosAdded(newPhotos);
    e.target.value = '';
  };

  return (
    <div className="flex items-center justify-center w-full">
      <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-slate-300 rounded-2xl cursor-pointer bg-white hover:bg-slate-50 transition-colors group">
        <div className="flex flex-col items-center justify-center pt-5 pb-6">
          <svg className="w-8 h-8 mb-3 text-slate-400 group-hover:text-amber-600 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/>
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/>
          </svg>
          <p className="text-xs text-slate-500 font-black uppercase tracking-widest">Tirar Fotos</p>
        </div>
        <input 
          type="file" 
          multiple 
          accept="image/*" 
          capture="environment"
          className="hidden" 
          onChange={handleFileChange} 
        />
      </label>
    </div>
  );
};

