import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);

  // Carregar dados iniciais do LocalStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        setInspections(JSON.parse(saved));
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      // Salva no localStorage imediatamente para garantir persistência
      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex justify-between items-center no-print px-4">
