  "Cozinha",
  "Dormitório",
  "Suíte",
  "Banheiro Social",
  "Varanda/Sacada",
  "Área de Serviço",
  "Garagem",
  "Escritório",
  "Lavabo",
  "Quintal",
  "Corredor"
];

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);

  // Carregar dados iniciais do LocalStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        setInspections(JSON.parse(saved));
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      // Salva no localStorage imediatamente para garantir persistência
      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex justify-between items-center no-print px-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3">
            <button 
              onClick={handlePrint}
              className="bg-amber-600 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir / PDF
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 md:w-12 md:h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-slate-900 font-black text-lg">DO</span>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-amber-500 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                      {ins.rooms.length} Ambientes
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">{ins.clientName || 'Cliente não informado'}</p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>
                <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
                  {COMMON_ROOMS.slice(0, 6).map(roomType => (
                    <button 
                      key={roomType}
                      onClick={() => addRoom(roomType)}
                      className="whitespace-nowrap bg-white border border-slate-200 text-slate-700 px-4 py-2 rounded-full text-[10px] font-black uppercase hover:border-amber-500 transition-all shadow-sm"
                    >
                      + {roomType}
                    </button>
                  ))}
                  <button 
                    onClick={() => {
                      const name = prompt("Nome do ambiente:");
                      if (name) addRoom(name);
                    }}
                    className="whitespace-nowrap bg-slate-900 text-amber-500 px-5 py-2 rounded-full text-[10px] font-black uppercase hover:bg-slate-800 transition-all"
                  >
                    + Novo
                  </button>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-amber-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => {
                              if(confirm("Remover ambiente?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        setInspections(JSON.parse(saved));
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      // Salva no localStorage imediatamente para garantir persistência
      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = (e: React.MouseEvent) => {
    e.preventDefault();
    window.print();
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento. Tente usar o botão Imprimir.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF. Tente usar a opção 'Imprimir'.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
             <button 
              type="button"
              onClick={handlePrint}
              className="flex-1 md:flex-none bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir
            </button>
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-amber-600 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 md:w-12 md:h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-slate-900 font-black text-lg">DO</span>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-amber-500 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                      {ins.rooms.length} Ambientes
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">{ins.clientName || 'Cliente não informado'}</p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>
                <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
                  {COMMON_ROOMS.slice(0, 6).map(roomType => (
                    <button 
                      key={roomType}
                      onClick={() => addRoom(roomType)}
                      className="whitespace-nowrap bg-white border border-slate-200 text-slate-700 px-4 py-2 rounded-full text-[10px] font-black uppercase hover:border-amber-500 transition-all shadow-sm"
                    >
                      + {roomType}
                    </button>
                  ))}
                  <button 
                    onClick={() => {
                      const name = prompt("Nome do ambiente:");
                      if (name) addRoom(name);
                    }}
                    className="whitespace-nowrap bg-slate-900 text-amber-500 px-5 py-2 rounded-full text-[10px] font-black uppercase hover:bg-slate-800 transition-all"
                  >
                    + Novo
                  </button>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-amber-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => {
                              if(confirm("Remover ambiente?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        setInspections(JSON.parse(saved));
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      // Salva no localStorage imediatamente para garantir persistência
      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = (e: React.MouseEvent) => {
    e.preventDefault();
    window.print();
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento. Tente usar o botão Imprimir.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF. Tente usar a opção 'Imprimir'.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
             <button 
              type="button"
              onClick={handlePrint}
              className="flex-1 md:flex-none bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir
            </button>
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-amber-600 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 md:w-12 md:h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-slate-900 font-black text-lg">DO</span>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-amber-500 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                      {ins.rooms.length} Ambientes
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">{ins.clientName || 'Cliente não informado'}</p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>

                {/* Dropdown de Ambientes */}
                <div className="relative w-full md:w-64">
                  <select
                    className="w-full appearance-none bg-white border border-slate-200 text-slate-700 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-amber-500 transition-all shadow-sm focus:outline-none focus:ring-2 focus:ring-amber-500 cursor-pointer"
                    onChange={(e) => {
                      if (e.target.value === 'custom') {
                        const name = prompt("Nome do novo ambiente:");
                        if (name) addRoom(name);
                      } else if (e.target.value) {
                        addRoom(e.target.value);
                      }
                      e.target.value = ""; // Reset do dropdown
                    }}
                    defaultValue=""
                  >
                    <option value="" disabled>+ Adicionar Ambiente</option>
                    {COMMON_ROOMS.map(room => (
                      <option key={room} value={room}>{room}</option>
                    ))}
                    <option value="custom" className="text-amber-600 font-bold">+ Outro / Personalizado...</option>
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-amber-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => {
                              if(confirm("Remover ambiente?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        setInspections(JSON.parse(saved));
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.type, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      // Salva no localStorage imediatamente para garantir persistência
      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = (e: React.MouseEvent) => {
    e.preventDefault();
    window.print();
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento. Tente usar o botão Imprimir.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF. Tente usar a opção 'Imprimir'.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
             <button 
              type="button"
              onClick={handlePrint}
              className="flex-1 md:flex-none bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir
            </button>
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-amber-600 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 md:w-12 md:h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-slate-900 font-black text-lg">DO</span>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-amber-500 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                      {ins.rooms.length} Ambientes
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">{ins.clientName || 'Cliente não informado'}</p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>

                {/* Dropdown de Ambientes */}
                <div className="relative w-full md:w-64">
                  <select
                    className="w-full appearance-none bg-white border border-slate-200 text-slate-700 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-amber-500 transition-all shadow-sm focus:outline-none focus:ring-2 focus:ring-amber-500 cursor-pointer"
                    value=""
                    onChange={(e) => {
                      const value = e.target.value;
                      if (value === 'custom') {
                        const name = prompt("Nome do novo ambiente:");
                        if (name) addRoom(name);
                      } else if (value) {
                        addRoom(value);
                      }
                    }}
                  >
                    <option value="" disabled>+ Adicionar Ambiente</option>
                    {COMMON_ROOMS.map(room => (
                      <option key={room} value={room}>{room}</option>
                    ))}
                    <option value="custom" className="text-amber-600 font-bold">+ Outro / Personalizado...</option>
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-amber-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => {
                              if(confirm("Remover ambiente?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        setInspections(JSON.parse(saved));
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      // Usa o nome personalizado se houver, para dar mais contexto à IA
      const contextName = room.customName || room.type;
      const result = await analyzeRoomWithAI(contextName, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      // Salva no localStorage imediatamente para garantir persistência
      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = (e: React.MouseEvent) => {
    e.preventDefault();
    window.print();
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento. Tente usar o botão Imprimir.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF. Tente usar a opção 'Imprimir'.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
             <button 
              type="button"
              onClick={handlePrint}
              className="flex-1 md:flex-none bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir
            </button>
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-amber-600 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 md:w-12 md:h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-slate-900 font-black text-lg">DO</span>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-amber-500 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                      {ins.rooms.length} Ambientes
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">{ins.clientName || 'Cliente não informado'}</p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente / Locatário</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.clientName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, clientName: e.target.value})}
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>

                {/* Dropdown de Ambientes */}
                <div className="relative w-full md:w-64">
                  <select
                    className="w-full appearance-none bg-white border border-slate-200 text-slate-700 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-amber-500 transition-all shadow-sm focus:outline-none focus:ring-2 focus:ring-amber-500 cursor-pointer"
                    value=""
                    onChange={(e) => {
                      const value = e.target.value;
                      if (value === 'custom') {
                        addRoom('Ambiente Personalizado');
                      } else if (value) {
                        addRoom(value);
                      }
                    }}
                  >
                    <option value="" disabled>+ Adicionar Ambiente</option>
                    {COMMON_ROOMS.map(room => (
                      <option key={room} value={room}>{room}</option>
                    ))}
                    <option value="custom" className="text-amber-600 font-bold">+ Outro / Personalizado...</option>
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">

                        {/* Campo de Nome do Ambiente */}
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Nome do Ambiente</label>
                          <input 
                            type="text" 
                            className="w-full px-4 py-3 bg-white rounded-xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 font-bold text-slate-700 uppercase"
                            value={room.customName !== undefined ? room.customName : room.type}
                            onChange={(e) => updateRoom(room.id, { customName: e.target.value })}
                            placeholder="Nome do ambiente..."
                          />
                        </div>

                        <div className="pt-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-amber-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => {
                              if(confirm("Remover ambiente?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

export interface Photo {
  id: string;
  data: string; // base64
  mimeType: string;
}

export interface Room {
  id: string;
  type: string;
  customName?: string;
  description: string;
  photos: Photo[];
  condition: 'Novo' | 'Bom' | 'Regular' | 'Ruim';
}

export interface Inspection {
  id: string;
  clientName: string; // Mantido para compatibilidade, espelha o primeiro locatário
  tenants: string[]; // Lista de locatários
  ownerName?: string; // Nome do proprietário
  type: 'Entrada' | 'Saída' | 'Constatação'; // Tipo da vistoria
  address: string;
  generalRemarks?: string;
  date: string;
  rooms: Room[];
  status: 'draft' | 'completed';
}

export const COMMON_ROOMS = [
  "Sala de Estar",
  "Cozinha",
  "Dormitório",
  "Suíte",
  "Banheiro Social",
  "Varanda/Sacada",
  "Área de Serviço",
  "Garagem",
  "Escritório",
  "Lavabo",
  "Quintal",
  "Corredor"
];

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage e Migrar esquema antigo se necessário
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        const parsedData = JSON.parse(saved);
        // Migração de dados para incluir novos campos
        const migratedData = parsedData.map((item: any) => ({
          ...item,
          type: item.type || 'Entrada',
          tenants: item.tenants || (item.clientName ? [item.clientName] : ['']),
          ownerName: item.ownerName || ''
        }));
        setInspections(migratedData);
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type: 'Entrada',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  // Funções de Gestão de Locatários
  const updateTenant = (index: number, value: string) => {
    if (!currentInspection) return;
    const newTenants = [...currentInspection.tenants];
    newTenants[index] = value;
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || '' // Mantém clientName sincronizado com o primeiro
    });
  };

  const addTenant = () => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      tenants: [...currentInspection.tenants, '']
    });
  };

  const removeTenant = (index: number) => {
    if (!currentInspection || currentInspection.tenants.length <= 1) return;
    const newTenants = currentInspection.tenants.filter((_, i) => i !== index);
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || ''
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const contextName = room.customName || room.type;
      const result = await analyzeRoomWithAI(contextName, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handlePrint = (e: React.MouseEvent) => {
    e.preventDefault();
    window.print();
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento. Tente usar o botão Imprimir.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF. Tente usar a opção 'Imprimir'.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-amber-600 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
             <button 
              type="button"
              onClick={handlePrint}
              className="flex-1 md:flex-none bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
              Imprimir
            </button>
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-amber-600 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-700 transition-all shadow-lg shadow-amber-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-amber-600/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 md:w-12 md:h-12 bg-amber-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-slate-900 font-black text-lg">DO</span>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">David Oliveira</h1>
              <p className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-[0.2em]">Corretor de Imóveis</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-amber-600 text-slate-900 px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-amber-500 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-amber-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-2">
                       <div className="bg-amber-50 text-amber-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
                        {ins.rooms.length} Ambientes
                      </div>
                      <div className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-200">
                        {ins.type || 'Vistoria'}
                      </div>
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">
                    {ins.tenants && ins.tenants[0] ? ins.tenants.join(', ') : 'Cliente não informado'}
                  </p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-amber-600 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                {/* Tipo de Vistoria e Proprietário */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Vistoria</label>
                  <select 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold appearance-none cursor-pointer"
                    value={currentInspection?.type}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, type: e.target.value as any})}
                  >
                    <option value="Entrada">Vistoria de Entrada</option>
                    <option value="Constatação">Vistoria de Constatação</option>
                    <option value="Saída">Vistoria de Saída</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Proprietário (Opcional)</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    placeholder="Nome do Proprietário"
                    value={currentInspection?.ownerName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, ownerName: e.target.value})}
                  />
                </div>

                {/* Endereço */}
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>

                {/* Locatários Múltiplos */}
                <div className="space-y-2 md:col-span-2">
                  <div className="flex justify-between items-center mb-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Locatários / Clientes</label>
                    <button 
                      onClick={addTenant}
                      className="text-[10px] font-black text-amber-600 uppercase tracking-widest hover:text-amber-700"
                    >
                      + Adicionar Outro
                    </button>
                  </div>
                  <div className="space-y-3">
                    {currentInspection?.tenants.map((tenant, idx) => (
                      <div key={idx} className="flex gap-2">
                        <input 
                          type="text"
                          className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold"
                          placeholder={`Nome do Locatário ${idx + 1}`}
                          value={tenant}
                          onChange={(e) => updateTenant(idx, e.target.value)}
                        />
                        {currentInspection.tenants.length > 1 && (
                          <button 
                            onClick={() => removeTenant(idx)}
                            className="bg-red-50 text-red-500 px-4 rounded-2xl hover:bg-red-100 transition-colors"
                          >
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Observações */}
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>

                {/* Dropdown de Ambientes */}
                <div className="relative w-full md:w-64">
                  <select
                    className="w-full appearance-none bg-white border border-slate-200 text-slate-700 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-amber-500 transition-all shadow-sm focus:outline-none focus:ring-2 focus:ring-amber-500 cursor-pointer"
                    value=""
                    onChange={(e) => {
                      const value = e.target.value;
                      if (value === 'custom') {
                        addRoom('Ambiente Personalizado');
                      } else if (value) {
                        addRoom(value);
                      }
                    }}
                  >
                    <option value="" disabled>+ Adicionar Ambiente</option>
                    {COMMON_ROOMS.map(room => (
                      <option key={room} value={room}>{room}</option>
                    ))}
                    <option value="custom" className="text-amber-600 font-bold">+ Outro / Personalizado...</option>
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-amber-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">

                        {/* Campo de Nome do Ambiente */}
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Nome do Ambiente</label>
                          <input 
                            type="text" 
                            className="w-full px-4 py-3 bg-white rounded-xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 font-bold text-slate-700 uppercase"
                            value={room.customName !== undefined ? room.customName : room.type}
                            onChange={(e) => updateRoom(room.id, { customName: e.target.value })}
                            placeholder="Nome do ambiente..."
                          />
                        </div>

                        <div className="pt-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-amber-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-amber-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => {
                              if(confirm("Remover ambiente?")) {
                                setCurrentInspection({
                                  ...currentInspection!,
                                  rooms: currentInspection!.rooms.filter(r => r.id !== room.id)
                                });
                              }
                            }}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-amber-600 text-slate-900 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-amber-500 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>David Oliveira • Vistoria Inteligente</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage e Migrar esquema antigo se necessário
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        const parsedData = JSON.parse(saved);
        // Migração de dados para incluir novos campos
        const migratedData = parsedData.map((item: any) => ({
          ...item,
          type: item.type || 'Entrada',
          tenants: item.tenants || (item.clientName ? [item.clientName] : ['']),
          ownerName: item.ownerName || ''
        }));
        setInspections(migratedData);
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type: 'Entrada',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const deleteRoom = (roomId: string) => {
    if (!currentInspection) return;
    if (confirm("Tem certeza que deseja remover este ambiente? Esta ação não pode ser desfeita.")) {
        // Se o ambiente sendo deletado estiver em edição, fecha o editor
        if (editingRoomId === roomId) {
            setEditingRoomId(null);
        }

        setCurrentInspection({
            ...currentInspection,
            rooms: currentInspection.rooms.filter(r => r.id !== roomId)
        });
    }
  };

  // Funções de Gestão de Locatários
  const updateTenant = (index: number, value: string) => {
    if (!currentInspection) return;
    const newTenants = [...currentInspection.tenants];
    newTenants[index] = value;
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || '' // Mantém clientName sincronizado com o primeiro
    });
  };

  const addTenant = () => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      tenants: [...currentInspection.tenants, '']
    });
  };

  const removeTenant = (index: number) => {
    if (!currentInspection || currentInspection.tenants.length <= 1) return;
    const newTenants = currentInspection.tenants.filter((_, i) => i !== index);
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || ''
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const contextName = room.customName || room.type;
      const result = await analyzeRoomWithAI(contextName, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-red-700 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
            {/* Botão de Imprimir Removido conforme solicitado */}
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-red-700 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-red-800 transition-all shadow-lg shadow-red-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
             <div className="w-10 h-10 md:w-12 md:h-12 bg-white rounded-xl flex items-center justify-center shadow-lg p-1">
               {/* Ícone Simplificado Qdez Header */}
                <svg viewBox="0 0 100 100" className="w-full h-full" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <circle cx="50" cy="50" r="45" fill="#be1e2d" />
                  <path d="M25 50L50 30L75 50V75H25V50Z" fill="white" />
                  <circle cx="50" cy="50" r="15" fill="#be1e2d" />
                </svg>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">Qdez Imóveis</h1>
              <p className="text-[9px] md:text-[10px] text-red-500 font-bold uppercase tracking-[0.2em]">CRECI 34.873 J</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-red-700 text-white px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-red-600 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-red-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-2">
                       <div className="bg-red-50 text-red-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-red-100">
                        {ins.rooms.length} Ambientes
                      </div>
                      <div className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-200">
                        {ins.type || 'Vistoria'}
                      </div>
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">
                    {ins.tenants && ins.tenants[0] ? ins.tenants.join(', ') : 'Cliente não informado'}
                  </p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-red-700 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                {/* Tipo de Vistoria e Proprietário */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Vistoria</label>
                  <select 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold appearance-none cursor-pointer"
                    value={currentInspection?.type}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, type: e.target.value as any})}
                  >
                    <option value="Entrada">Vistoria de Entrada</option>
                    <option value="Constatação">Vistoria de Constatação</option>
                    <option value="Saída">Vistoria de Saída</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Proprietário (Opcional)</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold"
                    placeholder="Nome do Proprietário"
                    value={currentInspection?.ownerName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, ownerName: e.target.value})}
                  />
                </div>

                {/* Endereço */}
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>

                {/* Locatários Múltiplos */}
                <div className="space-y-2 md:col-span-2">
                  <div className="flex justify-between items-center mb-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Locatários / Clientes</label>
                    <button 
                      onClick={addTenant}
                      className="text-[10px] font-black text-red-600 uppercase tracking-widest hover:text-red-700"
                    >
                      + Adicionar Outro
                    </button>
                  </div>
                  <div className="space-y-3">
                    {currentInspection?.tenants.map((tenant, idx) => (
                      <div key={idx} className="flex gap-2">
                        <input 
                          type="text"
                          className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold"
                          placeholder={`Nome do Locatário ${idx + 1}`}
                          value={tenant}
                          onChange={(e) => updateTenant(idx, e.target.value)}
                        />
                        {currentInspection.tenants.length > 1 && (
                          <button 
                            onClick={() => removeTenant(idx)}
                            className="bg-red-50 text-red-500 px-4 rounded-2xl hover:bg-red-100 transition-colors"
                          >
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Observações */}
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>

                {/* Dropdown de Ambientes */}
                <div className="relative w-full md:w-64">
                  <select
                    className="w-full appearance-none bg-white border border-slate-200 text-slate-700 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-red-500 transition-all shadow-sm focus:outline-none focus:ring-2 focus:ring-red-500 cursor-pointer"
                    value=""
                    onChange={(e) => {
                      const value = e.target.value;
                      if (value === 'custom') {
                        addRoom('Ambiente Personalizado');
                      } else if (value) {
                        addRoom(value);
                      }
                    }}
                  >
                    <option value="" disabled>+ Adicionar Ambiente</option>
                    {COMMON_ROOMS.map(room => (
                      <option key={room} value={room}>{room}</option>
                    ))}
                    <option value="custom" className="text-red-600 font-bold">+ Outro / Personalizado...</option>
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-red-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">

                        {/* Campo de Nome do Ambiente */}
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Nome do Ambiente</label>
                          <input 
                            type="text" 
                            className="w-full px-4 py-3 bg-white rounded-xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 uppercase"
                            value={room.customName !== undefined ? room.customName : room.type}
                            onChange={(e) => updateRoom(room.id, { customName: e.target.value })}
                            placeholder="Nome do ambiente..."
                          />
                        </div>

                        <div className="pt-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-red-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={() => deleteRoom(room.id)}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest bg-red-50 hover:bg-red-100 px-4 py-2 rounded-lg transition-colors"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-red-700 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>Qdez Imóveis • CRECI 34.873 J</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage e Migrar esquema antigo se necessário
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        const parsedData = JSON.parse(saved);
        // Migração de dados para incluir novos campos
        const migratedData = parsedData.map((item: any) => ({
          ...item,
          type: item.type || 'Entrada',
          tenants: item.tenants || (item.clientName ? [item.clientName] : ['']),
          ownerName: item.ownerName || ''
        }));
        setInspections(migratedData);
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type: 'Entrada',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const deleteRoom = (roomId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!currentInspection) return;
    if (confirm("Tem certeza que deseja remover este ambiente? Esta ação não pode ser desfeita.")) {
        // Se o ambiente sendo deletado estiver em edição, fecha o editor
        if (editingRoomId === roomId) {
            setEditingRoomId(null);
        }

        setCurrentInspection({
            ...currentInspection,
            rooms: currentInspection.rooms.filter(r => r.id !== roomId)
        });
    }
  };

  // Funções de Gestão de Locatários
  const updateTenant = (index: number, value: string) => {
    if (!currentInspection) return;
    const newTenants = [...currentInspection.tenants];
    newTenants[index] = value;
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || '' // Mantém clientName sincronizado com o primeiro
    });
  };

  const addTenant = () => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      tenants: [...currentInspection.tenants, '']
    });
  };

  const removeTenant = (index: number) => {
    if (!currentInspection || currentInspection.tenants.length <= 1) return;
    const newTenants = currentInspection.tenants.filter((_, i) => i !== index);
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || ''
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const contextName = room.customName || room.type;
      const result = await analyzeRoomWithAI(contextName, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-red-700 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
            {/* Botão de Imprimir Removido conforme solicitado */}
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-red-700 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-red-800 transition-all shadow-lg shadow-red-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
             <div className="w-10 h-10 md:w-12 md:h-12 bg-white rounded-xl flex items-center justify-center shadow-lg p-1">
               {/* Ícone Simplificado Qdez Header */}
                <svg viewBox="0 0 100 100" className="w-full h-full" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <circle cx="50" cy="50" r="45" fill="#be1e2d" />
                  <path d="M25 50L50 30L75 50V75H25V50Z" fill="white" />
                  <circle cx="50" cy="50" r="15" fill="#be1e2d" />
                </svg>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">Qdez Imóveis</h1>
              <p className="text-[9px] md:text-[10px] text-red-500 font-bold uppercase tracking-[0.2em]">CRECI 34.873 J</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
              className="bg-red-700 text-white px-4 md:px-6 py-2 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest hover:bg-red-600 transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
              Novo Laudo
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-8 flex-grow no-print">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {inspections.length === 0 ? (
              <div className="col-span-full py-24 text-center">
                <div className="bg-slate-200 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 uppercase">Nenhuma vistoria</h3>
                <p className="text-slate-500 mt-2 font-medium">Inicie um novo laudo profissional agora.</p>
                <button 
                  onClick={createNewInspection}
                  className="mt-8 bg-slate-900 text-red-500 px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                >
                  Começar agora
                </button>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-3xl border border-slate-200 p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col h-full" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-2">
                       <div className="bg-red-50 text-red-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-red-100">
                        {ins.rooms.length} Ambientes
                      </div>
                      <div className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-200">
                        {ins.type || 'Vistoria'}
                      </div>
                    </div>
                    <button 
                      onClick={(e) => deleteInspection(ins.id, e)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    </button>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 mb-1 truncate uppercase tracking-tight">{ins.address || 'Endereço Pendente'}</h3>
                  <p className="text-sm text-slate-500 mb-6 truncate font-medium">
                    {ins.tenants && ins.tenants[0] ? ins.tenants.join(', ') : 'Cliente não informado'}
                  </p>
                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(ins.date).toLocaleDateString('pt-BR')}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }}
                      className="bg-slate-100 p-2 rounded-lg text-slate-400 hover:bg-red-700 hover:text-white transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : (
          <div className="space-y-8 pb-32">
            <div className="bg-white rounded-[2rem] border border-slate-200 p-6 md:p-10 shadow-sm relative overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                {/* Tipo de Vistoria e Proprietário */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Vistoria</label>
                  <select 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold appearance-none cursor-pointer"
                    value={currentInspection?.type}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, type: e.target.value as any})}
                  >
                    <option value="Entrada">Vistoria de Entrada</option>
                    <option value="Constatação">Vistoria de Constatação</option>
                    <option value="Saída">Vistoria de Saída</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Proprietário (Opcional)</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold"
                    placeholder="Nome do Proprietário"
                    value={currentInspection?.ownerName}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, ownerName: e.target.value})}
                  />
                </div>

                {/* Endereço */}
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço do Imóvel</label>
                  <input 
                    type="text"
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold"
                    value={currentInspection?.address}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, address: e.target.value})}
                  />
                </div>

                {/* Locatários Múltiplos */}
                <div className="space-y-2 md:col-span-2">
                  <div className="flex justify-between items-center mb-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Locatários / Clientes</label>
                    <button 
                      onClick={addTenant}
                      className="text-[10px] font-black text-red-600 uppercase tracking-widest hover:text-red-700"
                    >
                      + Adicionar Outro
                    </button>
                  </div>
                  <div className="space-y-3">
                    {currentInspection?.tenants.map((tenant, idx) => (
                      <div key={idx} className="flex gap-2">
                        <input 
                          type="text"
                          className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold"
                          placeholder={`Nome do Locatário ${idx + 1}`}
                          value={tenant}
                          onChange={(e) => updateTenant(idx, e.target.value)}
                        />
                        {currentInspection.tenants.length > 1 && (
                          <button 
                            onClick={() => removeTenant(idx)}
                            className="bg-red-50 text-red-500 px-4 rounded-2xl hover:bg-red-100 transition-colors"
                          >
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Observações */}
                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações Gerais</label>
                  <textarea 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all font-semibold min-h-[100px]"
                    placeholder="Notas adicionais sobre a vistoria, chaves, estado geral externo, etc..."
                    value={currentInspection?.generalRemarks || ''}
                    onChange={(e) => currentInspection && setCurrentInspection({...currentInspection, generalRemarks: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Ambientes</h2>

                {/* Dropdown de Ambientes */}
                <div className="relative w-full md:w-64">
                  <select
                    className="w-full appearance-none bg-white border border-slate-200 text-slate-700 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-red-500 transition-all shadow-sm focus:outline-none focus:ring-2 focus:ring-red-500 cursor-pointer"
                    value=""
                    onChange={(e) => {
                      const value = e.target.value;
                      if (value === 'custom') {
                        addRoom('Ambiente Personalizado');
                      } else if (value) {
                        addRoom(value);
                      }
                    }}
                  >
                    <option value="" disabled>+ Adicionar Ambiente</option>
                    {COMMON_ROOMS.map(room => (
                      <option key={room} value={room}>{room}</option>
                    ))}
                    <option value="custom" className="text-red-600 font-bold">+ Outro / Personalizado...</option>
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                {currentInspection?.rooms.map((room) => (
                  <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                    <div 
                      className="p-6 md:p-8 flex justify-between items-center cursor-pointer hover:bg-slate-50"
                      onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${room.photos.length > 0 ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-900 uppercase text-base">{room.customName || room.type}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{room.photos.length} Fotos • {room.condition}</p>
                        </div>
                      </div>
                      <button className={`p-2 rounded-full transition-transform ${editingRoomId === room.id ? 'rotate-180 text-red-600' : ''}`}>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </button>
                    </div>

                    {editingRoomId === room.id && (
                      <div className="p-6 md:p-8 pt-0 border-t bg-slate-50/20 border-slate-100 space-y-6">

                        {/* Campo de Nome do Ambiente */}
                        <div className="pt-6">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Nome do Ambiente</label>
                          <input 
                            type="text" 
                            className="w-full px-4 py-3 bg-white rounded-xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 uppercase"
                            value={room.customName !== undefined ? room.customName : room.type}
                            onChange={(e) => updateRoom(room.id, { customName: e.target.value })}
                            placeholder="Nome do ambiente..."
                          />
                        </div>

                        <div className="pt-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 block">Fotos do Ambiente</label>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button 
                                  onClick={() => updateRoom(room.id, { photos: room.photos.filter(ph => ph.id !== p.id) })}
                                  className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-lg shadow-lg"
                                >
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                                </button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Condição</label>
                            <select 
                              className="text-[10px] font-black uppercase tracking-widest border-none bg-white rounded-xl px-4 py-2 ring-1 ring-slate-200"
                              value={room.condition}
                              onChange={(e) => updateRoom(room.id, { condition: e.target.value as any })}
                            >
                              <option>Novo</option>
                              <option>Bom</option>
                              <option>Regular</option>
                              <option>Ruim</option>
                            </select>
                          </div>

                          <div className="flex justify-between items-center pt-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</label>
                            <button 
                              onClick={() => handleAIAnalysis(room)}
                              disabled={isAnalyzing || room.photos.length === 0}
                              className={`flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                isAnalyzing ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-slate-900 text-red-500 hover:bg-slate-800'
                              }`}
                            >
                              <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/>
                              </svg>
                              {isAnalyzing ? 'Gerando...' : 'Análise IA'}
                            </button>
                          </div>
                          <textarea 
                            className="w-full h-40 px-6 py-4 bg-white rounded-3xl border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-red-600 transition-all text-sm leading-relaxed font-medium"
                            placeholder="Descreva as condições ou use IA..."
                            value={room.description}
                            onChange={(e) => updateRoom(room.id, { description: e.target.value })}
                          ></textarea>
                        </div>

                        <div className="flex justify-end">
                          <button 
                            onClick={(e) => deleteRoom(room.id, e)}
                            className="text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest bg-red-50 hover:bg-red-100 px-4 py-2 rounded-lg transition-colors"
                          >
                            Excluir ambiente
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Ações Fixas */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl flex justify-between items-center gap-3">
                <button 
                  onClick={() => setView('list')}
                  className="px-4 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-white"
                >
                  Sair
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setView('report')}
                    className="px-6 py-3 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 border border-white/5"
                  >
                    Ver Laudo
                  </button>
                  <button 
                    onClick={saveInspection}
                    className="px-8 py-3 bg-red-700 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-xl transition-all active:scale-95"
                  >
                    Salvar Tudo
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] no-print mt-auto">
          <p>Qdez Imóveis • CRECI 34.873 J</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Inspection, Room, Photo, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Carregar dados iniciais do LocalStorage e Migrar esquema antigo se necessário
  useEffect(() => {
    try {
      const saved = localStorage.getItem('vistorias_pro_data');
      if (saved) {
        const parsedData = JSON.parse(saved);
        // Migração de dados para incluir novos campos
        const migratedData = parsedData.map((item: any) => ({
          ...item,
          type: item.type || 'Entrada',
          tenants: item.tenants || (item.clientName ? [item.clientName] : ['']),
          ownerName: item.ownerName || ''
        }));
        setInspections(migratedData);
      }
    } catch (e) {
      console.error("Erro ao carregar dados do localStorage", e);
    }
  }, []);

  const saveToLocalStorage = (data: Inspection[]) => {
    try {
      localStorage.setItem('vistorias_pro_data', JSON.stringify(data));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        alert("Limite de memória atingido! Tente remover vistorias antigas ou usar menos fotos por ambiente (as fotos são salvas no seu navegador).");
      } else {
        console.error("Erro ao salvar no localStorage", e);
      }
    }
  };

  const createNewInspection = () => {
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type: 'Entrada',
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const deleteRoom = (roomId: string, e: React.MouseEvent) => {
    e.preventDefault(); // Impede comportamento padrão
    e.stopPropagation(); // Impede que o clique feche o acordeão

    if (!currentInspection) return;

    if (window.confirm("Tem certeza que deseja remover este ambiente? Esta ação não pode ser desfeita.")) {
        // Usa atualização funcional para garantir estado atualizado
        setCurrentInspection(prev => {
            if (!prev) return null;
            return {
                ...prev,
                rooms: prev.rooms.filter(r => r.id !== roomId)
            };
        });

        // Se o ambiente deletado estiver aberto, limpa o estado de edição
        if (editingRoomId === roomId) {
            setEditingRoomId(null);
        }
    }
  };

  // Funções de Gestão de Locatários
  const updateTenant = (index: number, value: string) => {
    if (!currentInspection) return;
    const newTenants = [...currentInspection.tenants];
    newTenants[index] = value;
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || '' // Mantém clientName sincronizado com o primeiro
    });
  };

  const addTenant = () => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      tenants: [...currentInspection.tenants, '']
    });
  };

  const removeTenant = (index: number) => {
    if (!currentInspection || currentInspection.tenants.length <= 1) return;
    const newTenants = currentInspection.tenants.filter((_, i) => i !== index);
    setCurrentInspection({
      ...currentInspection,
      tenants: newTenants,
      clientName: newTenants[0] || ''
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0) {
      alert("Adicione pelo menos uma foto para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const contextName = room.customName || room.type;
      const result = await analyzeRoomWithAI(contextName, room.photos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Falha ao analisar ambiente. Verifique sua conexão.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveInspection = () => {
    if (!currentInspection) return;

    setInspections(prev => {
      const updated = [...prev];
      const index = updated.findIndex(i => i.id === currentInspection.id);

      if (index !== -1) {
        updated[index] = { ...currentInspection, status: 'completed' };
      } else {
        updated.unshift({ ...currentInspection, status: 'completed' });
      }

      saveToLocalStorage(updated);
      return updated;
    });

    setView('list');
    setCurrentInspection(null);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente esta vistoria?")) {
      const filtered = inspections.filter(i => i.id !== id);
      setInspections(filtered);
      saveToLocalStorage(filtered);
    }
  };

  const handleDownloadPdf = () => {
    // @ts-ignore
    if (!window.html2pdf) {
      alert("Recurso de PDF indisponível no momento.");
      return;
    }

    setIsGeneratingPdf(true);
    const element = document.getElementById('report-content');
    const opt = {
      margin: [10, 10, 10, 10], // top, left, bottom, right (mm)
      filename: `vistoria-${currentInspection?.clientName?.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'laudo'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save().then(() => {
      setIsGeneratingPdf(false);
    }).catch((err: any) => {
      console.error(err);
      setIsGeneratingPdf(false);
      alert("Erro ao gerar PDF.");
    });
  };

  // Renderização do Relatório (Modo Impressão)
  if (view === 'report' && currentInspection) {
    return (
      <div className="min-h-screen bg-slate-100 py-6 md:py-12">
        <div className="max-w-4xl mx-auto mb-6 flex flex-col md:flex-row justify-between items-center no-print px-4 gap-4">
          <button 
            onClick={() => setView('editor')}
            className="flex items-center gap-2 text-slate-600 hover:text-red-700 transition-colors font-bold uppercase text-xs tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            Voltar ao Editor
          </button>
          <div className="flex gap-3 w-full md:w-auto">
            <button 
              type="button"
              onClick={handleDownloadPdf}
              disabled={isGeneratingPdf}
              className="flex-1 md:flex-none bg-red-700 text-white px-6 md:px-8 py-3 rounded-xl font-black uppercase text-xs tracking-[0.2em] hover:bg-red-800 transition-all shadow-lg shadow-red-200 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingPdf ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
              )}
              {isGeneratingPdf ? 'Gerando...' : 'Baixar PDF'}
            </button>
          </div>
        </div>
        <InspectionReport inspection={currentInspection} />
      </div>
    );
  }

  // Renderização Principal (Lista ou Editor)
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
             <div className="w-10 h-10 md:w-12 md:h-12 bg-white rounded-xl flex items-center justify-center shadow-lg p-1">
                <svg viewBox="0 0 100 100" className="w-full h-full" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <circle cx="50" cy="50" r="45" fill="#be1e2d" />
                  <path d="M25 50L50 30L75 50V75H25V50Z" fill="white" />
                  <circle cx="50" cy="50" r="15" fill="#be1e2d" />
                </svg>
            </div>
            <div>
              <h1 className="text-base md:text-lg font-black tracking-tighter text-white uppercase">Qdez Imóveis</h1>
              <p className="text-[9px] md:text-[10px] text-red-500 font-bold uppercase tracking-[0.2em]">CRECI 34.873 J</p>
            </div>
          </div>
          {view === 'list' && (
            <button 
              onClick={createNewInspection}
