                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="text-center py-12 text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] mt-auto">
        <p>Qdez Imóveis • CRECI 34.873 J</p>
      </footer>
    </div>
  );
};

