import { GoogleGenAI } from "@google/genai";
import { Photo, Video } from "../types";

export const analyzeRoomWithAI = async (roomType: string, photos: Photo[], videos: Video[], notes?: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const textPart = {
    text: `Você é um perito em vistorias imobiliárias profissional. Analise as imagens de um(a) ${roomType} e gere uma descrição técnica detalhada. Notas: ${notes || 'Nenhuma'}`
  };

  const imageParts = photos.slice(0, 4).map(photo => ({
    inlineData: {
      data: photo.data.split(',')[1],
      mimeType: photo.mimeType
    }
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [textPart, ...imageParts] },
    });
    return response.text || "Erro ao gerar descrição.";
  } catch (error) {
    return "Erro no processamento da IA.";
  }
};

export const compareInspectionsAI = async (entryPdfBase64: string, exitPdfBase64: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Você é um perito avaliador de imóveis sênior. Recebi dois laudos de vistoria (Entrada e Saída) em PDF.

    TAREFA:
    1. Compare minuciosamente os dois laudos.
    2. Liste todas as divergências por ambiente.
    3. Classifique cada dano como 'Estrutural' (responsabilidade locador) ou 'Locatário' (responsabilidade locatário).
    4. Realize uma pesquisa na internet por preços de materiais de construção atuais para o estado de São Paulo.
    5. Utilize a TABELA SINAPI (São Paulo) como base para calcular os valores de mão de obra para cada reparo identificado.
    6. Liste os sites e links onde os preços dos materiais foram encontrados (ex: Leroy Merlin, Telhanorte).

    FORMATO DE RESPOSTA (Markdown):
    ### 1. Quadro Comparativo de Divergências
    (Tabela com: Ambiente | Item | Estado Entrada | Estado Saída | Responsável)

    ### 2. Orçamento Estimado de Reparos
    (Tabela com: Item | Quantidade | Valor Material | Valor Mão de Obra (SINAPI SP) | Fonte do Preço (Link))

    ### 3. Conclusão Pericial
    (Resumo técnico final)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          parts: [
            { text: prompt },
            { inlineData: { data: entryPdfBase64, mimeType: 'application/pdf' } },
            { inlineData: { data: exitPdfBase64, mimeType: 'application/pdf' } }
          ]
        }
      ],
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    // Nota: O resultado conterá groundingMetadata com os URLs reais
    let output = response.text || "Falha na análise.";

    // Anexar fontes encontradas no final
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      output += "\n\n### Fontes de Preços Consultadas:\n";
      response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
        if (chunk.web) {
          output += `- [${chunk.web.title}](${chunk.web.uri})\n`;
        }
      });
    }

    return output;
  } catch (error) {
    console.error(error);
    return "Erro ao realizar comparação inteligente. Certifique-se que os PDFs são válidos.";
  }
};

import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, Photo, Video, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI, compareInspectionsAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isSavingDraft, setIsSavingDraft] = useState(false);

  // States para comparação
  const [entryPdf, setEntryPdf] = useState<string | null>(null);
  const [exitPdf, setExitPdf] = useState<string | null>(null);
  const [comparisonOutput, setComparisonOutput] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const saved: Inspection[] | null = await localforage.getItem('vistorias_pro_data');
        if (saved) setInspections(saved);
      } catch (e) { console.error(e); }
    };
    loadData();
  }, []);

  const saveToStorage = async (data: Inspection[]) => {
    try { await localforage.setItem('vistorias_pro_data', data); } 
    catch (e) { alert("Espaço insuficiente no dispositivo."); }
  };

  const createNewInspection = (type: 'Entrada' | 'Saída' | 'Constatação' | 'Comparação' = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setComparisonOutput(null);
      return;
    }
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type,
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const handlePdfUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'entry' | 'exit') => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      if (target === 'entry') setEntryPdf(base64);
      else setExitPdf(base64);
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!entryPdf || !exitPdf) {
      alert("Por favor, anexe os dois PDFs para comparação.");
      return;
    }
    setIsAnalyzing(true);
    const result = await compareInspectionsAI(entryPdf, exitPdf);
    setComparisonOutput(result);
    setIsAnalyzing(false);
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    setCurrentInspection({ ...currentInspection, rooms: [...currentInspection.rooms, newRoom] });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const saveInspection = async () => {
    if (!currentInspection) return;
    const updated = [currentInspection, ...inspections.filter(i => i.id !== currentInspection.id)];
    setInspections(updated);
    await saveToStorage(updated);
    setView('list');
    setCurrentInspection(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col no-select print:block">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => { setView('list'); setCurrentInspection(null); }}>
             <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center p-1 shadow-inner">
                <svg viewBox="0 0 100 100" className="w-full h-full" fill="none"><circle cx="50" cy="50" r="45" fill="#be1e2d" /><path d="M25 50L50 30L75 50V75H25V50Z" fill="white" /></svg>
            </div>
            <h1 className="text-white font-black uppercase text-sm tracking-tighter">Qdez Imóveis</h1>
          </div>
          {view === 'list' && (
            <div className="flex gap-2">
              <button onClick={() => createNewInspection('Comparação')} className="bg-slate-700 text-white px-4 py-2.5 rounded-2xl font-black uppercase text-[9px] tracking-widest hover:bg-slate-600 transition-all">Comparar Vistorias</button>
              <button onClick={() => createNewInspection('Entrada')} className="bg-red-700 text-white px-5 py-2.5 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-lg shadow-red-900/20 active:scale-95 transition-all">+ Novo Laudo</button>
            </div>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-6 flex-grow">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
            {inspections.length === 0 ? (
              <div className="col-span-full py-20 text-center opacity-50"><p className="font-black uppercase text-xs tracking-[0.3em] text-slate-400">Nenhum laudo encontrado</p></div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-[2rem] border border-slate-200/60 p-6 hover:shadow-xl cursor-pointer group transition-all" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <h3 className="font-black uppercase truncate text-slate-800 leading-tight">{ins.address || 'Sem Endereço'}</h3>
                  <div className="mt-4 flex justify-between items-center">
                    <span className="text-[9px] text-slate-400 font-bold uppercase">{ins.type} • {new Date(ins.date).toLocaleDateString()}</span>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : view === 'comparison' ? (
          <div className="max-w-4xl mx-auto space-y-8 pb-20">
            <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-sm">
              <h2 className="text-2xl font-black text-slate-900 uppercase mb-6">Módulo de Comparação Pericial</h2>
              <p className="text-sm text-slate-500 mb-8 font-medium">Anexe os arquivos PDF de entrada e saída para gerar o laudo de divergências com pesquisa de mercado.</p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">1. Vistoria de Entrada (PDF)</label>
                  <div className={`relative h-32 rounded-2xl border-2 border-dashed flex items-center justify-center transition-all ${entryPdf ? 'border-green-400 bg-green-50' : 'border-slate-300 bg-slate-50'}`}>
                    <input type="file" accept="application/pdf" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handlePdfUpload(e, 'entry')} />
                    <span className="text-xs font-bold text-slate-400">{entryPdf ? "PDF Anexado ✓" : "Selecionar Arquivo"}</span>
                  </div>
                </div>
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">2. Vistoria de Saída (PDF)</label>
                  <div className={`relative h-32 rounded-2xl border-2 border-dashed flex items-center justify-center transition-all ${exitPdf ? 'border-green-400 bg-green-50' : 'border-slate-300 bg-slate-50'}`}>
                    <input type="file" accept="application/pdf" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handlePdfUpload(e, 'exit')} />
                    <span className="text-xs font-bold text-slate-400">{exitPdf ? "PDF Anexado ✓" : "Selecionar Arquivo"}</span>
                  </div>
                </div>
              </div>

              <button 
                onClick={runComparison} 
                disabled={isAnalyzing || !entryPdf || !exitPdf}
                className="w-full mt-8 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[12px] tracking-widest hover:bg-red-700 transition-all disabled:bg-slate-300 shadow-xl"
              >
                {isAnalyzing ? "Analisando com IA e Consultando Preços..." : "Iniciar Comparação Inteligente"}
              </button>
            </div>

            {comparisonOutput && (
              <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-xl animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="prose prose-slate max-w-none">
                  <div className="bg-red-50 border-l-4 border-red-700 p-4 mb-6">
                    <p className="text-red-900 font-bold text-xs uppercase tracking-widest">Relatório Pericial Gerado</p>
                  </div>
                  <div dangerouslySetInnerHTML={{ __html: comparisonOutput.replace(/\n/g, '<br/>') }} className="text-sm text-slate-700 leading-relaxed" />
                </div>
                <div className="mt-8 flex gap-4 no-print">
                   <button onClick={() => window.print()} className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest">Imprimir Laudo</button>
                   <button onClick={() => setView('list')} className="flex-1 py-4 bg-slate-100 text-slate-600 rounded-2xl font-black uppercase text-[10px] tracking-widest">Fechar</button>
                </div>
              </div>
            )}
          </div>
        ) : view === 'editor' && currentInspection ? (
          <div className="space-y-6 pb-32">
            {/* Mantido o editor existente... */}
            <div className="bg-white rounded-[2.5rem] p-6 border border-slate-200">
               <h2 className="text-lg font-black uppercase mb-4 text-slate-800">Editor de Vistoria</h2>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input className="w-full p-4 bg-slate-50 rounded-xl" placeholder="Endereço" value={currentInspection.address} onChange={e => setCurrentInspection({...currentInspection, address: e.target.value})} />
                  <input className="w-full p-4 bg-slate-50 rounded-xl" placeholder="Proprietário" value={currentInspection.ownerName} onChange={e => setCurrentInspection({...currentInspection, ownerName: e.target.value})} />
               </div>
            </div>

            <div className="flex justify-between items-center">
               <button onClick={() => addRoom('Sala')} className="bg-slate-900 text-white px-6 py-3 rounded-xl font-bold">+ Adicionar Ambiente</button>
               <button onClick={saveInspection} className="bg-red-700 text-white px-8 py-3 rounded-xl font-bold shadow-lg">Salvar Tudo</button>
            </div>
          </div>
        ) : null}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, Photo, Video, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI, compareInspectionsAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isSavingDraft, setIsSavingDraft] = useState(false);

  // States para comparação
  const [entryPdf, setEntryPdf] = useState<string | null>(null);
  const [exitPdf, setExitPdf] = useState<string | null>(null);
  const [comparisonOutput, setComparisonOutput] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const saved: Inspection[] | null = await localforage.getItem('vistorias_pro_data');
        if (saved) {
          setInspections(saved);
        }
      } catch (e) {
        console.error("Erro ao carregar dados do IndexedDB:", e);
      }
    };
    loadData();
  }, []);

  const saveToStorage = async (data: Inspection[]) => {
    try {
      await localforage.setItem('vistorias_pro_data', data);
    } catch (e) {
      console.error("Erro ao salvar no IndexedDB:", e);
      alert("Erro ao salvar dados. Verifique o espaço disponível.");
    }
  };

  const createNewInspection = (type: 'Entrada' | 'Saída' | 'Constatação' | 'Comparação' = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setComparisonOutput(null);
      setEntryPdf(null);
      setExitPdf(null);
      return;
    }
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type,
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const handlePdfUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'entry' | 'exit') => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      if (target === 'entry') setEntryPdf(base64);
      else setExitPdf(base64);
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!entryPdf || !exitPdf) {
      alert("Por favor, anexe os dois PDFs para comparação.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await compareInspectionsAI(entryPdf, exitPdf);
      setComparisonOutput(result);
    } catch (err) {
      alert("Erro na comparação inteligente.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const deleteRoom = (roomId: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!currentInspection) return;
    if (window.confirm("Confirmar exclusão deste ambiente?")) {
        setCurrentInspection(prev => {
            if (!prev) return null;
            return {
                ...prev,
                rooms: prev.rooms.filter(r => r.id !== roomId)
            };
        });
        if (editingRoomId === roomId) {
            setEditingRoomId(null);
        }
    }
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0 && room.videos.length === 0) {
      alert("Adicione mídia para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.customName || room.type, room.photos, room.videos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Erro na análise inteligente.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleTenantChange = (index: number, value: string) => {
    if (!currentInspection) return;
    const newTenants = [...currentInspection.tenants];
    newTenants[index] = value;
    setCurrentInspection({ ...currentInspection, tenants: newTenants });
  };

  const addTenant = () => {
    if (!currentInspection) return;
    setCurrentInspection({ ...currentInspection, tenants: [...currentInspection.tenants, ''] });
  };

  const removeTenant = (index: number) => {
    if (!currentInspection || currentInspection.tenants.length <= 1) return;
    const newTenants = currentInspection.tenants.filter((_, i) => i !== index);
    setCurrentInspection({ ...currentInspection, tenants: newTenants });
  };

  const saveDraft = async () => {
    if (!currentInspection) return;
    setIsSavingDraft(true);
    try {
      const updatedInspections = [...inspections];
      const index = updatedInspections.findIndex(i => i.id === currentInspection.id);
      const draftInspection = { ...currentInspection, status: 'draft' as const };

      if (index !== -1) {
        updatedInspections[index] = draftInspection;
      } else {
        updatedInspections.unshift(draftInspection);
      }

      setInspections(updatedInspections);
      await saveToStorage(updatedInspections);
    } catch (e) {
      alert("Erro ao salvar rascunho.");
    } finally {
      setTimeout(() => setIsSavingDraft(false), 1000);
    }
  };

  const saveInspection = async () => {
    if (!currentInspection) return;
    try {
      const updatedInspections = [...inspections];
      const index = updatedInspections.findIndex(i => i.id === currentInspection.id);
      const finalInspection = { ...currentInspection, status: 'completed' as const };

      if (index !== -1) updatedInspections[index] = finalInspection;
      else updatedInspections.unshift(finalInspection);

      setInspections(updatedInspections);
      await saveToStorage(updatedInspections);
      setView('list');
      setCurrentInspection(null);
    } catch (e) {
      alert("Erro ao finalizar o laudo.");
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col no-select print:block">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => { setView('list'); setCurrentInspection(null); }}>
             <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center p-1 shadow-inner">
                <svg viewBox="0 0 100 100" className="w-full h-full" fill="none">
                  <circle cx="50" cy="50" r="45" fill="#be1e2d" />
                  <path d="M25 50L50 30L75 50V75H25V50Z" fill="white" />
                </svg>
            </div>
            <div className="hidden sm:block">
              <h1 className="text-white font-black uppercase text-sm tracking-tighter">Qdez Imóveis</h1>
              <p className="text-[8px] text-red-500 font-bold uppercase tracking-widest">CRECI 34.873 J</p>
            </div>
          </div>

          {view === 'list' && (
            <div className="flex gap-2">
              <button onClick={() => createNewInspection('Comparação')} className="bg-slate-700 text-white px-4 py-2.5 rounded-2xl font-black uppercase text-[9px] tracking-widest hover:bg-slate-600 transition-all">Comparar Vistorias</button>
              <button onClick={() => createNewInspection('Entrada')} className="bg-red-700 text-white px-5 py-2.5 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-lg shadow-red-900/20 active:scale-95 transition-all">+ Novo Laudo</button>
            </div>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-6 flex-grow print:p-0 print:max-w-full">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
            {inspections.length === 0 ? (
              <div className="col-span-full py-20 text-center opacity-50">
                <p className="font-black uppercase text-xs tracking-[0.3em] text-slate-400">Nenhum laudo encontrado</p>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-[2rem] border border-slate-200/60 p-6 hover:shadow-xl transition-all cursor-pointer group active:bg-slate-50" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-2">
                        <span className="bg-red-50 text-red-700 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider">{ins.rooms.length} Ambientes</span>
                        {ins.status === 'draft' && (
                            <span className="bg-amber-100 text-amber-800 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider">Rascunho</span>
                        )}
                    </div>
                    <span className="text-[9px] font-black text-slate-300">#{ins.id}</span>
                  </div>
                  <h3 className="font-black uppercase truncate text-slate-800 leading-tight">{ins.address || 'Local não informado'}</h3>
                  <div className="mt-4 pt-4 border-t border-slate-50 flex justify-between items-center">
                    <span className="text-[9px] text-slate-400 font-bold uppercase">{ins.type} • {new Date(ins.date).toLocaleDateString()}</span>
                    <button onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }} className="bg-slate-900 text-white p-2.5 rounded-xl hover:bg-red-700 transition-colors shadow-sm">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : view === 'comparison' ? (
          <div className="max-w-4xl mx-auto space-y-8 pb-20">
            <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-sm">
              <h2 className="text-2xl font-black text-slate-900 uppercase mb-6">Módulo de Comparação Pericial</h2>
              <p className="text-sm text-slate-500 mb-8 font-medium">Anexe os arquivos PDF de entrada e saída para gerar o laudo de divergências com pesquisa de mercado.</p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">1. Vistoria de Entrada (PDF)</label>
                  <div className={`relative h-32 rounded-2xl border-2 border-dashed flex items-center justify-center transition-all ${entryPdf ? 'border-green-400 bg-green-50' : 'border-slate-300 bg-slate-50'}`}>
                    <input type="file" accept="application/pdf" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handlePdfUpload(e, 'entry')} />
                    <span className="text-xs font-bold text-slate-400">{entryPdf ? "PDF Anexado ✓" : "Selecionar Arquivo"}</span>
                  </div>
                </div>
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">2. Vistoria de Saída (PDF)</label>
                  <div className={`relative h-32 rounded-2xl border-2 border-dashed flex items-center justify-center transition-all ${exitPdf ? 'border-green-400 bg-green-50' : 'border-slate-300 bg-slate-50'}`}>
                    <input type="file" accept="application/pdf" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handlePdfUpload(e, 'exit')} />
                    <span className="text-xs font-bold text-slate-400">{exitPdf ? "PDF Anexado ✓" : "Selecionar Arquivo"}</span>
                  </div>
                </div>
              </div>

              <button 
                onClick={runComparison} 
                disabled={isAnalyzing || !entryPdf || !exitPdf}
                className="w-full mt-8 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[12px] tracking-widest hover:bg-red-700 transition-all disabled:bg-slate-300 shadow-xl"
              >
                {isAnalyzing ? "Analisando com IA e Consultando Preços..." : "Iniciar Comparação Inteligente"}
              </button>
            </div>

            {comparisonOutput && (
              <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-xl animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="prose prose-slate max-w-none">
                  <div className="bg-red-50 border-l-4 border-red-700 p-4 mb-6">
                    <p className="text-red-900 font-bold text-xs uppercase tracking-widest">Relatório Pericial Gerado</p>
                  </div>
                  <div dangerouslySetInnerHTML={{ __html: comparisonOutput.replace(/\n/g, '<br/>') }} className="text-sm text-slate-700 leading-relaxed" />
                </div>
                <div className="mt-8 flex gap-4 no-print">
                   <button onClick={() => window.print()} className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest">Imprimir Laudo</button>
                   <button onClick={() => setView('list')} className="flex-1 py-4 bg-slate-100 text-slate-600 rounded-2xl font-black uppercase text-[10px] tracking-widest">Fechar</button>
                </div>
              </div>
            )}
          </div>
        ) : view === 'editor' && currentInspection ? (
          <div className="space-y-6 pb-32">
            <div className="bg-white rounded-[2.5rem] border border-slate-200/60 p-6 md:p-8 shadow-sm">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="space-y-1.5 md:col-span-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Endereço Completo</label>
                  <input type="text" className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 placeholder:text-slate-300" placeholder="Ex: Av. Paulista, 1000 - Ap 52" value={currentInspection.address} onChange={(e) => setCurrentInspection({ ...currentInspection, address: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Finalidade</label>
                  <select className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 appearance-none" value={currentInspection.type} onChange={(e) => setCurrentInspection({ ...currentInspection, type: e.target.value as any })}>
                    <option value="Entrada">Vistoria de Entrada</option>
                    <option value="Saída">Vistoria de Saída</option>
                    <option value="Constatação">Vistoria de Constatação</option>
                  </select>
                </div>
                 <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Proprietário / Locador</label>
                  <input type="text" className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 placeholder:text-slate-300" placeholder="Nome do proprietário" value={currentInspection.ownerName} onChange={(e) => setCurrentInspection({ ...currentInspection, ownerName: e.target.value })} />
                </div>
              </div>
              <div className="pt-5 mt-5 border-t border-slate-100 space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Locatários / Interessados</label>
                 {currentInspection.tenants.map((tenant, index) => (
                    <div key={index} className="flex items-center gap-2">
                      <input 
                        type="text" 
                        className="flex-grow px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 placeholder:text-slate-300" 
                        placeholder={`Nome do locatário ${index + 1}`} 
                        value={tenant} 
                        onChange={(e) => handleTenantChange(index, e.target.value)} 
                      />
                      {currentInspection.tenants.length > 1 && (
                        <button onClick={() => removeTenant(index)} className="w-10 h-10 flex-shrink-0 bg-red-50 text-red-500 rounded-full flex items-center justify-center font-black text-lg active:bg-red-100 transition-colors">&times;</button>
                      )}
                    </div>
                 ))}
                 <button onClick={addTenant} className="text-[9px] font-black text-slate-500 uppercase bg-slate-100 px-4 py-2.5 rounded-xl hover:bg-slate-200 transition-all">+ Adicionar outro locatário</button>
              </div>
               <div className="pt-5 mt-5 border-t border-slate-100 space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Observações Gerais do Laudo</label>
                  <textarea className="w-full h-24 px-6 py-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 font-medium text-slate-600 text-sm" placeholder="Detalhes importantes sobre a vistoria, chaves, medidores, etc." value={currentInspection.generalRemarks} onChange={(e) => setCurrentInspection({ ...currentInspection, generalRemarks: e.target.value })} />
                </div>
            </div>

            <div className="flex flex-col gap-5">
              <div className="flex justify-between items-center px-4">
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-400">Ambientes do Imóvel</h2>
                <div className="relative">
                  <select className="bg-slate-900 text-white px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all appearance-none pr-10" value="" onChange={(e) => e.target.value === 'custom' ? addRoom('Ambiente Extra') : addRoom(e.target.value)}>
                    <option value="" disabled>+ Adicionar</option>
                    {COMMON_ROOMS.map(r => <option key={r} value={r}>{r}</option>)}
                    <option value="custom" className="text-red-500">+ Outro...</option>
                  </select>
                </div>
              </div>

              {currentInspection.rooms.map(room => (
                <div key={room.id} className="bg-white rounded-[2rem] border border-slate-200/50 overflow-hidden shadow-sm transition-all">
                  <div className="p-6 flex justify-between items-center cursor-pointer active:bg-slate-50" onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}>
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${room.photos.length > 0 || room.videos.length > 0 ? 'bg-red-600 text-white shadow-lg shadow-red-200' : 'bg-slate-100 text-slate-400'}`}>
                        {room.videos.length > 0 ? (
                           <svg className="w-5 h-5 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 00-2 2z"/></svg>
                        ) : (
                           <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>
                        )}
                      </div>
                      <div>
                        <h4 className="font-black uppercase text-slate-800 text-sm">{room.customName || room.type}</h4>
                        <p className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">{room.photos.length} Fotos • {room.videos.length} Vídeos</p>
                      </div>
                    </div>
                    <svg className={`w-5 h-5 text-slate-300 transition-transform ${editingRoomId === room.id ? 'rotate-180 text-red-600' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                  </div>

                  {editingRoomId === room.id && (
                    <div className="px-6 pb-8 space-y-6 bg-slate-50/20 border-t border-slate-50 pt-6">
                      <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Nome do Ambiente</label>
                        <input 
                          type="text" 
                          className="w-full px-5 py-3 bg-white rounded-xl border-none ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 font-bold text-slate-700 placeholder:text-slate-300" 
                          placeholder="Ex: Suíte Master"
                          value={room.customName || room.type} 
                          onChange={(e) => updateRoom(room.id, { customName: e.target.value })}
                        />
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Galeria de Fotos</label>
                          <div className="grid grid-cols-3 gap-2">
                            {room.photos.map(p => (
                              <div key={p.id} className="relative aspect-square rounded-xl overflow-hidden shadow-sm group">
                                <img src={p.data} className="w-full h-full object-cover" />
                                <button onClick={() => updateRoom(room.id, { photos: room.photos.filter(x => x.id !== p.id) })} className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12"/></svg></button>
                              </div>
                            ))}
                            <PhotoUploader onPhotosAdded={(newP) => updateRoom(room.id, { photos: [...room.photos, ...newP] })} />
                          </div>
                        </div>

                        <div>
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Filmagem (Análise IA)</label>
                          <div className="grid grid-cols-3 gap-2">
                            {room.videos.map(v => (
                              <div key={v.id} className="relative aspect-square rounded-xl overflow-hidden shadow-md bg-black group">
                                <img src={v.thumbnail} className="w-full h-full object-cover opacity-60" />
                                <div className="absolute inset-0 flex items-center justify-center">
                                  <svg className="w-6 h-6 text-white/80" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
                                </div>
                                <button onClick={() => updateRoom(room.id, { videos: room.videos.filter(x => x.id !== v.id) })} className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12"/></svg></button>
                              </div>
                            ))}
                            <VideoUploader onVideosAdded={(newV) => updateRoom(room.id, { videos: [...room.videos, ...newV] })} />
                          </div>
                        </div>
                      </div>

                      <div className="space-y-3">
                        <div className="flex justify-between items-center">
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Descrição Técnica</label>
                          <button onClick={() => handleAIAnalysis(room)} disabled={isAnalyzing} className={`flex items-center gap-2 px-5 py-2 rounded-xl text-[9px] font-black uppercase transition-all shadow-lg active:scale-95 ${isAnalyzing ? 'bg-slate-200 text-slate-400' : 'bg-slate-900 text-red-500 hover:bg-slate-800 shadow-slate-900/10'}`}>
                            <svg className={`w-3.5 h-3.5 ${isAnalyzing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
                            {isAnalyzing ? 'Processando Mídia...' : 'Auto-Descrever com IA'}
                          </button>
                        </div>
                        <textarea className="w-full h-32 px-5 py-4 bg-white rounded-2xl ring-1 ring-slate-100 focus:ring-2 focus:ring-red-600 text-xs leading-relaxed font-medium text-slate-600" placeholder="A IA preencherá aqui após analisar seus vídeos e fotos..." value={room.description} onChange={(e) => updateRoom(room.id, { description: e.target.value })} />
                      </div>

                      <div className="flex justify-between items-center pt-2">
                         <button type="button" onClick={(e) => deleteRoom(room.id, e)} className="text-[9px] font-black text-red-600 uppercase bg-red-50 px-4 py-2.5 rounded-xl hover:bg-red-100 transition-all">Excluir Ambiente</button>
                         <div className="flex gap-3">
                            {['Novo', 'Bom', 'Regular', 'Ruim'].map(cond => {
                                let colors = '';
                                switch(cond) {
                                    case 'Novo':    colors = room.condition === cond ? 'bg-blue-600 text-white border-blue-600'     : 'bg-white text-blue-700 border-blue-200 hover:bg-blue-50'; break;
                                    case 'Bom':     colors = room.condition === cond ? 'bg-green-600 text-white border-green-600'   : 'bg-white text-green-700 border-green-200 hover:bg-green-50'; break;
                                    case 'Regular': colors = room.condition === cond ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-amber-700 border-amber-200 hover:bg-amber-50'; break;
                                    case 'Ruim':    colors = room.condition === cond ? 'bg-red-600 text-white border-red-600'     : 'bg-white text-red-700 border-red-200 hover:bg-red-50'; break;
                                }
                                return (
                                  <button 
                                      key={cond} 
                                      onClick={() => updateRoom(room.id, { condition: cond as any })} 
                                      className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase border transition-all shadow-sm ${colors}`}
                                  >
                                      {cond}
                                  </button>
                                )
                            })}
                         </div>
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-3.5 rounded-[2.5rem] shadow-2xl flex gap-3">
                  <button onClick={saveDraft} disabled={isSavingDraft} className="flex-1 px-6 py-4 bg-slate-800 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest border border-white/5 active:bg-slate-700 transition-colors disabled:bg-slate-600">
                    {isSavingDraft ? 'Salvando...' : 'Salvar Rascunho'}
                  </button>
                  <button onClick={saveInspection} className="flex-1 px-8 py-4 bg-red-700 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-xl active:scale-95 transition-all">Finalizar Laudo</button>
              </div>
            </div>
          </div>
        ) : view === 'report' && currentInspection ? (
           <>
            <InspectionReport inspection={currentInspection} />
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-40 no-print">
              <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 p-3.5 rounded-[2.5rem] shadow-2xl flex gap-3">
                  <button onClick={() => setView('editor')} className="flex-1 px-6 py-4 bg-slate-700 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest border border-white/5 active:bg-slate-600 transition-colors">Voltar à Edição</button>
                  <button onClick={() => window.print()} className="flex-1 px-8 py-4 bg-red-700 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-xl active:scale-95 transition-all">Imprimir Laudo</button>
              </div>
            </div>
           </>
        ) : null}
      </main>

      {view === 'list' && (
        <footer className="text-center py-12 text-slate-400 text-[9px] font-bold uppercase tracking-[0.4em] opacity-40">
          <p>Qdez Imóveis Profissional</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, Photo, Video, COMMON_ROOMS } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomWithAI, compareInspectionsAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isSavingDraft, setIsSavingDraft] = useState(false);

  // States para o módulo de comparação
  const [entryPdf, setEntryPdf] = useState<string | null>(null);
  const [exitPdf, setExitPdf] = useState<string | null>(null);
  const [comparisonOutput, setComparisonOutput] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const saved: Inspection[] | null = await localforage.getItem('vistorias_pro_data');
        if (saved) setInspections(saved);
      } catch (e) {
        console.error("Erro ao carregar do IndexedDB:", e);
      }
    };
    loadData();
  }, []);

  const saveToStorage = async (data: Inspection[]) => {
    try {
      await localforage.setItem('vistorias_pro_data', data);
    } catch (e) {
      alert("Erro de armazenamento. Verifique o espaço do dispositivo.");
    }
  };

  const createNewInspection = (type: 'Entrada' | 'Saída' | 'Constatação' | 'Comparação' = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setComparisonOutput(null);
      setEntryPdf(null);
      setExitPdf(null);
      return;
    }
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type,
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const handlePdfUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'entry' | 'exit') => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      if (target === 'entry') setEntryPdf(base64);
      else setExitPdf(base64);
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!entryPdf || !exitPdf) {
      alert("Anexe os dois laudos PDF para comparação.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await compareInspectionsAI(entryPdf, exitPdf);
      setComparisonOutput(result);
    } catch (err) {
      alert("Erro na análise pericial.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const addRoom = (type: string) => {
    if (!currentInspection) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    setCurrentInspection({
      ...currentInspection,
      rooms: [...currentInspection.rooms, newRoom]
    });
    setEditingRoomId(newRoom.id);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const handleAIAnalysis = async (room: Room) => {
    if (room.photos.length === 0 && room.videos.length === 0) {
      alert("Adicione mídia para análise.");
      return;
    }
    setIsAnalyzing(true);
    try {
      const result = await analyzeRoomWithAI(room.customName || room.type, room.photos, room.videos, room.description);
      updateRoom(room.id, { description: result });
    } catch (err) {
      alert("Erro na análise inteligente.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleTenantChange = (index: number, value: string) => {
    if (!currentInspection) return;
    const newTenants = [...currentInspection.tenants];
    newTenants[index] = value;
    setCurrentInspection({ ...currentInspection, tenants: newTenants });
  };

  const addTenant = () => {
    if (!currentInspection) return;
    setCurrentInspection({ ...currentInspection, tenants: [...currentInspection.tenants, ''] });
  };

  const removeTenant = (index: number) => {
    if (!currentInspection || currentInspection.tenants.length <= 1) return;
    const newTenants = currentInspection.tenants.filter((_, i) => i !== index);
    setCurrentInspection({ ...currentInspection, tenants: newTenants });
  };

  const saveDraft = async () => {
    if (!currentInspection) return;
    setIsSavingDraft(true);
    try {
      const updatedInspections = [...inspections];
      const index = updatedInspections.findIndex(i => i.id === currentInspection.id);
      const draft = { ...currentInspection, status: 'draft' as const };
      if (index !== -1) updatedInspections[index] = draft;
      else updatedInspections.unshift(draft);
      setInspections(updatedInspections);
      await saveToStorage(updatedInspections);
    } catch (e) {
      alert("Erro ao salvar rascunho.");
    } finally {
      setTimeout(() => setIsSavingDraft(false), 800);
    }
  };

  const finalizeInspection = async () => {
    if (!currentInspection) return;
    try {
      const updatedInspections = [...inspections];
      const index = updatedInspections.findIndex(i => i.id === currentInspection.id);
      const final = { ...currentInspection, status: 'completed' as const };
      if (index !== -1) updatedInspections[index] = final;
      else updatedInspections.unshift(final);
      setInspections(updatedInspections);
      await saveToStorage(updatedInspections);
      setView('list');
      setCurrentInspection(null);
    } catch (e) {
      alert("Erro ao finalizar laudo.");
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col no-select print:block">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => { setView('list'); setCurrentInspection(null); }}>
             <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center p-1 shadow-inner">
                <svg viewBox="0 0 100 100" className="w-full h-full" fill="none">
                  <circle cx="50" cy="50" r="45" fill="#be1e2d" />
                  <path d="M25 50L50 30L75 50V75H25V50Z" fill="white" />
                </svg>
            </div>
            <div className="hidden sm:block">
              <h1 className="text-white font-black uppercase text-sm tracking-tighter">Qdez Imóveis</h1>
              <p className="text-[8px] text-red-500 font-bold uppercase tracking-widest">SISTEMA PERICIAL</p>
            </div>
          </div>

          {view === 'list' && (
            <div className="flex gap-2">
              <button onClick={() => createNewInspection('Comparação')} className="bg-slate-700 text-white px-4 py-2.5 rounded-2xl font-black uppercase text-[9px] tracking-widest hover:bg-slate-600 transition-all border border-white/10">Comparar PDFs</button>
              <button onClick={() => createNewInspection('Entrada')} className="bg-red-700 text-white px-5 py-2.5 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-red-600 shadow-lg shadow-red-900/20 active:scale-95 transition-all">+ Novo Laudo</button>
            </div>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-6 flex-grow print:p-0">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
            {inspections.length === 0 ? (
              <div className="col-span-full py-20 text-center opacity-50">
                <p className="font-black uppercase text-xs tracking-[0.3em] text-slate-400">Nenhum laudo encontrado</p>
              </div>
            ) : (
              inspections.map(ins => (
                <div key={ins.id} className="bg-white rounded-[2rem] border border-slate-200/60 p-6 hover:shadow-xl transition-all cursor-pointer group active:bg-slate-50" onClick={() => { setCurrentInspection(ins); setView('editor'); }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-2">
                        <span className="bg-red-50 text-red-700 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider">{ins.rooms.length} Ambientes</span>
                        {ins.status === 'draft' && (
                            <span className="bg-amber-100 text-amber-800 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider">Rascunho</span>
                        )}
                    </div>
                    <span className="text-[9px] font-black text-slate-300">#{ins.id}</span>
                  </div>
                  <h3 className="font-black uppercase truncate text-slate-800 leading-tight">{ins.address || 'Local não informado'}</h3>
                  <div className="mt-4 pt-4 border-t border-slate-50 flex justify-between items-center">
                    <span className="text-[9px] text-slate-400 font-bold uppercase">{ins.type} • {new Date(ins.date).toLocaleDateString()}</span>
                    <button onClick={(e) => { e.stopPropagation(); setCurrentInspection(ins); setView('report'); }} className="bg-slate-900 text-white p-2.5 rounded-xl hover:bg-red-700 transition-colors shadow-sm">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2z"/></svg>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : view === 'comparison' ? (
          <div className="max-w-4xl mx-auto space-y-8 pb-20">
            <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-sm">
              <h2 className="text-2xl font-black text-slate-900 uppercase mb-4 tracking-tighter">Comparação Técnica de Laudos</h2>
              <p className="text-sm text-slate-500 mb-8 font-medium leading-relaxed">Anexe os PDFs de Entrada e Saída. Nossa IA buscará materiais na internet e mão de obra na tabela SINAPI SP para gerar o orçamento de reparos.</p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">1. Laudo de Entrada (PDF)</label>
                  <div className={`relative h-40 rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all ${entryPdf ? 'border-green-400 bg-green-50' : 'border-slate-300 bg-slate-50'}`}>
                    <input type="file" accept="application/pdf" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handlePdfUpload(e, 'entry')} />
                    <svg className={`w-8 h-8 mb-2 ${entryPdf ? 'text-green-500' : 'text-slate-300'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                    <span className="text-[10px] font-black uppercase text-slate-500">{entryPdf ? "Laudo Carregado ✓" : "Selecionar PDF"}</span>
                  </div>
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">2. Laudo de Saída (PDF)</label>
                  <div className={`relative h-40 rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all ${exitPdf ? 'border-green-400 bg-green-50' : 'border-slate-300 bg-slate-50'}`}>
                    <input type="file" accept="application/pdf" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handlePdfUpload(e, 'exit')} />
                    <svg className={`w-8 h-8 mb-2 ${exitPdf ? 'text-green-500' : 'text-slate-300'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                    <span className="text-[10px] font-black uppercase text-slate-500">{exitPdf ? "Laudo Carregado ✓" : "Selecionar PDF"}</span>
                  </div>
                </div>
              </div>

              <button 
                onClick={runComparison} 
                disabled={isAnalyzing || !entryPdf || !exitPdf}
                className="w-full mt-8 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] hover:bg-red-700 transition-all disabled:bg-slate-300 shadow-2xl shadow-slate-900/20"
              >
                {isAnalyzing ? "Cruzando Dados e Consultando Preços..." : "Gerar Comparativo e Orçamentos"}
              </button>
            </div>

            {comparisonOutput && (
              <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-2xl animate-in fade-in slide-in-from-bottom-6 duration-700">
                <div className="prose prose-slate max-w-none">
