import { GoogleGenAI, Type } from "@google/genai";
import { Photo, Video, AIAnalysis } from "../types";

const SYSTEM_PROMPT_VIDEO = `
Você é um Vistoriador Técnico Imobiliário. Analise o VÍDEO (frames + áudio) e preencha a vistoria com alta precisão.
Regras:
- Não invente informações. 
- Se algo não estiver claramente visível/dito, marque confidence como BAIXA e escreva "NECESSITA VALIDAÇÃO HUMANA".
- Seja formal, objetivo e específico.
- Identifique problemas informando: local, descrição, gravidade e evidência (timestamp).
`;

export const analyzeRoomVideoAI = async (roomType: string, video: Video): Promise<AIAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            { text: SYSTEM_PROMPT_VIDEO },
            { text: `Analise este vídeo do cômodo: ${roomType}` },
            { inlineData: { data: video.data.split(',')[1], mimeType: video.mimeType } }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        // O schema é passado via prompt para garantir compatibilidade com o modelo flash-preview
      }
    });

    return JSON.parse(response.text || '{}') as AIAnalysis;
  } catch (error) {
    console.error("Erro na análise de vídeo:", error);
    throw error;
  }
};

export const generateFinalConclusionAI = async (entryPdf: string, exitPdf: string, manualRemarks: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Como Perito Imobiliário, gere uma Conclusão Final Técnica comparando os dois laudos anexos.
    Considere também estas OBSERVAÇÕES MANUAIS DO VISTORIADOR: "${manualRemarks}"

    A conclusão deve ser formal e conter:
    1. Resumo do estado geral (Piorou/Melhorou).
    2. Itens Críticos identificados.
    3. Recomendações de manutenção e prioridade.
    4. Notas de responsabilidade (Dano por uso vs Desgaste natural).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          parts: [
            { text: prompt },
            { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
            { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
          ]
        }
      ],
      config: { tools: [{ googleSearch: {} }] }
    });
    return response.text || "Falha ao gerar conclusão.";
  } catch (error) {
    return "Erro no processamento da conclusão inteligente.";
  }
};

export const transcribeAudio = async (audioBase64: string, mimeType: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: "Transcreva este áudio de vistoria em texto técnico formal." },
        { inlineData: { data: audioBase64, mimeType: mimeType } }
      ]
    },
  });
  return response.text || "";
};

export const compareInspectionsAI = async (entryPdf: string, exitPdf: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{
      parts: [
        { text: "Compare estes dois laudos e liste as divergências técnicas por ambiente." },
        { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
        { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
      ]
    }],
    config: { tools: [{ googleSearch: {} }] }
  });
  return response.text || "";
};

import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, Photo, Video, COMMON_ROOMS, AIAnalysis } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import InspectionReport from './components/InspectionReport';
import { analyzeRoomVideoAI, compareInspectionsAI, generateFinalConclusionAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison' | 'share'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);
  const [isSavingDraft, setIsSavingDraft] = useState(false);

  const [entryPdf, setEntryPdf] = useState<string | null>(null);
  const [exitPdf, setExitPdf] = useState<string | null>(null);
  const [manualRemarks, setManualRemarks] = useState('');
  const [comparisonOutput, setComparisonOutput] = useState<string | null>(null);
  const [finalConclusion, setFinalConclusion] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      const saved: Inspection[] | null = await localforage.getItem('vistorias_pro_data');
      if (saved) setInspections(saved);
    };
    loadData();
  }, []);

  const saveToStorage = async (data: Inspection[]) => {
    await localforage.setItem('vistorias_pro_data', data);
  };

  const createNewInspection = (type: any = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setComparisonOutput(null);
      setFinalConclusion(null);
      return;
    }
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type,
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft',
      shareToken: Math.random().toString(36).substr(2, 15)
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const handleVideoUpload = async (roomId: string, video: Video) => {
    if (!currentInspection) return;
    setIsAnalyzing(true);
    try {
      const room = currentInspection.rooms.find(r => r.id === roomId);
      if (room) {
        const result = await analyzeRoomVideoAI(room.customName || room.type, video);
        updateRoom(roomId, { 
          aiAnalysis: result,
          description: `Análise por Vídeo: ${result.evidencias.length} evidências encontradas.`,
          videos: [...room.videos, { ...video, processed: true }]
        });
      }
    } catch (err) {
      alert("Erro ao processar vídeo com IA.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const runFullComparison = async () => {
    if (!entryPdf || !exitPdf) return;
    setIsAnalyzing(true);
    try {
      const diff = await compareInspectionsAI(entryPdf, exitPdf);
      setComparisonOutput(diff);
      const conclusion = await generateFinalConclusionAI(entryPdf, exitPdf, manualRemarks);
      setFinalConclusion(conclusion);
    } catch (err) {
      alert("Erro no comparativo.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    setCurrentInspection({
      ...currentInspection,
      rooms: currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r)
    });
  };

  const finalize = async () => {
    if (!currentInspection) return;
    const updated = [...inspections];
    const idx = updated.findIndex(i => i.id === currentInspection.id);
    const completed = { ...currentInspection, status: 'completed' as const };
    if (idx !== -1) updated[idx] = completed; else updated.unshift(completed);
    setInspections(updated);
    await saveToStorage(updated);
    setView('report');
  };

  const getShareLink = () => {
    if (!currentInspection) return '';
    return `${window.location.origin}${window.location.pathname}?view=share&id=${currentInspection.id}&token=${currentInspection.shareToken}`;
  };

