          </div>
          <div className="flex gap-2">
            <button onClick={() => createNewInspection('Comparação')} className="bg-slate-700 text-white px-3 py-2 rounded-xl text-[10px] font-bold">COMPARAR</button>
            <button onClick={() => createNewInspection()} className="bg-red-700 text-white px-3 py-2 rounded-xl text-[10px] font-bold">+ NOVO</button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-6 flex-grow">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {inspections.map(ins => (
