import React, { useState } from 'react';
import { Video as VideoType } from '../types';

interface VideoUploaderProps {
  onVideosAdded: (newVideos: VideoType[]) => void;
}

const VideoUploader: React.FC<VideoUploaderProps> = ({ onVideosAdded }) => {
  const [isUploading, setIsUploading] = useState(false);

  const processVideo = (file: File): Promise<VideoType> => {
    return new Promise((resolve) => {
      const video = document.createElement('video');
      video.preload = 'metadata';
      video.src = URL.createObjectURL(file);

      video.onloadedmetadata = () => {
        const reader = new FileReader();
        reader.onload = (e) => {
          resolve({
            id: Math.random().toString(36).substr(2, 9),
            data: e.target?.result as string,
            mimeType: file.type,
            size: file.size,
            duration: video.duration,
            processed: false
          });
        };
        reader.readAsDataURL(file);
      };
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsUploading(true);
    const newVideos: VideoType[] = [];
    for (let i = 0; i < files.length; i++) {
      const v = await processVideo(files[i]);
      newVideos.push(v);
    }
    onVideosAdded(newVideos);
    setIsUploading(false);
    e.target.value = '';
  };

  return (
    <div className="flex items-center justify-center w-full">
      <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-red-200 rounded-3xl cursor-pointer bg-red-50/20 hover:bg-red-50 transition-colors group relative overflow-hidden">
        {isUploading && (
          <div className="absolute inset-0 bg-white/80 flex items-center justify-center z-10">
            <span className="text-[10px] font-black text-red-600 animate-pulse uppercase">Upload Ativo...</span>
          </div>
        )}
        <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
          <svg className="w-8 h-8 mb-3 text-red-400 group-hover:text-red-600 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"/>
          </svg>
          <p className="text-[10px] text-red-600 font-black uppercase tracking-widest">Upload Vídeo com Áudio</p>
          <p className="text-[8px] text-slate-400 mt-1 font-bold uppercase">(MP4, WEBM, MOV)</p>
        </div>
        <input type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
      </label>
    </div>
  );
};

