import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, Photo, Video, COMMON_ROOMS, AIAnalysis } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import InspectionReport from './components/InspectionReport';
import VoiceTranscription from './components/VoiceTranscription';
import { analyzeRoomVideoAI, compareInspectionsAI, generateFinalConclusionAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);

  const [entryPdf, setEntryPdf] = useState<string | null>(null);
  const [exitPdf, setExitPdf] = useState<string | null>(null);
  const [manualRemarks, setManualRemarks] = useState('');
  const [comparisonOutput, setComparisonOutput] = useState<string | null>(null);
  const [finalConclusion, setFinalConclusion] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      const saved: Inspection[] | null = await localforage.getItem('vistorias_pro_data_v2');
      if (saved) setInspections(saved);
    };
    loadData();
  }, []);

  const saveToStorage = async (data: Inspection[]) => {
    await localforage.setItem('vistorias_pro_data_v2', data);
  };

  const createNewInspection = (type: any = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setComparisonOutput(null);
      setFinalConclusion(null);
      return;
    }
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type,
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft',
      shareToken: Math.random().toString(36).substr(2, 15)
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const handleVideoUpload = async (roomId: string, video: Video) => {
    if (!currentInspection) return;
    setIsAnalyzing(true);
    try {
      const room = currentInspection.rooms.find(r => r.id === roomId);
      if (room) {
        const result = await analyzeRoomVideoAI(room.customName || room.type, video);
        updateRoom(roomId, { 
          aiAnalysis: result,
          description: room.description + (room.description ? '\n' : '') + `[Análise IA]: ${result.evidencias.length} evidências críticas detectadas via vídeo.`,
          videos: [...room.videos, { ...video, processed: true }]
        });
      }
    } catch (err) {
      alert("Erro ao processar vídeo com IA. Verifique sua chave API.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const runFullComparison = async () => {
    if (!entryPdf || !exitPdf) return;
    setIsAnalyzing(true);
    try {
      const diff = await compareInspectionsAI(entryPdf, exitPdf);
      setComparisonOutput(diff);
      const conclusion = await generateFinalConclusionAI(entryPdf, exitPdf, manualRemarks);
      setFinalConclusion(conclusion);
    } catch (err) {
      alert("Erro no comparativo pericial.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    const updatedRooms = currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedInspection = { ...currentInspection, rooms: updatedRooms };
    setCurrentInspection(updatedInspection);

    // Auto-save draft
    const all = [...inspections];
    const idx = all.findIndex(i => i.id === currentInspection.id);
    if (idx !== -1) {
      all[idx] = updatedInspection;
      setInspections(all);
      saveToStorage(all);
    }
  };

  const finalize = async () => {
    if (!currentInspection) return;
    const updated = [...inspections];
    const idx = updated.findIndex(i => i.id === currentInspection.id);
    const completed = { ...currentInspection, status: 'completed' as const };
    if (idx !== -1) updated[idx] = completed; else updated.unshift(completed);
    setInspections(updated);
    await saveToStorage(updated);
    setView('report');
  };

  const getShareLink = () => {
    if (!currentInspection) return '';
    return `${window.location.origin}${window.location.pathname}?id=${currentInspection.id}&token=${currentInspection.shareToken}`;
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (!element) return;
    const opt = {
      margin: 10,
      filename: `Vistoria_${currentInspection?.id}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };
    (window as any).html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col no-select">
      <header className="bg-slate-900 border-b border-red-700/30 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center p-1">
               <svg viewBox="0 0 100 100" className="w-full h-full"><circle cx="50" cy="50" r="45" fill="#be1e2d" /><path d="M25 50L50 30L75 50V75H25V50Z" fill="white" /></svg>
            </div>
            <h1 className="text-white font-black uppercase text-sm tracking-tight">Qdez Vistoria AI</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => createNewInspection('Comparação')} className="bg-slate-700 text-white px-3 py-2 rounded-xl text-[10px] font-bold">COMPARATIVO</button>
            <button onClick={() => createNewInspection()} className="bg-red-700 text-white px-3 py-2 rounded-xl text-[10px] font-bold">+ NOVA VISTORIA</button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto w-full px-4 py-6 flex-grow">
        {view === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {inspections.length === 0 ? (
              <div className="col-span-full py-20 text-center">
                <p className="text-slate-400 font-bold uppercase text-xs">Nenhuma vistoria encontrada.</p>
                <button onClick={() => createNewInspection()} className="mt-4 text-red-600 font-black text-[10px] uppercase">Começar Agora</button>
              </div>
            ) : inspections.map(ins => (
              <div key={ins.id} className="bg-white p-5 rounded-3xl shadow-sm border border-slate-200 cursor-pointer hover:border-red-500 transition-all group" onClick={() => {setCurrentInspection(ins); setView(ins.status === 'completed' ? 'report' : 'editor');}}>
                <div className="flex justify-between mb-2">
                  <span className={`text-[10px] font-black uppercase ${ins.type === 'Saída' ? 'text-amber-600' : 'text-red-600'}`}>{ins.type}</span>
                  <span className="text-[10px] text-slate-400 font-mono">#{ins.id}</span>
                </div>
                <h3 className="font-bold text-slate-800 truncate">{ins.address || 'Sem Endereço'}</h3>
                <div className="flex justify-between items-center mt-4">
                  <p className="text-[10px] text-slate-400 uppercase font-bold">{new Date(ins.date).toLocaleDateString()}</p>
                  <span className={`text-[8px] font-black px-2 py-1 rounded-lg uppercase ${ins.status === 'completed' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'}`}>
                    {ins.status === 'completed' ? 'Finalizada' : 'Rascunho'}
                  </span>
                </div>
              </div>
            ))}
          </div>
        ) : view === 'comparison' ? (
          <div className="max-w-3xl mx-auto space-y-6">
            <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-200">
              <h2 className="text-xl font-black mb-6 text-slate-900">Módulo de Comparação Pericial</h2>
              <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                  <label className="text-[10px] font-black uppercase text-slate-400 block mb-2">Laudo de Entrada (PDF)</label>
                  <input type="file" accept="application/pdf" className="text-[10px]" onChange={(e) => {
                    const f = e.target.files?.[0];
                    if (f) {
                      const reader = new FileReader();
                      reader.onload = (ev) => setEntryPdf((ev.target?.result as string).split(',')[1]);
                      reader.readAsDataURL(f);
                    }
                  }} />
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                  <label className="text-[10px] font-black uppercase text-slate-400 block mb-2">Laudo de Saída (PDF)</label>
                  <input type="file" accept="application/pdf" className="text-[10px]" onChange={(e) => {
                    const f = e.target.files?.[0];
                    if (f) {
                      const reader = new FileReader();
                      reader.onload = (ev) => setExitPdf((ev.target?.result as string).split(',')[1]);
                      reader.readAsDataURL(f);
                    }
                  }} />
                </div>
              </div>
              <div className="mb-6">
                <label className="text-[10px] font-black uppercase text-slate-400">Notas Adicionais do Perito</label>
                <textarea 
                  className="w-full mt-2 p-4 bg-slate-50 rounded-2xl border-none ring-1 ring-slate-200 focus:ring-red-500 text-sm" 
                  rows={4}
                  placeholder="Descreva pontos específicos não captados nos laudos..."
                  value={manualRemarks}
                  onChange={(e) => setManualRemarks(e.target.value)}
                />
              </div>
              <button 
                onClick={runFullComparison}
                disabled={isAnalyzing || !entryPdf || !exitPdf}
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest disabled:opacity-50 transition-all active:scale-[0.98]"
              >
                {isAnalyzing ? "Cruzando Dados com IA..." : "Iniciar Análise Pericial"}
              </button>
            </div>

            {comparisonOutput && (
              <div className="bg-white p-8 rounded-[2rem] shadow-lg border border-red-100 animate-in fade-in">
                <div className="flex items-center gap-2 mb-6">
                  <div className="w-2 h-2 bg-red-600 rounded-full"></div>
                  <h3 className="font-black text-slate-900 uppercase text-xs tracking-widest">Relatório de Divergências</h3>
                </div>
                <div className="prose prose-sm text-slate-700 mb-8 leading-relaxed" dangerouslySetInnerHTML={{ __html: comparisonOutput.replace(/\n/g, '<br/>') }} />

                {finalConclusion && (
                  <div className="mt-8 pt-8 border-t-2 border-slate-100">
                    <h3 className="font-black text-slate-900 uppercase text-xs tracking-widest mb-4">Conclusão Final Recomendada</h3>
                    <div className="p-6 bg-red-50/50 rounded-2xl text-sm italic text-slate-800 leading-relaxed border border-red-100">
                      {finalConclusion}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        ) : view === 'editor' && currentInspection ? (
          <div className="space-y-6 pb-24">
            <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-200">
              <input 
                className="w-full text-2xl font-black border-none focus:ring-0 placeholder:text-slate-200 p-0" 
                placeholder="Endereço Completo do Imóvel"
                value={currentInspection.address}
                onChange={(e) => setCurrentInspection({...currentInspection, address: e.target.value})}
              />
              <div className="mt-6 grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[8px] font-black uppercase text-slate-400 ml-1">Proprietário</label>
                  <input className="w-full bg-slate-50 p-3 rounded-xl border-none ring-1 ring-slate-100 text-xs font-bold" value={currentInspection.ownerName} onChange={(e) => setCurrentInspection({...currentInspection, ownerName: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-[8px] font-black uppercase text-slate-400 ml-1">Locatário</label>
                  <input className="w-full bg-slate-50 p-3 rounded-xl border-none ring-1 ring-slate-100 text-xs font-bold" value={currentInspection.tenants[0]} onChange={(e) => {
                    const t = [...currentInspection.tenants]; t[0] = e.target.value; setCurrentInspection({...currentInspection, tenants: t});
                  }} />
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="font-black uppercase text-slate-400 text-[10px] tracking-widest ml-2">Ambientes do Imóvel</h2>
                <select className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase" onChange={(e) => {
                  if (!e.target.value) return;
                  const type = e.target.value;
                  const newRoom: Room = { id: Math.random().toString(36).substr(2,9), type, description: '', photos: [], videos: [], condition: 'Bom' };
                  const updated = {...currentInspection, rooms: [...currentInspection.rooms, newRoom]};
                  setCurrentInspection(updated);
                  e.target.value = "";
                }}>
                  <option value="">+ ADICIONAR CÔMODO</option>
                  {COMMON_ROOMS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              {currentInspection.rooms.map(room => (
                <div key={room.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-all">
                  <div className="p-6 flex justify-between items-center cursor-pointer" onClick={() => setEditingRoomId(editingRoomId === room.id ? null : room.id)}>
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl shadow-inner ${room.aiAnalysis ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>
                        {room.videos.length > 0 ? '📹' : '📸'}
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 uppercase text-xs">{room.customName || room.type}</h4>
                        <p className="text-[10px] text-slate-400 font-bold">{room.photos.length} fotos • {room.videos.length} vídeos</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                       <span className={`text-[9px] font-black px-3 py-1 rounded-full uppercase ${room.condition === 'Novo' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-600'}`}>
                         {room.condition}
                       </span>
                       <svg className={`w-4 h-4 text-slate-300 transition-transform ${editingRoomId === room.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                    </div>
                  </div>

                  {editingRoomId === room.id && (
                    <div className="px-6 pb-6 pt-2 border-t border-slate-50 space-y-6 bg-slate-50/20">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <PhotoUploader onPhotosAdded={(photos) => updateRoom(room.id, { photos: [...room.photos, ...photos] })} />
                        <VideoUploader onVideosAdded={(videos) => handleVideoUpload(room.id, videos[0])} />
                      </div>

                      {room.aiAnalysis && (
                        <div className="bg-white p-6 rounded-3xl border border-red-100 shadow-sm animate-in zoom-in-95">
                          <div className="flex items-center justify-between mb-4">
                            <div className="flex items-center gap-2">
                              <span className="w-2 h-2 bg-red-600 rounded-full animate-pulse"></span>
                              <h5 className="text-[10px] font-black uppercase text-red-700 tracking-widest">Checklist Inteligente Gemini</h5>
                            </div>
                          </div>
                          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                            {Object.entries(room.aiAnalysis.itens).filter(([_, v]: any) => v.estado).map(([key, val]: any) => (
                              <div key={key} className="p-3 bg-slate-50 rounded-2xl border border-slate-100 group hover:border-red-200 transition-colors">
                                <span className="text-[8px] font-black uppercase text-slate-400 block mb-1">{key}</span>
                                <div className="flex items-center justify-between">
                                  <span className="text-[10px] font-bold text-slate-800">{val.estado}</span>
                                  <span className={`text-[7px] px-1 rounded font-black ${val.confidence === 'ALTA' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
                                    {val.confidence}
                                  </span>
                                </div>
                              </div>
                            ))}
                          </div>
                          {room.aiAnalysis.evidencias.length > 0 && (
                            <div className="mt-5 pt-5 border-t border-slate-100">
                                <span className="text-[8px] font-black uppercase text-slate-400 block mb-3">Evidências de Vídeo Detetadas</span>
                                <div className="grid grid-cols-1 gap-2">
                                  {room.aiAnalysis.evidencias.map((ev, i) => (
                                    <div key={i} className="text-[10px] flex items-center justify-between bg-white p-3 rounded-xl border border-red-50 shadow-sm">
                                      <div className="flex items-center gap-3">
                                        <span className={`w-1.5 h-1.5 rounded-full ${ev.gravidade === 'ALTA' ? 'bg-red-600' : 'bg-amber-500'}`}></span>
                                        <span className="font-bold text-slate-700">{ev.descricao}</span>
                                      </div>
                                      <span className="font-black text-red-600 bg-red-50 px-2 py-0.5 rounded-md">@{ev.timestampInicio}s</span>
                                    </div>
                                  ))}
                                </div>
                            </div>
                          )}
                        </div>
                      )}

                      <div className="space-y-3">
                        <div className="flex justify-between items-center">
                          <label className="text-[9px] font-black uppercase text-slate-400 ml-1">Descrição Técnica</label>
                          <VoiceTranscription onTranscriptionComplete={(text) => {
                            updateRoom(room.id, { description: room.description + (room.description ? ' ' : '') + text });
