- Seja formal, objetivo e específico.
- Identifique problemas informando: local, descrição, gravidade e evidência (timestamp).
`;

export const analyzeRoomVideoAI = async (roomType: string, video: Video): Promise<AIAnalysis> => {
  // Use process.env.API_KEY directly for initialization as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: SYSTEM_PROMPT_VIDEO },
          { text: `Analise este vídeo do cômodo: ${roomType}` },
          { inlineData: { data: video.data.split(',')[1], mimeType: video.mimeType } }
        ]
      },
      config: {
        responseMimeType: "application/json",
      }
    });

    return JSON.parse(response.text || '{}') as AIAnalysis;
  } catch (error) {
    console.error("Erro na análise de vídeo:", error);
    throw error;
  }
};

export const generateFinalConclusionAI = async (entryPdf: string, exitPdf: string, manualRemarks: string): Promise<string> => {
  // Use process.env.API_KEY directly for initialization as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Como Perito Imobiliário, gere uma Conclusão Final Técnica comparando os dois laudos anexos.
    Considere também estas OBSERVAÇÕES MANUAIS DO VISTORIADOR: "${manualRemarks}"

    A conclusão deve ser formal e conter:
