import { analyzeRoomVideoAI, compareInspectionsAI, generateFinalConclusionAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [currentInspection, setCurrentInspection] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [editingRoomId, setEditingRoomId] = useState<string | null>(null);

  const [entryPdf, setEntryPdf] = useState<string | null>(null);
  const [exitPdf, setExitPdf] = useState<string | null>(null);
  const [manualRemarks, setManualRemarks] = useState('');
  const [comparisonOutput, setComparisonOutput] = useState<string | null>(null);
  const [finalConclusion, setFinalConclusion] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      const saved: Inspection[] | null = await localforage.getItem('vistorias_pro_data_v2');
      if (saved) setInspections(saved);
    };
    loadData();
  }, []);

  const saveToStorage = async (data: Inspection[]) => {
    await localforage.setItem('vistorias_pro_data_v2', data);
  };

  const createNewInspection = (type: any = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setComparisonOutput(null);
      setFinalConclusion(null);
      return;
    }
    const newInspection: Inspection = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      clientName: '',
      tenants: [''],
      ownerName: '',
      type,
      address: '',
      generalRemarks: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft',
      shareToken: Math.random().toString(36).substr(2, 15)
    };
    setCurrentInspection(newInspection);
    setView('editor');
  };

  const handleVideoUpload = async (roomId: string, video: Video) => {
    if (!currentInspection) return;
    setIsAnalyzing(true);
    try {
      const room = currentInspection.rooms.find(r => r.id === roomId);
      if (room) {
        const result = await analyzeRoomVideoAI(room.customName || room.type, video);
        updateRoom(roomId, { 
          aiAnalysis: result,
          description: room.description + (room.description ? '\n' : '') + `[Análise IA]: ${result.evidencias.length} evidências críticas detectadas via vídeo.`,
          videos: [...room.videos, { ...video, processed: true }]
        });
      }
    } catch (err) {
      alert("Erro ao processar vídeo com IA. Verifique sua chave API.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const runFullComparison = async () => {
    if (!entryPdf || !exitPdf) return;
    setIsAnalyzing(true);
    try {
      const diff = await compareInspectionsAI(entryPdf, exitPdf);
      setComparisonOutput(diff);
      const conclusion = await generateFinalConclusionAI(entryPdf, exitPdf, manualRemarks);
      setFinalConclusion(conclusion);
    } catch (err) {
      alert("Erro no comparativo pericial.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!currentInspection) return;
    const updatedRooms = currentInspection.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedInspection = { ...currentInspection, rooms: updatedRooms };
    setCurrentInspection(updatedInspection);

    // Auto-save draft
    const all = [...inspections];
    const idx = all.findIndex(i => i.id === currentInspection.id);
    if (idx !== -1) {
      all[idx] = updatedInspection;
      setInspections(all);
      saveToStorage(all);
    }
  };

  const finalize = async () => {
    if (!currentInspection) return;
    const updated = [...inspections];
    const idx = updated.findIndex(i => i.id === currentInspection.id);
    const completed = { ...currentInspection, status: 'completed' as const };
    if (idx !== -1) updated[idx] = completed; else updated.unshift(completed);
    setInspections(updated);
    await saveToStorage(updated);
    setView('report');
