import { GoogleGenAI } from "@google/genai";

export const performComparisonAI = async (entryPdf: string, exitPdf: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Você é um Perito Engenheiro Civil e Vistoriador Imobiliário sênior no estado de São Paulo.

    TAREFA:
    1. Compare os dois laudos anexos (Entrada e Saída).
    2. Identifique divergências (danos, sujeira, itens faltantes).
    3. Categorize cada divergência como: "Dano Provocado pelo Locatário" ou "Defeito Estrutural/Natural".
    4. Gere um orçamento de reparos utilizando como referência a Tabela SINAPI do Estado de São Paulo para mão de obra.
    5. Realize uma pesquisa na internet por preços ATUAIS de materiais em lojas como Leroy Merlin, Telhanorte ou Mercado Livre para os itens necessários.
    6. Forneça links diretos para os anúncios dos materiais citados.

    FORMATO DE RESPOSTA:
    Retorne um relatório técnico detalhado em Markdown. Inclua uma tabela de custos com Colunas: Item, Quantidade, Valor Unitário (SINAPI/Loja), Valor Total e Link da Fonte.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const analysis = response.text || "Falha ao gerar análise.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Fonte de Preço",
        uri: chunk.web?.uri
      })).filter((s: any) => s.uri) || [];

    return { analysis, sources };
  } catch (error) {
    console.error("Erro na comparação pericial:", error);
    throw error;
  }
};

export const analyzeRoomVideoAI = async (roomType: string, videoData: string, mimeType: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `Analise este vídeo de vistoria do ambiente ${roomType}. Liste estados de conservação e avarias detectadas.` },
        { inlineData: { data: videoData, mimeType } }
      ]
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text);
};

export const transcribeAudio = async (base64Audio: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: "Transcreva este áudio de vistoria em texto técnico imobiliário." },
        { inlineData: { data: base64Audio, mimeType: 'audio/webm' } }
      ]
    }
  });
  return response.text || "";
};

import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomVideoAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);

  // Comparison State
  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);

  useEffect(() => {
    localforage.getItem<Inspection[]>('qdez_rascunhos').then(data => {
      if (data) setInspections(data);
    });
  }, []);

  const saveDrafts = (updated: Inspection[]) => {
    setInspections(updated);
    localforage.setItem('qdez_rascunhos', updated);
  };

  const startNew = (type: Inspection['type'] = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setPdfEntry(null);
      setPdfExit(null);
      return;
    }
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrent(newIns);
    setView('editor');
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    const list = inspections.filter(i => i.id !== current.id);
    saveDrafts([updated, ...list]);
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 5),
      type,
      customName: type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    updateCurrent({ rooms: [...current.rooms, newRoom] });
    setEditingRoom(newRoom.id);
  };

  const handleComparison = async () => {
    if (!pdfEntry || !pdfExit) return;
    setIsBusy(true);
    try {
      const result = await performComparisonAI(pdfEntry, pdfExit);
      const id = 'CMP-' + Math.random().toString(36).substr(2, 6).toUpperCase();
      const newIns: Inspection = {
        id,
        clientName: 'Sistema',
        tenantName: 'Comparativo Pericial',
        type: 'Comparação',
        address: 'Análise de Documentos',
        date: new Date().toISOString(),
        rooms: [],
        status: 'completed',
        comparisonResult: {
          analysis: result.analysis,
          budget: '', // O Gemini Pro já entrega o orçamento no Markdown da análise
          sources: result.sources
        }
      };
      setCurrent(newIns);
      setView('report');
    } catch (e) {
      alert("Erro ao comparar laudos.");
    } finally {
      setIsBusy(false);
    }
  };

  const handleFile = (file: File, setter: (val: string) => void) => {
    const reader = new FileReader();
    reader.onload = (e) => setter((e.target?.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  };

  const getStatusColor = (status: Room['condition']) => {
    switch (status) {
      case 'Ótimo': return 'bg-green-600';
      case 'Bom': return 'bg-blue-600';
      case 'Regular': return 'bg-amber-500';
      case 'Ruim': return 'bg-red-600';
      default: return 'bg-slate-400';
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
