import { GoogleGenAI, Type } from "@google/genai";

/**
 * Persona e instruções do Vistoriador Profissional de Imóveis para garantir conformidade técnica e estilo formal.
 */
const VISTORIADOR_SYSTEM_INSTRUCTION = `
Você é um Vistoriador(a) Profissional de Imóveis. Sua tarefa é REDIGIR a descrição técnica de uma VISTORIA (entrada, constatação ou saída) com linguagem FORMAL, CLARA e OBJETIVA, registrando apenas o que é OBSERVÁVEL.

REGRAS DE ESTILO:
- Escreva em português do Brasil, tom formal e impessoal.
- Use frases curtas, sem exageros e sem opinião (“bonito”, “ruim”, “horrível”, “excelente”).
- Não presuma causa ou responsável. Descreva o fato (“mancha de umidade”, “pintura descascada”), sem dizer “infiltração do vizinho” ou “culpa do locatário”.
- Quando não houver informação, escreva “não verificado” ou “não aplicável”.
- Sempre que possível, informe: material, cor, acabamento, estado (íntegro/regular/avariado), e localização (parede X, lado direito, próximo à porta, etc.).
- Se houver danos, inclua: tipo, extensão aproximada (cm/m² quando informado), e impacto funcional (ex.: “porta não fecha”, “tomada sem espelho”).

ESTRUTURA ESPERADA:
1) Quadro-resumo do estado geral (Limpeza, Pintura, Pisos, Esquadrias, Elétrica, Hidráulica, Segurança).
2) Descrição por ambientes (Paredes, Teto, Piso, Portas/Janelas, Elétrica, Hidráulica, Itens).
3) Pendências / Recomendações (apenas com base no observado).
`;

export const performComparisonAI = async (entryPdf: string, exitPdf: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Você é um Perito Engenheiro Civil e Vistoriador Imobiliário sênior.

    TAREFA:
    1. Compare os dois laudos anexos (Entrada e Saída).
    2. Identifique divergências (danos, sujeira, itens faltantes).
    3. Categorize cada divergência como: "Dano Provocado pelo Locatário" ou "Defeito Estrutural/Natural".
    4. Gere um orçamento de reparos utilizando como referência a Tabela SINAPI do Estado de São Paulo para mão de obra.
    5. Realize uma pesquisa na internet por preços ATUAIS de materiais em lojas como Leroy Merlin, Telhanorte ou Mercado Livre para os itens necessários.
    6. Forneça links diretos para os anúncios dos materiais citados.

    FORMATO DE RESPOSTA:
    Retorne um relatório técnico detalhado em Markdown conforme a estrutura profissional definida. Inclua uma tabela de custos com Colunas: Item, Quantidade, Valor Unitário (SINAPI/Loja), Valor Total e Link da Fonte.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }]
      }
    });

    const analysis = response.text || "Falha ao gerar análise.";

    // Extração de fontes via groundingMetadata conforme diretrizes do SDK
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Fonte de Preço",
        uri: chunk.web?.uri
      })).filter((s: any) => s.uri) || [];

    return { analysis, sources };
  } catch (error) {
    console.error("Erro na comparação pericial:", error);
    throw error;
  }
};

export const analyzeRoomVideoAI = async (roomType: string, videoData: string, mimeType: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `Analise este vídeo de vistoria do ambiente ${roomType}. Liste estados de conservação e avarias detectadas de forma técnica.` },
        { inlineData: { data: videoData, mimeType } }
      ]
    },
    config: { 
      systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itens: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                nome: { type: Type.STRING, description: "Item vistoriado" },
                estado: { type: Type.STRING, description: "Estado geral" },
                detalhes: { type: Type.STRING, description: "Descrição técnica objetiva" }
              },
              required: ["nome", "estado", "detalhes"]
            }
          },
          evidencias: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                timestampInicio: { type: Type.STRING, description: "Momento no vídeo (ex: 0:25)" },
                descricao: { type: Type.STRING, description: "Descrição do dano ou ponto crítico" },
                gravidade: { type: Type.STRING, description: "Nível de severidade" }
              },
              required: ["timestampInicio", "descricao", "gravidade"]
            }
          }
        },
        required: ["itens", "evidencias"]
      }
    }
  });

  const text = response.text;
  return text ? JSON.parse(text) : { itens: [], evidencias: [] };
};

