import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomVideoAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);

  useEffect(() => {
    localforage.getItem<Inspection[]>('qdez_rascunhos').then(data => {
      if (data) setInspections(data);
    });
  }, []);

  const saveDrafts = (updated: Inspection[]) => {
    setInspections(updated);
    localforage.setItem('qdez_rascunhos', updated);
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    const list = inspections.filter(i => i.id !== current.id);
    saveDrafts([updated, ...list]);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    updateCurrent({ rooms: updatedRooms });
  };

  const startNew = (type: Inspection['type'] = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setPdfEntry(null);
      setPdfExit(null);
      return;
    }
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrent(newIns);
    setView('editor');
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 5),
      type,
      customName: type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    updateCurrent({ rooms: [...current.rooms, newRoom] });
    setEditingRoom(newRoom.id);
  };

  const handleVideoAdded = async (roomId: string, videos: Video[]) => {
    if (!current) return;
    const video = videos[0];
    updateRoom(roomId, { videos: [...(current.rooms.find(r => r.id === roomId)?.videos || []), video] });

    setProcessingRoomId(roomId);
    try {
      const base64 = video.data.split(',')[1];
      const result = await analyzeRoomVideoAI(
        current.rooms.find(r => r.id === roomId)?.customName || "Ambiente", 
        base64, 
        video.mimeType
      );

      if (result) {
        const room = current.rooms.find(r => r.id === roomId);
        const newDesc = room?.description 
          ? `${room.description}\n\n[Análise Automática de Vídeo]:\n${result.descricaoTecnica}`
