              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center px-2">
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Cômodos da Vistoria</h3>
                <select className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-xl shadow-lg border-none ring-0" onChange={(e) => e.target.value && addRoom(e.target.value)}>
                  <option value="">+ Adicionar Ambiente</option>
                  {COMMON_ROOMS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              {current.rooms.map(room => (
                <div key={room.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
                  <div className="p-5 flex justify-between items-center cursor-pointer" onClick={() => setEditingRoom(editingRoom === room.id ? null : room.id)}>
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-white font-black shadow-inner ${getStatusColor(room.condition)}`}>
                         {room.condition.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 uppercase text-xs">{room.customName || room.type}</h4>
                        <div className="flex gap-2 mt-1">
                           <span className="text-[8px] font-bold px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded uppercase">{room.photos.length} Fotos</span>
                           <span className="text-[8px] font-bold px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded uppercase">{room.videos.length} Vídeos</span>
                        </div>
                      </div>
                    </div>
                    {processingRoomId === room.id ? (
                      <div className="w-5 h-5 border-2 border-red-600 border-t-transparent rounded-full animate-spin"></div>
                    ) : (
                      <svg className={`w-4 h-4 text-slate-300 transition-transform ${editingRoom === room.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                    )}
                  </div>

                  {editingRoom === room.id && (
                    <div className="p-6 border-t border-slate-50 space-y-6 bg-slate-50/20">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Nome Customizado</label>
                          <input className="w-full bg-white p-3 rounded-xl text-sm font-bold border border-slate-200" value={room.customName} onChange={(e) => updateRoom(room.id, { customName: e.target.value })} />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Estado de Conservação</label>
                          <div className="flex gap-1">
                            {(['Ótimo', 'Bom', 'Regular', 'Ruim'] as const).map(s => (
                              <button key={s} onClick={() => updateRoom(room.id, { condition: s })} className={`flex-1 text-[8px] font-black py-2.5 rounded-lg uppercase transition-all ${room.condition === s ? getStatusColor(s) + ' text-white shadow-lg scale-105' : 'bg-white text-slate-400 border border-slate-200'}`}>{s}</button>
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                        <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                        <VideoUploader onVideosAdded={(newVideos) => handleVideoAdded(room.id, newVideos)} />
                      </div>

                      {room.photos.length > 0 && (
                        <div className="grid grid-cols-4 gap-2">
                          {room.photos.map(photo => (
                            <div key={photo.id} className="relative group aspect-square rounded-xl overflow-hidden border border-slate-200 shadow-sm">
                               <img src={photo.data} className="w-full h-full object-cover" />
                               <button onClick={() => updateRoom(room.id, { photos: room.photos.filter(p => p.id !== photo.id) })} className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
                                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                               </button>
                            </div>
                          ))}
                        </div>
                      )}

                      <div className="space-y-2">
                        <div className="flex justify-between items-center">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Observações do Vistoriador</label>
                          <VoiceTranscription onTranscriptionComplete={(text) => updateRoom(room.id, { description: (room.description + ' ' + text).trim() })} />
                        </div>
                        <textarea className="w-full bg-white p-4 rounded-2xl border border-slate-200 text-sm h-32 leading-relaxed focus:ring-2 focus:ring-red-100 outline-none transition-all" placeholder="Relate o estado das paredes, teto, piso, elétrica e hidráulica..." value={room.description} onChange={(e) => updateRoom(room.id, { description: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-slate-50 via-slate-50/90 to-transparent no-print">
              <div className="max-w-md mx-auto grid grid-cols-2 gap-4">
                <button onClick={() => setView('list')} className="bg-slate-200 text-slate-700 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg">Sair e Salvar</button>
                <button onClick={() => { updateCurrent({ status: 'completed' }); setView('report'); }} className="bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-2xl">Finalizar Laudo</button>
              </div>
            </div>
          </div>
        )}

        {view === 'report' && current && (
          <div className="bg-white p-8 rounded-3xl shadow-sm mb-20">
            <div className="mb-8 no-print flex gap-4">
              <button onClick={() => setView('editor')} className="bg-slate-100 text-slate-600 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Voltar e Editar</button>
              <button onClick={() => window.print()} className="bg-red-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Imprimir / PDF</button>
            </div>
            <InspectionReport inspection={current} />
          </div>
        )}

        {view === 'comparison' && (
          <div className="max-w-xl mx-auto space-y-6 pt-10">
             <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-slate-100">
               <h2 className="text-xl font-black mb-2 uppercase tracking-tighter">Comparativo de Vistorias</h2>
               <p className="text-[10px] text-slate-400 font-bold uppercase mb-8">Detecte divergências entre entrada e saída</p>

               <div className="space-y-4">
                 <div className="p-6 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200 group hover:border-red-400 transition-colors">
                   <label className="text-[9px] font-black uppercase text-slate-400 block mb-3">Laudo de Entrada (PDF)</label>
                   <input type="file" accept=".pdf" onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0], setPdfEntry)} className="text-xs font-bold" />
                 </div>
                 <div className="p-6 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200 group hover:border-red-400 transition-colors">
                   <label className="text-[9px] font-black uppercase text-slate-400 block mb-3">Laudo de Saída (PDF)</label>
                   <input type="file" accept=".pdf" onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0], setPdfExit)} className="text-xs font-bold" />
                 </div>
               </div>

               <button 
                 onClick={async () => {
                   if (!pdfEntry || !pdfExit) return;
                   setIsBusy(true);
                   try {
                     const res = await performComparisonAI(pdfEntry, pdfExit);
                     updateCurrent({ comparisonResult: res, status: 'completed' });
                     setView('report');
                   } catch(e) { alert("Erro na comparação."); }
                   finally { setIsBusy(false); }
                 }}
                 disabled={isBusy || !pdfEntry || !pdfExit}
                 className="w-full mt-8 bg-slate-900 text-white py-5 rounded-3xl font-black uppercase text-xs tracking-widest disabled:opacity-50 shadow-2xl"
               >
                 {isBusy ? "Periciando..." : "Gerar Relatório de Danos"}
               </button>
             </div>
          </div>
        )}
      </main>

      {isBusy && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-10">
          <div className="bg-white p-10 rounded-[3rem] max-w-xs w-full text-center shadow-2xl animate-in zoom-in-95">
            <div className="w-16 h-16 border-4 border-red-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
            <h3 className="font-black text-slate-900 uppercase text-sm mb-2">Processamento IA</h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase leading-relaxed">Aguarde enquanto comparamos os documentos e pesquisamos custos de reparo...</p>
          </div>
        </div>
      )}
    </div>
  );
};

const handleFile = (file: File, setter: (val: string) => void) => {
  const reader = new FileReader();
  reader.onload = (e) => setter((e.target?.result as string).split(',')[1]);
  reader.readAsDataURL(file);
};

export default App;

import React, { useState, useEffect } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomVideoAI } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);

  // Carregar rascunhos ao iniciar
  useEffect(() => {
    localforage.getItem<Inspection[]>('qdez_rascunhos').then(data => {
      if (data) setInspections(data);
    });
  }, []);

  // Persistir sempre que a lista mudar
  useEffect(() => {
    if (inspections.length > 0) {
      localforage.setItem('qdez_rascunhos', inspections);
    }
  }, [inspections]);

  const saveToGlobalList = (updatedIns: Inspection) => {
    setInspections(prev => {
      const filtered = prev.filter(i => i.id !== updatedIns.id);
      return [updatedIns, ...filtered];
    });
    setLastSaved(new Date().toLocaleTimeString());
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    saveToGlobalList(updated);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedIns = { ...current, rooms: updatedRooms };
    setCurrent(updatedIns);
    saveToGlobalList(updatedIns);
  };

  // Fix: Implemented addRoom function to add a new room to the inspection
  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    const updated = { ...current, rooms: [...current.rooms, newRoom] };
    setCurrent(updated);
    saveToGlobalList(updated);
    setEditingRoom(newRoom.id);
  };

  const startNew = (type: Inspection['type'] = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setPdfEntry(null);
      setPdfExit(null);
      return;
    }
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrent(newIns);
    saveToGlobalList(newIns);
    setView('editor');
  };

  const handleVideoAdded = async (roomId: string, videos: Video[]) => {
    if (!current) return;
    const room = current.rooms.find(r => r.id === roomId);
    if (!room) return;

    updateRoom(roomId, { videos: [...room.videos, ...videos] });

    setProcessingRoomId(roomId);
    try {
      const video = videos[0];
      const base64 = video.data.split(',')[1];
      const result = await analyzeRoomVideoAI(room.customName || room.type, base64, video.mimeType);

      if (result) {
        const newDesc = room.description 
          ? `${room.description}\n\n[Análise IA]: ${result.descricaoTecnica}`
          : result.descricaoTecnica;

        updateRoom(roomId, { 
          description: newDesc,
          condition: result.estadoSugerido as any,
          aiAnalysis: {
            itens: {},
            evidencias: result.evidencias.map((ev: any) => ({
              timestampInicio: ev.timestamp,
              descricao: `${ev.item}: ${ev.descricao}`,
              gravidade: ev.gravidade
            }))
          }
        });
      }
    } catch (error) {
      console.error("Erro no processamento:", error);
    } finally {
      setProcessingRoomId(null);
    }
  };

  const getStatusColor = (status: Room['condition']) => {
    switch (status) {
      case 'Ótimo': return 'bg-green-600';
      case 'Bom': return 'bg-blue-600';
      case 'Regular': return 'bg-amber-500';
      case 'Ruim': return 'bg-red-600';
      default: return 'bg-slate-400';
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 text-white p-4 sticky top-0 z-50 shadow-lg no-print">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-8 h-8 bg-red-600 rounded flex items-center justify-center font-black">Q</div>
            <h1 className="font-black uppercase text-sm tracking-tighter">Qdez Vistoria AI</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => startNew('Comparação')} className="bg-slate-700 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Comparar PDFs</button>
            <button onClick={() => startNew()} className="bg-red-600 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">+ Nova Vistoria</button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 w-full flex-1">
        {view === 'list' && (
          <div className="space-y-8">
            <section>
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Em Andamento (Rascunhos)</h2>
              <div className="grid gap-4">
                {inspections.filter(i => i.status === 'draft').length === 0 ? (
                  <div className="p-8 border-2 border-dashed border-slate-200 rounded-3xl text-center text-slate-400 text-xs font-bold uppercase">Nenhum rascunho salvo</div>
                ) : (
                  inspections.filter(i => i.status === 'draft').map(ins => (
                    <div key={ins.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 flex justify-between items-center hover:border-red-500 transition-all cursor-pointer" onClick={() => { setCurrent(ins); setView('editor'); }}>
                      <div>
                        <div className="flex gap-2 items-center mb-1">
                          <span className="text-[9px] font-black uppercase text-red-600">{ins.type}</span>
                          <span className="text-[9px] font-bold text-slate-400">#{ins.id}</span>
                        </div>
                        <h3 className="font-bold text-slate-800">{ins.address || 'Sem endereço definido'}</h3>
                        <p className="text-[10px] text-slate-500">Locatário: {ins.tenantName || 'Pendente'}</p>
                      </div>
                      <svg className="w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
                    </div>
                  ))
                )}
              </div>
            </section>

            <section>
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Finalizadas</h2>
              <div className="grid gap-4 opacity-75">
                {inspections.filter(i => i.status === 'completed').map(ins => (
                  <div key={ins.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 flex justify-between items-center cursor-pointer" onClick={() => { setCurrent(ins); setView('report'); }}>
                    <div>
                      <h3 className="font-bold text-slate-800">{ins.address}</h3>
                      <p className="text-[10px] text-slate-500 italic">{new Date(ins.date).toLocaleDateString()}</p>
                    </div>
                    <span className="text-[8px] font-black bg-green-100 text-green-700 px-2 py-1 rounded-full uppercase">Concluída</span>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        {view === 'editor' && current && (
          <div className="space-y-6 pb-40 animate-in fade-in duration-300">
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
              <div className="flex justify-between items-start mb-4">
                <input className="flex-1 text-xl font-black border-none focus:ring-0 p-0 placeholder:text-slate-200" placeholder="Digite o endereço completo..." value={current.address} onChange={(e) => updateCurrent({ address: e.target.value })} />
                {lastSaved && <span className="text-[8px] font-bold text-slate-300 uppercase">Salvo às {lastSaved}</span>}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Proprietário</label>
                  <input className="w-full bg-slate-50 p-3 rounded-xl text-sm font-bold border-none ring-0" value={current.clientName} onChange={(e) => updateCurrent({ clientName: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Locatário / Interessado</label>
                  <input className="w-full bg-slate-50 p-3 rounded-xl text-sm font-bold border-none ring-0" value={current.tenantName} onChange={(e) => updateCurrent({ tenantName: e.target.value })} />
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center px-2">
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Cômodos da Vistoria</h3>
                <select className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-xl shadow-lg border-none ring-0" onChange={(e) => e.target.value && addRoom(e.target.value)}>
                  <option value="">+ Adicionar Ambiente</option>
                  {COMMON_ROOMS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              {current.rooms.map(room => (
                <div key={room.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
                  <div className="p-5 flex justify-between items-center cursor-pointer" onClick={() => setEditingRoom(editingRoom === room.id ? null : room.id)}>
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-white font-black shadow-inner ${getStatusColor(room.condition)}`}>
                         {room.condition.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 uppercase text-xs">{room.customName || room.type}</h4>
                        <div className="flex gap-2 mt-1">
                           <span className="text-[8px] font-bold px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded uppercase">{room.photos.length} Fotos</span>
                           <span className="text-[8px] font-bold px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded uppercase">{room.videos.length} Vídeos</span>
                        </div>
                      </div>
                    </div>
                    {processingRoomId === room.id ? (
                      <div className="w-5 h-5 border-2 border-red-600 border-t-transparent rounded-full animate-spin"></div>
                    ) : (
                      <svg className={`w-4 h-4 text-slate-300 transition-transform ${editingRoom === room.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                    )}
                  </div>

                  {editingRoom === room.id && (
                    <div className="p-6 border-t border-slate-50 space-y-6 bg-slate-50/20">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Nome Customizado</label>
                          <input className="w-full bg-white p-3 rounded-xl text-sm font-bold border border-slate-200" value={room.customName} onChange={(e) => updateRoom(room.id, { customName: e.target.value })} />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Estado de Conservação</label>
                          <div className="flex gap-1">
                            {(['Ótimo', 'Bom', 'Regular', 'Ruim'] as const).map(s => (
                              <button key={s} onClick={() => updateRoom(room.id, { condition: s })} className={`flex-1 text-[8px] font-black py-2.5 rounded-lg uppercase transition-all ${room.condition === s ? getStatusColor(s) + ' text-white shadow-lg scale-105' : 'bg-white text-slate-400 border border-slate-200'}`}>{s}</button>
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                        <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                        <VideoUploader onVideosAdded={(newVideos) => handleVideoAdded(room.id, newVideos)} />
