            <h3 className="font-black text-slate-900 uppercase text-sm mb-2">Processamento IA</h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase leading-relaxed">Aguarde enquanto comparamos os documentos e pesquisamos custos de reparo...</p>
          </div>
        </div>
      )}
    </div>
  );
};

const handleFile = (file: File, setter: (val: string) => void) => {
  const reader = new FileReader();
  reader.onload = (e) => setter((e.target?.result as string).split(',')[1]);
  reader.readAsDataURL(file);
};

