import { GoogleGenAI, Type } from "@google/genai";

const VISTORIADOR_SYSTEM_INSTRUCTION = `
Você é um Vistoriador(a) Profissional de Imóveis Sênior. Sua tarefa é REDIGIR a descrição técnica de uma VISTORIA com linguagem FORMAL, CLARA e OBJETIVA.

REGRAS DE OURO:
- Escreva em português do Brasil, tom extremamente profissional.
- Não presuma causas (ex: em vez de "vazamento do vizinho", use "mancha de umidade progressiva").
- Identifique materiais (madeira, MDF, granito, cerâmica, metal).
- Descreva o estado: "íntegro", "regular", "avariado", "com marcas de uso", "pintura nova", "descascado".
- Se houver danos, identifique a localização exata no ambiente.
- Ao analisar MÚLTIPLAS FOTOS ou VÍDEO, faça um inventário completo dos itens visíveis (portas, janelas, tomadas, luminárias, móveis fixos, pisos e tetos).
`;

export const analyzeRoomMediaAI = async (roomType: string, mediaItems: { data: string, mimeType: string }[]): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Usamos o gemini-3-pro-preview para análise visual complexa de fotos
  // ou gemini-3-flash-preview para vídeos (velocidade).
  // Se houver vídeo, priorizamos o flash-preview para eficiência.
  const hasVideo = mediaItems.some(item => item.mimeType.startsWith('video/'));
  const modelName = hasVideo ? 'gemini-3-flash-preview' : 'gemini-3-pro-preview';

  const parts = [
    { text: `Analise visualmente este ambiente (${roomType}) através das mídias anexadas.

    TAREFAS:
    1. Gere uma descrição técnica completa e profissional do ambiente em geral (pisos, paredes, tetos).
    2. Liste todos os itens específicos encontrados (ex: Ar condicionado, Armários, Janela, Porta) e descreva o estado de cada um.
    3. Identifique evidências de danos, desgaste ou falta de manutenção.
    4. Sugira o estado geral de conservação.

    Retorne em JSON estruturado.` },
    ...mediaItems.map(item => ({
      inlineData: {
        data: item.data.split(',')[1] || item.data,
        mimeType: item.mimeType
      }
    }))
  ];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        thinkingConfig: modelName === 'gemini-3-pro-preview' ? { thinkingBudget: 32768 } : undefined,
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            descricaoGeral: { type: Type.STRING, description: "Texto corrido descrevendo o ambiente." },
            estadoConservacao: { type: Type.STRING, enum: ["Ótimo", "Bom", "Regular", "Ruim"] },
            itensIdentificados: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  item: { type: Type.STRING },
                  estado: { type: Type.STRING },
                  detalhes: { type: Type.STRING }
                },
                required: ["item", "estado", "detalhes"]
              }
            },
            evidenciasDanos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  timestampOuLocal: { type: Type.STRING, description: "Timestamp se vídeo, ou local na foto" },
                  descricao: { type: Type.STRING },
                  gravidade: { type: Type.STRING, enum: ["Baixa", "Média", "Alta"] }
                }
              }
            }
          },
          required: ["descricaoGeral", "estadoConservacao", "itensIdentificados", "evidenciasDanos"]
        }
      }
    });

    const text = response.text;
    return text ? JSON.parse(text) : null;
  } catch (error) {
    console.error("Erro na análise Gemini:", error);
    throw error;
  }
};

export const performComparisonAI = async (entryPdf: string, exitPdf: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Compare os dois laudos anexos (Entrada e Saída). 
    Identifique divergências significativas, categorize danos e use o Google Search para estimar custos de reparo atuais.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }]
      }
    });

    const analysis = response.text || "Falha ao gerar análise.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Referência de Preço",
        uri: chunk.web?.uri
      })).filter((s: any) => s.uri) || [];

    return { analysis, sources };
  } catch (error) {
    console.error("Erro na comparação pericial:", error);
    throw error;
  }
};

export const transcribeAudio = async (base64Audio: string, mimeType: string = 'audio/webm'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite', // Resposta ultra rápida para transcrição
    contents: {
      parts: [
        { text: "Converta este áudio de vistoria para um texto técnico formal." },
        { inlineData: { data: base64Audio, mimeType: mimeType } }
      ]
    },
    config: { systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION }
  });
  return response.text || "";
};

// Nova função para buscar dados de localização via Maps Grounding
export const getPropertyContext = async (address: string, lat?: number, lng?: number): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `Forneça informações relevantes sobre a vizinhança e infraestrutura para o imóvel localizado em: ${address}`,
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: lat && lng ? { latitude: lat, longitude: lng } : undefined
        }
      }
    }
  });
  return response.text || "";
};

