            <div className="w-8 h-8 bg-red-600 rounded flex items-center justify-center font-black">Q</div>
            <h1 className="font-black uppercase text-sm tracking-tighter">Qdez Vistoria AI</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => startNew('Comparação')} className="bg-slate-700 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Comparar PDFs</button>
            <button onClick={() => startNew()} className="bg-red-600 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">+ Nova Vistoria</button>
          </div>
        </div>
      </header>

