                            <span className="text-[7px] font-black bg-slate-900 text-white px-1.5 py-0.5 rounded-full uppercase tracking-tighter animate-pulse">Auto-fill Ativo</span>
                          </div>
                          <VoiceTranscription onTranscriptionComplete={(text) => updateRoom(room.id, { description: (room.description + '\n' + text).trim() })} />
                        </div>
                        <textarea 
                          className="w-full bg-white p-6 rounded-[2rem] border border-slate-200 text-xs h-48 leading-relaxed focus:ring-4 focus:ring-red-50 outline-none transition-all shadow-inner" 
                          placeholder="A IA preencherá este campo automaticamente ao detectar itens em fotos/vídeos..." 
                          value={room.description} 
                          onChange={(e) => updateRoom(room.id, { description: e.target.value })} 
                        />
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/95 to-transparent no-print pointer-events-none">
              <div className="max-w-md mx-auto grid grid-cols-2 gap-4 pointer-events-auto">
                <button onClick={() => setView('list')} className="bg-slate-200 text-slate-700 py-5 rounded-[2rem] font-black uppercase text-[10px] tracking-[0.2em] shadow-lg active:scale-95 transition-transform">Pausar e Salvar</button>
                <button onClick={() => { updateCurrent({ status: 'completed' }); setView('report'); }} className="bg-slate-900 text-white py-5 rounded-[2rem] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl active:scale-95 transition-transform border-t border-white/10">Gerar Laudo PDF</button>
              </div>
            </div>
          </div>
        )}

        {view === 'report' && current && (
          <div className="bg-white p-12 rounded-[3rem] shadow-2xl mb-24 animate-in zoom-in-95 duration-500">
            <div className="mb-10 no-print flex justify-between items-center">
              <button onClick={() => setView('editor')} className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-colors">Voltar ao Editor</button>
              <button onClick={() => window.print()} className="bg-red-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-red-700 transition-colors">Exportar PDF</button>
            </div>
            <InspectionReport inspection={current} />
          </div>
        )}
      </main>

      {isBusy && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[100] flex items-center justify-center p-10 animate-in fade-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] max-w-sm w-full text-center shadow-[0_0_100px_rgba(220,38,38,0.2)]">
            <div className="w-20 h-20 border-4 border-red-600 border-t-transparent rounded-full animate-spin mx-auto mb-8 shadow-inner"></div>
            <h3 className="font-black text-slate-900 uppercase text-lg mb-3 tracking-tighter">Inteligência Qdez</h3>
            <p className="text-[11px] text-slate-400 font-bold uppercase leading-relaxed tracking-widest">Cruzando dados visuais e pesquisando referências de mercado...</p>
          </div>
        </div>
      )}
    </div>
  );
};

const handleFile = (file: File, setter: (val: string) => void) => {
  const reader = new FileReader();
  reader.onload = (e) => setter((e.target?.result as string).split(',')[1]);
  reader.readAsDataURL(file);
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomMediaAI, getPropertyContext } from './services/geminiService';

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);

  useEffect(() => {
    localforage.getItem<Inspection[]>('qdez_rascunhos').then(data => {
      if (data) setInspections(data);
    });
  }, []);

  useEffect(() => {
    if (inspections.length > 0) {
      localforage.setItem('qdez_rascunhos', inspections);
    }
  }, [inspections]);

  const saveToGlobalList = (updatedIns: Inspection) => {
    setInspections(prev => {
      const filtered = prev.filter(i => i.id !== updatedIns.id);
      return [updatedIns, ...filtered];
    });
    setLastSaved(new Date().toLocaleTimeString());
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    saveToGlobalList(updated);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedIns = { ...current, rooms: updatedRooms };
    setCurrent(updatedIns);
    saveToGlobalList(updatedIns);
  };

  const handleMediaAnalysis = async (roomId: string, photos: Photo[], videos: Video[]) => {
    if (!current) return;
    const room = current.rooms.find(r => r.id === roomId);
    if (!room) return;

    setProcessingRoomId(roomId);

    try {
      const mediaToAnalyze = [
        ...photos.map(p => ({ data: p.data, mimeType: p.mimeType })),
        ...videos.map(v => ({ data: v.data, mimeType: v.mimeType }))
      ];

      const analysisItems = mediaToAnalyze.slice(-10); 

      const result = await analyzeRoomMediaAI(room.customName || room.type, analysisItems);

      if (result) {
        const itemsText = result.itensIdentificados
          .map((i: any) => `- ${i.item}: ${i.estado}. (${i.detalhes})`)
          .join('\n');

        const newDesc = `[ANÁLISE IA AUTOMÁTICA]\n\n${result.descricaoGeral}\n\nITENS IDENTIFICADOS:\n${itemsText}`;

        updateRoom(roomId, { 
          description: newDesc,
          condition: result.estadoConservacao,
          aiAnalysis: {
            itens: result.itensIdentificados,
            evidencias: result.evidenciasDanos.map((ev: any) => ({
              timestampInicio: ev.timestampOuLocal || '00:00',
              descricao: ev.descricao,
              gravidade: ev.gravidade
            }))
          }
        });
      }
    } catch (error) {
      console.error("Erro na análise automática:", error);
    } finally {
      setProcessingRoomId(null);
    }
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    const updated = { ...current, rooms: [...current.rooms, newRoom] };
    setCurrent(updated);
    saveToGlobalList(updated);
    setEditingRoom(newRoom.id);
  };

  const getStatusColor = (status: Room['condition']) => {
    switch (status) {
      case 'Ótimo': return 'bg-green-600';
      case 'Bom': return 'bg-blue-600';
      case 'Regular': return 'bg-amber-500';
      case 'Ruim': return 'bg-red-600';
      default: return 'bg-slate-400';
    }
  };

  const startNew = (type: Inspection['type'] = 'Entrada') => {
    if (type === 'Comparação') {
      setView('comparison');
      setPdfEntry(null);
      setPdfExit(null);
      return;
    }
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrent(newIns);
    saveToGlobalList(newIns);
    setView('editor');
  };

  // Fixed: Added explicit Record type to avoid 'unknown' inference in Object.entries
  const roomSummary = useMemo(() => {
    if (!current) return null;
    const counts: Record<string, number> = { Ótimo: 0, Bom: 0, Regular: 0, Ruim: 0 };
    current.rooms.forEach(r => {
      counts[r.condition]++;
    });
    return counts;
  }, [current]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
