                <button onClick={() => { updateCurrent({ status: 'completed' }); setView('report'); }} className="bg-slate-900 text-white py-5 rounded-[2rem] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl active:scale-95 transition-transform border-t border-white/10">Gerar Laudo PDF</button>
              </div>
            </div>
          </div>
        )}

        {view === 'report' && current && (
          <div className="bg-white p-12 rounded-[3rem] shadow-2xl mb-24 animate-in zoom-in-95 duration-500">
            <div className="mb-10 no-print flex justify-between items-center">
              <button onClick={() => setView('editor')} className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-colors">Voltar ao Editor</button>
              <button onClick={() => window.print()} className="bg-red-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-red-700 transition-colors">Exportar PDF</button>
            </div>
            <InspectionReport inspection={current} />
