            <h3 className="font-black text-slate-900 uppercase text-lg mb-3 tracking-tighter">Inteligência Qdez</h3>
            <p className="text-[11px] text-slate-400 font-bold uppercase leading-relaxed tracking-widest">Cruzando dados visuais e pesquisando referências de mercado...</p>
          </div>
        </div>
      )}
    </div>
  );
};

