import { GoogleGenAI, Type } from "@google/genai";

const VISTORIADOR_SYSTEM_INSTRUCTION = `
Você é David Oliveira (Creci 84926-F), um Vistoriador Profissional de Imóveis. 
Sua tarefa é REDIGIR descrições técnicas EXTREMAMENTE OBJETIVAS, CURTAS E DIRETAS.

REGRAS DE OURO:
- Proibido usar adjetivos subjetivos (lindo, bom, excelente). Use termos técnicos: íntegro, novo, com marcas de uso, avariado, funcional.
- Liste os itens identificados em tópicos (bullet points).
- Para cada item, indique apenas o material e o ESTADO DE CONSERVAÇÃO observado.
- Não crie parágrafos longos. Seja telegráfico se necessário.
- Ignore detalhes irrelevantes. Foque em: pintura, pisos, esquadrias, elétrica, hidráulica e móveis fixos.
- No caso de danos, apenas descreva o fato (ex: "Mancha de umidade em base de parede").
`;

export const analyzeRoomMediaAI = async (roomType: string, mediaItems: { data: string, mimeType: string }[]): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const hasVideo = mediaItems.some(item => item.mimeType.startsWith('video/'));
  const modelName = hasVideo ? 'gemini-3-flash-preview' : 'gemini-3-pro-preview';

  const parts = [
    { text: `Analise as mídias deste ambiente: ${roomType}. 
    1. Forneça uma frase curta sobre o estado geral.
    2. Gere uma lista técnica de itens identificados e seus respectivos estados de conservação.
    Seja extremamente resumido.

    Retorne o resultado estritamente no formato JSON definido.` },
    ...mediaItems.map(item => ({
      inlineData: {
        data: item.data.split(',')[1] || item.data,
        mimeType: item.mimeType
      }
    }))
  ];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        thinkingConfig: modelName === 'gemini-3-pro-preview' ? { thinkingBudget: 32768 } : undefined,
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            descricaoGeral: { type: Type.STRING, description: "Frase única e curta sobre o ambiente." },
            estadoConservacao: { type: Type.STRING, enum: ["Ótimo", "Bom", "Regular", "Ruim"] },
            itensIdentificados: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  item: { type: Type.STRING },
                  estado: { type: Type.STRING },
                  detalhes: { type: Type.STRING, description: "Apenas se houver dano específico." }
                },
                required: ["item", "estado", "detalhes"]
              }
            },
            evidenciasDanos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  timestampOuLocal: { type: Type.STRING },
                  descricao: { type: Type.STRING },
                  gravidade: { type: Type.STRING, enum: ["Baixa", "Média", "Alta"] }
                }
              }
            }
          },
          required: ["descricaoGeral", "estadoConservacao", "itensIdentificados", "evidenciasDanos"]
        }
      }
    });

    const text = response.text;
    return text ? JSON.parse(text) : null;
  } catch (error) {
    console.error("Erro na análise Gemini:", error);
    throw error;
  }
};

export const performComparisonAI = async (entryPdf: string, exitPdf: string, manualObs?: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    AJA COMO PERITO: Compare os laudos de ENTRADA e SAÍDA.
    IDENTIFIQUE APENAS AS DIVERGÊNCIAS (itens que pioraram o estado).
    ${manualObs ? `CONSIDERE AS SEGUINTES OBSERVAÇÕES MANUAIS DO VISTORIADOR: "${manualObs}"` : ''}

    Para cada divergência encontrada, use o Google Search para estimar um custo médio de reparo ou troca no mercado brasileiro atual.

    ESTRUTURA DO RELATÓRIO:
    1. Lista de divergências encontradas.
    2. Comparativo técnico de estado.
    3. Estimativa de custos de reparo.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    const analysis = response.text || "Falha ao gerar análise pericial.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Referência de Preço",
        uri: chunk.web?.uri
      })).filter((s: any) => s.uri) || [];

    return { analysis, sources };
  } catch (error) {
    console.error("Erro na comparação pericial:", error);
    throw error;
  }
};

export const transcribeAudio = async (base64Audio: string, mimeType: string = 'audio/webm'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
