`;

export const analyzeRoomMediaAI = async (roomType: string, inspectionType: string, mediaItems: { data: string, mimeType: string }[]): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const hasVideo = mediaItems.some(item => item.mimeType.startsWith('video/'));
  const modelName = hasVideo ? 'gemini-3-flash-preview' : 'gemini-3-pro-preview';

  const parts = [
    { text: `Analise as mídias deste ambiente: ${roomType}. 
    Este é um Laudo de ${inspectionType}.

    TAREFA:
    1. Forneça uma descrição técnica detalhada das paredes, piso e teto.
    2. Gere uma lista minuciosa de todos os itens identificados (portas, janelas, tomadas, móveis, ar condicionado, etc).
    3. Indique o estado de conservação de cada item com precisão pericial.

    Retorne o resultado no formato JSON definido.` },
    ...mediaItems.map(item => ({
      inlineData: {
        data: item.data.split(',')[1] || item.data,
        mimeType: item.mimeType
      }
    }))
  ];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        thinkingConfig: modelName === 'gemini-3-pro-preview' ? { thinkingBudget: 32768 } : undefined,
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            descricaoGeral: { type: Type.STRING, description: "Descrição técnica e detalhada do ambiente em geral." },
            estadoConservacao: { type: Type.STRING, enum: ["Ótimo", "Bom", "Regular", "Ruim"] },
            itensIdentificados: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  item: { type: Type.STRING },
                  estado: { type: Type.STRING },
                  detalhes: { type: Type.STRING, description: "Detalhes minuciosos sobre o estado ou material." }
                },
                required: ["item", "estado", "detalhes"]
              }
            },
            evidenciasDanos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  timestampOuLocal: { type: Type.STRING },
                  descricao: { type: Type.STRING },
                  gravidade: { type: Type.STRING, enum: ["Baixa", "Média", "Alta"] }
                }
              }
            }
          },
          required: ["descricaoGeral", "estadoConservacao", "itensIdentificados", "evidenciasDanos"]
        }
      }
    });

    const text = response.text;
    return text ? JSON.parse(text) : null;
  } catch (error) {
    console.error("Erro na análise Gemini:", error);
    throw error;
  }
};

export const performComparisonAI = async (entryPdf: string, exitPdf: string, manualObs?: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    PERÍCIA COMPARATIVA: Analise os laudos de ENTRADA e SAÍDA.
    IDENTIFIQUE TODAS AS DIVERGÊNCIAS relevantes onde houve piora no estado do imóvel.
    ${manualObs ? `CONSIDERE ESTAS OBSERVAÇÕES DO CORRETOR: "${manualObs}"` : ''}

    Gere um relatório técnico de danos e use o Google Search para estimar custos de reparo/substituição.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    return { 
      analysis: response.text || "Falha ao gerar análise.",
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks
        ?.map((chunk: any) => ({
          title: chunk.web?.title || "Referência de Preço",
          uri: chunk.web?.uri
        })).filter((s: any) => s.uri) || []
    };
  } catch (error) {
    console.error("Erro na comparação pericial:", error);
    throw error;
  }
};

export const transcribeAudio = async (base64Audio: string, mimeType: string = 'audio/webm'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-flash-lite-latest',
    contents: {
      parts: [
        { text: "Converta este áudio de vistoria em texto técnico e formal, corrigindo a gramática mas mantendo o sentido original." },
        { inlineData: { data: base64Audio, mimeType: mimeType } }
      ]
    },
    config: { systemInstruction: VISTORIADOR_SYSTEM_INSTRUCTION }
  });
  return response.text || "";
};

