import { GoogleGenAI, Type } from "@google/genai";
import { AppSettings } from "../types";

const getSystemInstruction = (settings: AppSettings) => {
  let detailInstruction = "";
  if (settings.detailLevel === 'Conciso') {
    detailInstruction = "Seja extremamente breve e direto. Foque apenas no estado geral e danos críticos.";
  } else if (settings.detailLevel === 'Muito Detalhado') {
    detailInstruction = "Seja exaustivo. Descreva materiais, texturas, marcas aparentes de desgaste e faça um inventário minucioso de cada centímetro do ambiente.";
  }

  const severityInstruction = `Em caso de dúvidas sobre danos, classifique a gravidade como '${settings.defaultSeverity}' por padrão.`;
  const toneInstruction = `Use um tom predominantemente ${settings.tone}.`;

  return `
Você é David Oliveira (Creci 84926-F), um Vistoriador Profissional de Imóveis especialista em laudos periciais.
Sua tarefa é REDIGIR descrições técnicas PRECISAS para laudos de vistoria imobiliária.

ESTILO ESPECÍFICO:
- ${detailInstruction}
- ${severityInstruction}
- ${toneInstruction}

REGRAS GERAIS:
- Use linguagem profissional (ex: "piso em porcelanato acetinado", "pintura látex fosca").
- Foque estritamente no ESTADO DE CONSERVAÇÃO (novo, íntegro, avariado, com marcas de uso).
- Não presuma causas de danos. Relate apenas o que é visualmente observável.
- Organize os itens em listas para facilitar a leitura técnica.
`;
};

export const analyzeRoomMediaAI = async (
  roomType: string, 
  inspectionType: string, 
  mediaItems: { data: string, mimeType: string }[],
  settings: AppSettings
): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Usando modelos da série 3 conforme as diretrizes para tarefas complexas/visuais
  const hasVideo = mediaItems.some(item => item.mimeType.startsWith('video/'));
  const modelName = hasVideo ? 'gemini-3-flash-preview' : 'gemini-3-pro-preview';

  const parts = [
    { text: `Analise as mídias deste ambiente (${roomType}) para um Laudo de ${inspectionType}.

    TAREFAS:
    1. Gere uma descrição técnica detalhada do ambiente seguindo as instruções de sistema.
    2. Liste todos os itens identificados e descreva o estado de conservação.
    3. Identifique evidências de danos ou falta de manutenção.

    RETORNE OBRIGATORIAMENTE EM JSON conforme o schema.` },
    ...mediaItems.map(item => ({
      inlineData: {
        data: item.data.split(',')[1] || item.data,
        mimeType: item.mimeType
      }
    }))
  ];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction: getSystemInstruction(settings),
        responseMimeType: "application/json",
        // Desativando thinkingConfig para esta tarefa para garantir que todos os tokens sejam usados na resposta JSON técnica
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            descricaoGeral: { type: Type.STRING, description: "Descrição detalhada e técnica do ambiente." },
            estadoConservacao: { type: Type.STRING, enum: ["Ótimo", "Bom", "Regular", "Ruim"] },
            itensIdentificados: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  item: { type: Type.STRING },
                  estado: { type: Type.STRING },
                  detalhes: { type: Type.STRING }
                },
                required: ["item", "estado", "detalhes"]
              }
            },
            evidenciasDanos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  timestampOuLocal: { type: Type.STRING },
                  descricao: { type: Type.STRING },
                  gravidade: { type: Type.STRING, enum: ["Baixa", "Média", "Alta"] }
                }
              }
            }
          },
          required: ["descricaoGeral", "estadoConservacao", "itensIdentificados", "evidenciasDanos"]
        }
      }
    });

    const text = response.text;
    if (!text) return null;

    // Limpeza básica para garantir JSON válido caso o modelo retorne markdown
    const cleanedJson = text.replace(/```json/g, "").replace(/```/g, "").trim();
    return JSON.parse(cleanedJson);
  } catch (error) {
    console.error("Erro na análise técnica IA:", error);
    throw error;
  }
};

export const performComparisonAI = async (
  entryPdf: string, 
  exitPdf: string, 
  settings: AppSettings,
  manualObs?: string
): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    AJA COMO PERITO: Compare os laudos de ENTRADA e SAÍDA anexados.
    IDENTIFIQUE DIVERGÊNCIAS de estado e danos.
    ${manualObs ? `CONSIDERE ESTAS OBSERVAÇÕES ADICIONAIS DO VISTORIADOR: "${manualObs}"` : ''}

    Use o Google Search para encontrar custos estimados de reparo no mercado brasileiro atual.
    Gere um laudo pericial de divergências detalhado seguindo o estilo: Nível de Detalhe ${settings.detailLevel}, Tom ${settings.tone}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        systemInstruction: getSystemInstruction(settings),
        tools: [{ googleSearch: {} }]
      }
    });

    const analysis = response.text || "Falha na análise comparativa.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Referência Técnica",
        uri: chunk.web?.uri
      })).filter((s: any) => s.uri) || [];

    return { analysis, sources };
  } catch (error) {
    console.error("Erro na comparação pericial:", error);
    throw error;
  }
};

export const transcribeAudio = async (base64Audio: string, settings: AppSettings, mimeType: string = 'audio/webm'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-flash-lite-latest',
    contents: {
      parts: [
        { text: `Transcreva este áudio de vistoria para um texto técnico formal. Siga o tom: ${settings.tone}.` },
        { inlineData: { data: base64Audio, mimeType: mimeType } }
      ]
    },
    config: { systemInstruction: getSystemInstruction(settings) }
  });
  return response.text || "";
};

import React, { useState, useEffect, useMemo } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video, AppSettings } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomMediaAI } from './services/geminiService';

const DEFAULT_INSPECTOR = "David Oliveira - Creci 84926-F";
const DEFAULT_SETTINGS: AppSettings = {
  detailLevel: 'Normal',
  defaultSeverity: 'Média',
  tone: 'Técnico'
};

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison' | 'type_selector' | 'settings'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);
  const [manualComparisonObs, setManualComparisonObs] = useState('');

  // Carregar vistorias e configurações ao iniciar
  useEffect(() => {
    Promise.all([
      localforage.getItem<Inspection[]>('qdez_rascunhos'),
      localforage.getItem<AppSettings>('qdez_settings')
    ]).then(([storedInspections, storedSettings]) => {
      if (storedInspections) setInspections(storedInspections);
      if (storedSettings) setSettings(storedSettings);
      setIsLoaded(true);
    });
  }, []);

  // Persistência automática
  useEffect(() => {
    if (isLoaded) {
      localforage.setItem('qdez_rascunhos', inspections);
      localforage.setItem('qdez_settings', settings);
    }
  }, [inspections, settings, isLoaded]);

  // Resumo de estado dos ambientes (Ótimo, Bom, Regular, Ruim)
  const roomSummary = useMemo(() => {
    if (!current || current.rooms.length === 0) return null;
    const summary = { 'Ótimo': 0, 'Bom': 0, 'Regular': 0, 'Ruim': 0 };
    current.rooms.forEach(room => { 
      if (summary[room.condition] !== undefined) {
        summary[room.condition]++; 
      }
    });
    return summary;
  }, [current?.rooms]);

  const saveToGlobalList = (updatedIns: Inspection) => {
    setInspections(prev => {
      const filtered = prev.filter(i => i.id !== updatedIns.id);
      return [updatedIns, ...filtered];
    });
    setLastSaved(new Date().toLocaleTimeString());
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmDelete = window.confirm("ATENÇÃO: Deseja realmente excluir esta vistoria? Esta ação é permanente.");
    if (confirmDelete) {
      setInspections(prev => prev.filter(ins => ins.id !== id));
      if (current?.id === id) {
        setCurrent(null);
        setView('list');
      }
    }
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    saveToGlobalList(updated);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedIns = { ...current, rooms: updatedRooms };
    setCurrent(updatedIns);
    saveToGlobalList(updatedIns);
  };

  const handleManualRoomAnalysis = async (roomId: string) => {
    if (!current) return;
    const room = current.rooms.find(r => r.id === roomId);
    if (!room) return;
    if (room.photos.length === 0 && room.videos.length === 0) {
      alert("Por favor, adicione fotos ou vídeos antes de iniciar a análise por IA.");
      return;
    }
    setProcessingRoomId(roomId);
    try {
      const mediaToAnalyze = [
        ...room.photos.map(p => ({ data: p.data, mimeType: p.mimeType })),
        ...room.videos.map(v => ({ data: v.data, mimeType: v.mimeType }))
      ];

      const result = await analyzeRoomMediaAI(
        room.customName || room.type, 
        current.type, 
        mediaToAnalyze.slice(-10), 
        settings
      );

      if (result) {
        const itemsText = result.itensIdentificados.map((i: any) => `- ${i.item}: ${i.estado}. ${i.detalhes}`).join('\n');
        const newDesc = `${result.descricaoGeral}\n\nITENS IDENTIFICADOS:\n${itemsText}`;
        updateRoom(roomId, { 
          description: newDesc,
          condition: result.estadoConservacao,
          aiAnalysis: {
            itens: result.itensIdentificados,
            evidencias: result.evidenciasDanos.map((ev: any) => ({
              timestampInicio: ev.timestampOuLocal || 'Localizado',
              descricao: ev.descricao,
              gravidade: ev.gravidade
            }))
          }
        });
      }
    } catch (error) {
      console.error("Erro na análise IA:", error);
      alert("Não foi possível completar a análise IA deste ambiente no momento. Verifique sua conexão ou tente novamente.");
    } finally {
      setProcessingRoomId(null);
    }
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    const updated = { ...current, rooms: [...current.rooms, newRoom] };
    setCurrent(updated);
    saveToGlobalList(updated);
    setEditingRoom(newRoom.id);
  };

  const getStatusColor = (status: Room['condition']) => {
    switch (status) {
      case 'Ótimo': return 'bg-green-600';
      case 'Bom': return 'bg-blue-600';
      case 'Regular': return 'bg-amber-500';
      case 'Ruim': return 'bg-red-600';
      default: return 'bg-slate-400';
    }
  };

  const startNewSequence = () => { setView('type_selector'); };

  const confirmNewInspection = (type: Inspection['type']) => {
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      inspectorName: DEFAULT_INSPECTOR,
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrent(newIns);
    saveToGlobalList(newIns);
    if (type === 'Comparação') {
      setPdfEntry(null);
      setPdfExit(null);
      setManualComparisonObs('');
      setView('comparison');
    } else {
      setView('editor');
    }
  };

  const handleRunComparison = async () => {
    if (!pdfEntry || !pdfExit || !current) {
      alert("Por favor, selecione os dois arquivos PDF para análise.");
      return;
    }
    setIsBusy(true);
    try {
      const res = await performComparisonAI(pdfEntry, pdfExit, settings, manualComparisonObs);
      const updatedCurrent: Inspection = { 
        ...current, 
        comparisonResult: {
          analysis: res.analysis,
          sources: res.sources,
          budget: "", 
          manualObservations: manualComparisonObs
        }, 
        status: 'completed' as const,
        date: new Date().toISOString()
      };
      setCurrent(updatedCurrent);
      saveToGlobalList(updatedCurrent);
      setView('report');
    } catch(e) { 
      alert("Erro na comparação pericial. Verifique se os PDFs são válidos e tente novamente."); 
    } finally { 
      setIsBusy(false); 
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string) => void) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = (ev.target?.result as string).split(',')[1];
        setter(base64);
      };
      reader.readAsDataURL(file);
    } else if (file) {
      alert("Apenas arquivos PDF são aceitos.");
      e.target.value = '';
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 text-white p-4 sticky top-0 z-50 shadow-lg no-print">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-8 h-8 bg-red-600 rounded flex items-center justify-center font-black">Q</div>
            <h1 className="font-black uppercase text-sm tracking-tighter">Qdez Vistoria AI</h1>
          </div>
          <div className="flex gap-4 items-center">
            <button 
              onClick={() => setView('settings')} 
              className={`p-2 rounded-xl transition-colors ${view === 'settings' ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
