import { GoogleGenAI, Type } from "@google/genai";
import { AppSettings } from "../types";

const getSystemInstruction = (settings: AppSettings, context: 'analysis' | 'comparison' = 'analysis') => {
  const detailInstruction = {
    'Conciso': "Seja extremamente breve e direto. Foque apenas no estado geral e danos críticos.",
    'Normal': "Descreva o estado de conservação de forma equilibrada e técnica.",
    'Muito Detalhado': "Seja exaustivo. Descreva materiais, texturas, marcas de uso e faça um inventário minucioso."
  }[settings.detailLevel];

  const severityInstruction = `Em caso de dúvidas sobre danos, classifique a gravidade como '${settings.defaultSeverity}' por padrão.`;
  const toneInstruction = `Use um tom predominantemente ${settings.tone}.`;

  if (context === 'comparison') {
    return `Você é David Oliveira (Creci 84926-F), um Perito Vistoriador Imobiliário.
Sua tarefa é COMPARAR dois laudos (Entrada e Saída) e identificar DIVERGÊNCIAS DOCUMENTAIS.
- Identifique danos novos, itens faltantes ou mudanças no estado de conservação.
- Use o Google Search para estimar custos de reparo no mercado brasileiro.
- Seja imparcial e estritamente técnico.
- ${detailInstruction}
- ${toneInstruction}`;
  }

  return `Você é David Oliveira (Creci 84926-F), um Vistoriador Profissional de Imóveis.
Sua tarefa é REDIGIR descrições técnicas PRECISAS para vistorias.
- Use linguagem técnica (ex: "pintura látex fosca", "esquadrias de alumínio").
- Relate apenas o que é visualmente observável.
- ${detailInstruction}
- ${severityInstruction}
- ${toneInstruction}`;
};

/**
 * Analisa mídias de um ambiente para gerar descrição técnica.
 */
export const analyzeRoomMediaAI = async (
  roomType: string, 
  inspectionType: string, 
  mediaItems: { data: string, mimeType: string }[],
  settings: AppSettings
): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview';

  const parts = [
    { text: `Analise as mídias deste ambiente (${roomType}) para um Laudo de ${inspectionType}.

    TAREFAS:
    1. Gere uma descrição técnica detalhada seguindo as instruções de sistema.
    2. Liste itens e estados de conservação.
    3. Identifique evidências de danos.

    RETORNE EM JSON.` },
    ...mediaItems.map(item => ({
      inlineData: {
        data: item.data.includes('base64,') ? item.data.split('base64,')[1] : item.data,
        mimeType: item.mimeType
      }
    }))
  ];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction: getSystemInstruction(settings, 'analysis'),
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            descricaoGeral: { type: Type.STRING },
            estadoConservacao: { type: Type.STRING, enum: ["Ótimo", "Bom", "Regular", "Ruim"] },
            itensIdentificados: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  item: { type: Type.STRING },
                  estado: { type: Type.STRING },
                  detalhes: { type: Type.STRING }
                },
                required: ["item", "estado", "detalhes"]
              }
            },
            evidenciasDanos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  timestampOuLocal: { type: Type.STRING },
                  descricao: { type: Type.STRING },
                  gravidade: { type: Type.STRING, enum: ["Baixa", "Média", "Alta"] }
                }
              }
            }
          },
          required: ["descricaoGeral", "estadoConservacao", "itensIdentificados", "evidenciasDanos"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Resposta da IA vazia");

    return JSON.parse(text.replace(/```json/g, "").replace(/```/g, "").trim());
  } catch (error) {
    console.error("Erro detalhado na análise IA:", error);
    throw error;
  }
};

/**
 * Realiza comparação pericial entre dois PDFs com otimização de payload.
 */
export const performComparisonAI = async (
  entryPdf: string, 
  exitPdf: string, 
  settings: AppSettings,
  manualObs?: string
): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Mudança para o modelo Flash-Preview: maior tolerância a requisições grandes e latência menor
  const modelName = 'gemini-3-flash-preview';

  const prompt = `AJA COMO PERITO PERQUISIDOR:
Compare o Laudo de ENTRADA (PDF 1) com o Laudo de SAÍDA (PDF 2).

FOCO DA ANÁLISE:
1. Itens novos faltantes ou danificados.
2. Manchas, quebras ou avarias não registradas no laudo original de entrada.
3. Diferenças na conservação de pintura, pisos e metais.

${manualObs ? `ATENÇÃO ESPECIAL DO VISTORIADOR: "${manualObs}"` : ''}

Utilize o Google Search para referenciar custos médios de mercado para reparos das divergências encontradas.
Apresente o laudo final em Markdown organizado por ambientes.`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { data: entryPdf, mimeType: 'application/pdf' } },
          { inlineData: { data: exitPdf, mimeType: 'application/pdf' } }
        ]
      },
      config: {
        systemInstruction: getSystemInstruction(settings, 'comparison'),
        tools: [{ googleSearch: {} }]
      }
    });

    const analysis = response.text || "Não foi possível extrair a análise do documento.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Fonte de Custo",
        uri: chunk.web?.uri
      })).filter((s: any) => s.uri) || [];

    return { analysis, sources };
  } catch (error) {
    console.error("Erro na comparação pericial (Service):", error);
    throw error;
  }
};

/**
 * Transcreve áudio para texto técnico.
 */
export const transcribeAudio = async (base64Audio: string, settings: AppSettings, mimeType: string = 'audio/webm'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: `Transcreva este áudio de vistoria imobiliária. Converta gírias para termos técnicos. Tom: ${settings.tone}.` },
          { inlineData: { data: base64Audio, mimeType: mimeType } }
        ]
      },
      config: { systemInstruction: getSystemInstruction(settings, 'analysis') }
    });
    return response.text || "";
  } catch (error) {
    console.error("Erro na transcrição:", error);
    return "";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video, AppSettings } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomMediaAI } from './services/geminiService';

const DEFAULT_INSPECTOR = "David Oliveira - Creci 84926-F";
const DEFAULT_SETTINGS: AppSettings = {
  detailLevel: 'Normal',
  defaultSeverity: 'Média',
  tone: 'Técnico'
};

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison' | 'type_selector' | 'settings'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);
  const [manualComparisonObs, setManualComparisonObs] = useState('');

  // Carregar vistorias e configurações ao iniciar
  useEffect(() => {
    Promise.all([
      localforage.getItem<Inspection[]>('qdez_rascunhos'),
      localforage.getItem<AppSettings>('qdez_settings')
    ]).then(([storedInspections, storedSettings]) => {
      if (storedInspections) setInspections(storedInspections);
      if (storedSettings) setSettings(storedSettings);
      setIsLoaded(true);
    });
  }, []);

  // Persistência automática
  useEffect(() => {
    if (isLoaded) {
      localforage.setItem('qdez_rascunhos', inspections);
      localforage.setItem('qdez_settings', settings);
    }
  }, [inspections, settings, isLoaded]);

  // Resumo de estado dos ambientes
  const roomSummary = useMemo(() => {
    if (!current || current.rooms.length === 0) return null;
    const summary = { 'Ótimo': 0, 'Bom': 0, 'Regular': 0, 'Ruim': 0 };
    current.rooms.forEach(room => { 
      if (summary[room.condition] !== undefined) {
        summary[room.condition]++; 
      }
    });
    return summary;
  }, [current?.rooms]);

  const saveToGlobalList = (updatedIns: Inspection) => {
    setInspections(prev => {
      const filtered = prev.filter(i => i.id !== updatedIns.id);
      return [updatedIns, ...filtered];
    });
    setLastSaved(new Date().toLocaleTimeString());
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmDelete = window.confirm("ATENÇÃO: Deseja realmente excluir esta vistoria?");
    if (confirmDelete) {
      setInspections(prev => prev.filter(ins => ins.id !== id));
      if (current?.id === id) {
        setCurrent(null);
        setView('list');
      }
    }
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    saveToGlobalList(updated);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedIns = { ...current, rooms: updatedRooms };
    setCurrent(updatedIns);
    saveToGlobalList(updatedIns);
  };

  const handleManualRoomAnalysis = async (roomId: string) => {
    if (!current) return;
    const room = current.rooms.find(r => r.id === roomId);
    if (!room || (room.photos.length === 0 && room.videos.length === 0)) {
      alert("Adicione mídias para análise.");
      return;
    }
    setProcessingRoomId(roomId);
    try {
      const media = [
        ...room.photos.map(p => ({ data: p.data, mimeType: p.mimeType })),
        ...room.videos.map(v => ({ data: v.data, mimeType: v.mimeType }))
      ];
      const result = await analyzeRoomMediaAI(room.customName || room.type, current.type, media.slice(-10), settings);
      if (result) {
        const itemsText = result.itensIdentificados.map((i: any) => `- ${i.item}: ${i.estado}. ${i.detalhes}`).join('\n');
        updateRoom(roomId, { 
          description: `${result.descricaoGeral}\n\nITENS IDENTIFICADOS:\n${itemsText}`,
          condition: result.estadoConservacao,
          aiAnalysis: {
            itens: result.itensIdentificados,
            evidencias: result.evidenciasDanos.map((ev: any) => ({
              timestampInicio: ev.timestampOuLocal || 'Localizado',
              descricao: ev.descricao,
              gravidade: ev.gravidade
            }))
          }
        });
      }
    } catch (error: any) {
      alert("Erro na análise técnica. Tente fotos mais leves.");
    } finally {
      setProcessingRoomId(null);
    }
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    updateCurrent({ rooms: [...current.rooms, newRoom] });
    setEditingRoom(newRoom.id);
  };

  const getStatusColor = (status: Room['condition']) => {
    switch (status) {
      case 'Ótimo': return 'bg-green-600';
      case 'Bom': return 'bg-blue-600';
      case 'Regular': return 'bg-amber-500';
      case 'Ruim': return 'bg-red-600';
      default: return 'bg-slate-400';
    }
  };

  const confirmNewInspection = (type: Inspection['type']) => {
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      inspectorName: DEFAULT_INSPECTOR,
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft'
    };
    setCurrent(newIns);
    saveToGlobalList(newIns);
    setView(type === 'Comparação' ? 'comparison' : 'editor');
  };

  const handleRunComparison = async () => {
    if (!pdfEntry || !pdfExit || !current) {
      alert("Selecione os dois laudos para perícia.");
      return;
    }
    setIsBusy(true);
    try {
      const res = await performComparisonAI(pdfEntry, pdfExit, settings, manualComparisonObs);
      const updatedCurrent: Inspection = { 
        ...current, 
        comparisonResult: {
          analysis: res.analysis,
          sources: res.sources,
          budget: "", 
          manualObservations: manualComparisonObs
        }, 
        status: 'completed' as const,
        date: new Date().toISOString()
      };
      setCurrent(updatedCurrent);
      saveToGlobalList(updatedCurrent);
      setView('report');
    } catch(e: any) { 
      console.error("Erro Comparação Pericial:", e);
      // Tratamento específico para erro 413 (Entity Too Large)
      if (e.message?.includes("413") || e.status === 413) {
        alert("DOCUMENTOS MUITO EXTENSOS: Os PDFs selecionados possuem muitas imagens ou alta resolução, excedendo o limite de processamento simultâneo. \n\nSOLUÇÃO: Utilize versões otimizadas dos PDFs ou arquivos com menos de 15MB cada.");
      } else {
        alert(`Não foi possível completar a perícia: ${e.message || 'Verifique sua conexão e tente novamente.'}`); 
      }
    } finally { 
      setIsBusy(false); 
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string) => void) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        const base64 = result.includes(',') ? result.split(',')[1] : result;
        setter(base64);
      };
      reader.readAsDataURL(file);
    } else if (file) {
      alert("Apenas arquivos PDF.");
      e.target.value = '';
    }
  };

  return (
