                 <div className="space-y-3 pt-4">
                   <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Foco da Perícia (Observações)</label>
                   <textarea className="w-full bg-slate-50 p-6 rounded-[2rem] border border-slate-200 text-xs h-36 focus:ring-4 focus:ring-red-50 outline-none transition-all" placeholder="Aponte focos específicos para a perícia de David Oliveira..." value={manualComparisonObs} onChange={(e) => setManualComparisonObs(e.target.value)} />
                 </div>
               </div>

               <button onClick={handleRunComparison} disabled={isBusy || !pdfEntry || !pdfExit} className="w-full mt-10 bg-slate-900 text-white py-6 rounded-[2rem] font-black uppercase text-xs shadow-2xl disabled:opacity-50 hover:bg-slate-800 transition-colors">
                 {isBusy ? "David Oliveira Periciando..." : "Gerar Perícia Comparativa"}
               </button>
               <button onClick={() => setView('list')} className="w-full mt-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cancelar e Voltar</button>
             </div>
          </div>
        )}

        {view === 'editor' && current && (
          <div className="space-y-6 pb-40 animate-in fade-in duration-500">
            <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1 h-full bg-red-600"></div>
              <input className="w-full text-2xl font-black border-none focus:ring-0 p-0 uppercase tracking-tighter mb-6 bg-transparent" placeholder="Endereço do Imóvel" value={current.address} onChange={(e) => updateCurrent({ address: e.target.value })} />
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Locador / Proprietário</label>
                  <input className="w-full bg-slate-50 p-4 rounded-2xl text-xs font-bold border-none" value={current.clientName} onChange={(e) => updateCurrent({ clientName: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Locatário / Proponente</label>
                  <input className="w-full bg-slate-50 p-4 rounded-2xl text-xs font-bold border-none" value={current.tenantName} onChange={(e) => updateCurrent({ tenantName: e.target.value })} />
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center px-4">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Checklist por Ambientes</h3>
                <select className="bg-slate-900 text-white text-[10px] font-black px-6 py-3 rounded-2xl shadow-xl border-none cursor-pointer" onChange={(e) => e.target.value && addRoom(e.target.value)} value="">
                  <option value="" disabled>+ NOVO AMBIENTE</option>
                  {COMMON_ROOMS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              {current.rooms.map(room => (
                <div key={room.id} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm group hover:border-red-500 transition-all">
                  <div className="p-6 flex justify-between items-center cursor-pointer" onClick={() => setEditingRoom(editingRoom === room.id ? null : room.id)}>
                    <div className="flex items-center gap-5">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black shadow-lg ${getStatusColor(room.condition)}`}>
                        {room.condition.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 uppercase text-xs">{room.customName || room.type}</h4>
                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{room.photos.length} Fotos • {room.condition}</span>
                      </div>
                    </div>
                    {processingRoomId === room.id ? (
                      <span className="text-[9px] font-black text-red-600 animate-pulse uppercase tracking-widest">Analisando...</span>
                    ) : (
                      <svg className={`w-4 h-4 text-slate-300 transition-transform duration-300 ${editingRoom === room.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                    )}
                  </div>

                  {editingRoom === room.id && (
                    <div className="p-8 border-t border-slate-50 space-y-8 bg-slate-50/20">
                      <div className="grid grid-cols-2 gap-8">
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Nome do Ambiente</label>
                          <input className="w-full bg-white p-4 rounded-2xl text-xs font-bold border border-slate-200" placeholder="Ex: Sala de Jantar" value={room.customName || ''} onChange={(e) => updateRoom(room.id, { customName: e.target.value })} />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Qualificação do Estado</label>
                          <div className="flex gap-1.5 p-1 bg-white rounded-2xl border border-slate-200">
                            {(['Ótimo', 'Bom', 'Regular', 'Ruim'] as const).map(s => (
                              <button key={s} onClick={() => updateRoom(room.id, { condition: s })} className={`flex-1 text-[8px] font-black py-2.5 rounded-xl uppercase transition-all ${room.condition === s ? getStatusColor(s) + ' text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>{s}</button>
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-6">
                        <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                        <VideoUploader onVideosAdded={(newVideos) => updateRoom(room.id, { videos: [...room.videos, ...newVideos] })} />
                      </div>

                      {/* Grade de Fotos */}
                      {room.photos.length > 0 && (
                        <div className="grid grid-cols-5 gap-3">
                          {room.photos.map(photo => (
                            <div key={photo.id} className="relative group aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                               <img src={photo.data} className="w-full h-full object-cover" />
                               <button onClick={() => updateRoom(room.id, { photos: room.photos.filter(p => p.id !== photo.id) })} className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-lg opacity-0 group-hover:opacity-100 transition-all shadow-lg">
                                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                               </button>
                            </div>
                          ))}
                        </div>
                      )}

                      <div className="space-y-4">
                        <div className="flex gap-3 bg-slate-900 p-2.5 rounded-2xl shadow-xl items-center">
                           <VoiceTranscription settings={settings} onTranscriptionComplete={(text) => updateRoom(room.id, { description: (room.description + '\n' + text).trim() })} />
                           <button onClick={() => handleManualRoomAnalysis(room.id)} disabled={processingRoomId === room.id} className="px-5 py-2.5 bg-red-600 text-white rounded-xl text-[9px] font-black uppercase transition-all active:scale-95 disabled:opacity-50 hover:bg-red-700">Análise Pericial IA</button>
                        </div>
                        <textarea className="w-full bg-white p-6 rounded-[2rem] border border-slate-200 text-xs h-64 leading-relaxed font-medium outline-none focus:ring-4 focus:ring-red-50 transition-all" placeholder="A IA David Oliveira gerará o laudo técnico com base nas fotos e áudio..." value={room.description} onChange={(e) => updateRoom(room.id, { description: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50 to-transparent no-print pointer-events-none z-40">
              <div className="max-w-md mx-auto grid grid-cols-2 gap-4 pointer-events-auto">
                <button onClick={() => setView('list')} className="bg-slate-200 text-slate-700 py-5 rounded-[2.5rem] font-black uppercase text-[10px] tracking-widest shadow-lg active:scale-95 transition-all">Pausar e Salvar</button>
                <button onClick={() => { updateCurrent({ status: 'completed', date: new Date().toISOString() }); setView('report'); }} className="bg-slate-900 text-white py-5 rounded-[2.5rem] font-black uppercase text-[10px] tracking-widest shadow-2xl active:scale-95 transition-all">Finalizar e Gerar Laudo</button>
              </div>
            </div>
          </div>
        )}

        {view === 'report' && current && (
          <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl mb-24 animate-in zoom-in-95 duration-700">
            <div className="mb-10 no-print flex justify-between items-center">
              <button onClick={() => setView(current.type === 'Comparação' ? 'comparison' : 'editor')} className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-colors">Voltar ao Editor</button>
              <button onClick={() => window.print()} className="bg-red-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-red-700 transition-colors">Imprimir Laudo PDF</button>
            </div>
            <InspectionReport inspection={current} />
          </div>
        )}
      </main>

      {isBusy && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-10 animate-in fade-in duration-500">
          <div className="bg-white p-16 rounded-[4rem] max-w-sm w-full text-center shadow-2xl border border-red-50">
            <div className="w-24 h-24 border-4 border-red-600 border-t-transparent rounded-full animate-spin mx-auto mb-10"></div>
            <h3 className="font-black text-slate-900 uppercase text-xl mb-4 tracking-tighter">Perícia David Oliveira</h3>
            <p className="text-[11px] text-slate-400 font-bold uppercase leading-relaxed tracking-widest">Aguarde, analisando divergências e custos de reparo via Google Search...</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface Photo {
  id: string;
  data: string; // base64
  mimeType: string;
}

export interface Video {
  id: string;
  data: string; // base64
  mimeType: string;
  thumbnail?: string;
  duration?: number;
  size?: number;
  processed?: boolean;
}

export interface AIAnalysis {
  itens: any;
  evidencias: Array<{
    timestampInicio: string;
    descricao: string;
    gravidade: string;
  }>;
}

export interface Room {
  id: string;
  type: string;
  customName?: string;
  description: string;
  photos: Photo[];
  videos: Video[];
  condition: 'Ótimo' | 'Bom' | 'Regular' | 'Ruim';
  aiAnalysis?: AIAnalysis;
}

export interface BudgetLink {
  title: string;
  uri: string;
}

export interface ComparisonResult {
  analysis: string;
  budget: string;
  sources: BudgetLink[];
  manualObservations?: string;
}

export interface AppSettings {
  detailLevel: 'Conciso' | 'Normal' | 'Muito Detalhado';
  defaultSeverity: 'Baixa' | 'Média' | 'Alta';
  tone: 'Técnico' | 'Formal' | 'Direto';
}

export interface Inspection {
  id: string;
  clientName: string; // Proprietário
  tenantName: string; // Locatário / Interessado
  inspectorName: string; // Responsável pela Vistoria
  type: 'Entrada' | 'Saída' | 'Constatação' | 'Comparação'; 
  address: string;
  date: string;
  rooms: Room[];
  status: 'draft' | 'completed';
  isSynced?: boolean; // Novo campo para simular upload cloud
  comparisonResult?: ComparisonResult;
  shareToken?: string;
}

export const COMMON_ROOMS = [
  "Sala de Estar", "Cozinha", "Dormitório", "Suíte", "Banheiro Social",
  "Varanda/Sacada", "Área de Serviço", "Garagem", "Escritório", "Lavabo",
  "Quintal", "Corredor"
];

import React, { useState, useEffect, useMemo } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video, AppSettings } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomMediaAI } from './services/geminiService';

const DEFAULT_INSPECTOR = "David Oliveira - Creci 84926-F";
const DEFAULT_SETTINGS: AppSettings = {
  detailLevel: 'Normal',
  defaultSeverity: 'Média',
  tone: 'Técnico'
};

const MAX_TOTAL_PDF_SIZE_MB = 15;

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison' | 'type_selector' | 'settings'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);
  const [pdfEntrySize, setPdfEntrySize] = useState(0);
  const [pdfExitSize, setPdfExitSize] = useState(0);
  const [manualComparisonObs, setManualComparisonObs] = useState('');

  useEffect(() => {
    Promise.all([
      localforage.getItem<Inspection[]>('qdez_rascunhos'),
      localforage.getItem<AppSettings>('qdez_settings')
    ]).then(([storedInspections, storedSettings]) => {
      if (storedInspections) setInspections(storedInspections);
      if (storedSettings) setSettings(storedSettings);
      setIsLoaded(true);
    });
  }, []);

  useEffect(() => {
    if (isLoaded) {
      localforage.setItem('qdez_rascunhos', inspections);
      localforage.setItem('qdez_settings', settings);
    }
  }, [inspections, settings, isLoaded]);

  const saveToGlobalList = (updatedIns: Inspection) => {
    setInspections(prev => {
      const filtered = prev.filter(i => i.id !== updatedIns.id);
      return [updatedIns, ...filtered];
    });
    setLastSaved(new Date().toLocaleTimeString());
  };

  // Simulação da função Python upload_midia_vistoria
  const handleSyncToCloud = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const ins = inspections.find(i => i.id === id);
    if (!ins) return;

    setIsBusy(true);
    // Simulando delay de upload de mídia (fotos/vídeos) para o bucket
    await new Promise(resolve => setTimeout(resolve, 2000));

    const updated = { ...ins, isSynced: true };
    saveToGlobalList(updated);
    setIsBusy(false);
    alert(`Vistoria ${id} sincronizada com sucesso no Storage Qdez!`);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Deseja excluir esta vistoria?")) {
      setInspections(prev => prev.filter(ins => ins.id !== id));
      if (current?.id === id) setCurrent(null);
    }
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    saveToGlobalList(updated);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedIns = { ...current, rooms: updatedRooms };
    setCurrent(updatedIns);
    saveToGlobalList(updatedIns);
  };

  const handleManualRoomAnalysis = async (roomId: string) => {
    if (!current) return;
    const room = current.rooms.find(r => r.id === roomId);
    if (!room || (room.photos.length === 0 && room.videos.length === 0)) {
      alert("Adicione mídias para análise.");
      return;
    }
    setProcessingRoomId(roomId);
    try {
      const media = [
        ...room.photos.map(p => ({ data: p.data, mimeType: p.mimeType })),
        ...room.videos.map(v => ({ data: v.data, mimeType: v.mimeType }))
      ];
      const result = await analyzeRoomMediaAI(room.customName || room.type, current.type, media.slice(-10), settings);
      if (result) {
        const itemsText = result.itensIdentificados.map((i: any) => `- ${i.item}: ${i.estado}. ${i.detalhes}`).join('\n');
        updateRoom(roomId, { 
          description: `${result.descricaoGeral}\n\nITENS IDENTIFICADOS:\n${itemsText}`,
          condition: result.estadoConservacao,
        });
      }
    } catch (error) {
      alert("Erro na análise.");
    } finally {
      setProcessingRoomId(null);
    }
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    updateCurrent({ rooms: [...current.rooms, newRoom] });
    setEditingRoom(newRoom.id);
  };

  const confirmNewInspection = (type: Inspection['type']) => {
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      inspectorName: DEFAULT_INSPECTOR,
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft',
      isSynced: false
    };
    setCurrent(newIns);
    saveToGlobalList(newIns);
    setView(type === 'Comparação' ? 'comparison' : 'editor');
  };

  const handleRunComparison = async () => {
    if (!pdfEntry || !pdfExit || !current) return;
    if ((pdfEntrySize + pdfExitSize) / (1024 * 1024) > MAX_TOTAL_PDF_SIZE_MB) {
      alert("Arquivos muito grandes.");
      return;
    }
    setIsBusy(true);
    try {
      const res = await performComparisonAI(pdfEntry, pdfExit, settings, manualComparisonObs);
      const updated: Inspection = { 
        ...current, 
        comparisonResult: { analysis: res.analysis, sources: res.sources, budget: "", manualObservations: manualComparisonObs }, 
        status: 'completed',
        date: new Date().toISOString()
      };
      setCurrent(updated);
      saveToGlobalList(updated);
      setView('report');
    } catch (e) {
      alert("Erro na perícia.");
    } finally { setIsBusy(false); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string) => void, sizeSetter: (size: number) => void) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      sizeSetter(file.size);
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        setter(result.includes(',') ? result.split(',')[1] : result);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 text-white p-4 sticky top-0 z-50 shadow-lg no-print">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('list')}>
            <div className="w-8 h-8 bg-red-600 rounded flex items-center justify-center font-black">Q</div>
            <h1 className="font-black uppercase text-sm tracking-tighter">Qdez Vistoria AI</h1>
          </div>
          <div className="flex gap-4 items-center">
            <button onClick={() => setView('settings')} className="p-2 text-slate-400 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
            </button>
            <button onClick={() => setView('type_selector')} className="bg-red-600 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase hover:bg-red-700 transition-colors shadow-lg">+ Nova Vistoria</button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 w-full flex-1">
        {view === 'settings' && (
          <div className="max-w-xl mx-auto py-10 animate-in fade-in zoom-in-95 duration-300">
            <div className="bg-white p-10 rounded-[3rem] shadow-2xl border border-slate-100">
              <h2 className="text-xl font-black uppercase tracking-tighter mb-8">Parâmetros David Oliveira</h2>
              <div className="space-y-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Nível de Detalhamento Técnico</label>
                  <div className="grid grid-cols-3 gap-2 p-1 bg-slate-50 rounded-2xl">
                    {(['Conciso', 'Normal', 'Muito Detalhado'] as const).map(option => (
                      <button key={option} onClick={() => setSettings(s => ({ ...s, detailLevel: option }))} className={`py-3 text-[9px] font-black uppercase rounded-xl transition-all ${settings.detailLevel === option ? 'bg-slate-900 text-white' : 'text-slate-400'}`}>
                        {option}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
              <button onClick={() => setView('list')} className="w-full mt-10 bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest">Salvar e Voltar</button>
            </div>
          </div>
        )}

        {view === 'list' && (
          <div className="space-y-8 animate-in fade-in duration-500">
            <section>
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Laudos Recentes</h2>
              <div className="grid gap-4">
                {!isLoaded ? (
                   <div className="p-20 text-center animate-pulse">Carregando Banco de Dados...</div>
                ) : (inspections.length === 0 ? (
                  <div className="p-16 border-2 border-dashed border-slate-200 rounded-[3rem] text-center bg-white/50">
                    <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Nenhum laudo ativo.</p>
                    <button onClick={() => setView('type_selector')} className="mt-4 text-red-600 font-black text-xs uppercase underline">Criar Vistoria</button>
                  </div>
                ) : (
                  inspections.map(ins => (
                    <div key={ins.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200 flex justify-between items-center hover:border-red-500 transition-all cursor-pointer group" onClick={() => { setCurrent(ins); setView(ins.type === 'Comparação' ? 'comparison' : 'editor'); }}>
                      <div className="flex-1">
                        <div className="flex gap-2 items-center mb-1">
                          <span className="text-[9px] font-black uppercase text-red-600 bg-red-50 px-2 py-0.5 rounded-full">{ins.type}</span>
                          <span className="text-[9px] font-bold text-slate-400">#{ins.id}</span>
                          {ins.isSynced ? (
                            <span className="text-[8px] font-black uppercase text-green-600 bg-green-50 px-2 py-0.5 rounded-full border border-green-100">Cloud Sync ✓</span>
                          ) : (
                            <span className="text-[8px] font-black uppercase text-amber-600 bg-amber-50 px-2 py-0.5 rounded-full border border-amber-100">Local Only</span>
                          )}
                        </div>
                        <h3 className="font-bold text-slate-800">{ins.address || 'Endereço Pendente'}</h3>
                        <p className="text-[10px] text-slate-500">Locatário: {ins.tenantName || 'Não informado'}</p>
                      </div>
                      <div className="flex gap-2">
                        {!ins.isSynced && (
                          <button onClick={(e) => handleSyncToCloud(ins.id, e)} className="w-10 h-10 rounded-full flex items-center justify-center bg-slate-50 text-slate-400 hover:text-blue-600 transition-all" title="Sincronizar Mídias Cloud">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>
                          </button>
                        )}
                        <button onClick={(e) => deleteInspection(ins.id, e)} className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-red-50 text-slate-300 hover:text-red-600 transition-all">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      </div>
                    </div>
                  ))
                ))}
              </div>
            </section>
          </div>
        )}

        {view === 'type_selector' && (
          <div className="max-w-md mx-auto pt-20 animate-in zoom-in-95 duration-300">
            <div className="bg-white p-10 rounded-[3rem] shadow-2xl border border-slate-100 text-center">
              <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-8">Novo Relatório</h2>
              <div className="grid gap-3">
                <button onClick={() => confirmNewInspection('Entrada')} className="p-5 rounded-2xl border-2 border-slate-100 hover:border-red-500 hover:bg-red-50 transition-all text-left">
                  <span className="block font-black text-slate-800 uppercase text-xs">Vistoria de Entrada</span>
                </button>
                <button onClick={() => confirmNewInspection('Saída')} className="p-5 rounded-2xl border-2 border-slate-100 hover:border-red-500 hover:bg-red-50 transition-all text-left">
                  <span className="block font-black text-slate-800 uppercase text-xs">Vistoria de Saída</span>
                </button>
                <button onClick={() => confirmNewInspection('Comparação')} className="p-5 rounded-2xl border-2 border-slate-100 hover:border-red-500 hover:bg-red-50 transition-all text-left">
                  <span className="block font-black text-slate-800 uppercase text-xs">Comparativo Pericial</span>
                </button>
              </div>
              <button onClick={() => setView('list')} className="mt-8 text-[10px] font-black text-slate-300 uppercase tracking-widest">Voltar</button>
            </div>
          </div>
        )}

        {view === 'comparison' && current && (
          <div className="max-w-xl mx-auto space-y-6 pt-10 pb-40 animate-in fade-in duration-500">
             <div className="bg-white p-10 rounded-[3rem] shadow-2xl border border-slate-100">
               <h2 className="text-2xl font-black mb-10 uppercase tracking-tighter">Comparativo IA</h2>

               <div className="space-y-6">
                 <div className={`p-8 rounded-[2rem] border-2 border-dashed transition-all ${pdfEntry ? 'bg-green-50 border-green-200' : 'bg-slate-50 border-slate-200'}`}>
                   <label className="text-[10px] font-black uppercase text-slate-400 block mb-4">Laudo de ENTRADA (PDF)</label>
                   {pdfEntry ? (
                     <div className="flex justify-between items-center">
                       <span className="text-green-700 font-bold uppercase text-xs">Arquivo OK ✓ ({(pdfEntrySize / 1024 / 1024).toFixed(1)}MB)</span>
                       <button onClick={() => { setPdfEntry(null); setPdfEntrySize(0); }} className="text-red-500 text-[10px] font-black uppercase underline">Trocar</button>
                     </div>
                   ) : (
                     <input type="file" accept=".pdf" onChange={(e) => handleFileUpload(e, setPdfEntry, setPdfEntrySize)} className="text-[10px] font-bold" />
                   )}
                 </div>

                 <div className={`p-8 rounded-[2rem] border-2 border-dashed transition-all ${pdfExit ? 'bg-green-50 border-green-200' : 'bg-slate-50 border-slate-200'}`}>
                   <label className="text-[10px] font-black uppercase text-slate-400 block mb-4">Laudo de SAÍDA (PDF)</label>
                   {pdfExit ? (
                     <div className="flex justify-between items-center">
                       <span className="text-green-700 font-bold uppercase text-xs">Arquivo OK ✓ ({(pdfExitSize / 1024 / 1024).toFixed(1)}MB)</span>
                       <button onClick={() => { setPdfExit(null); setPdfExitSize(0); }} className="text-red-500 text-[10px] font-black uppercase underline">Trocar</button>
                     </div>
                   ) : (
                     <input type="file" accept=".pdf" onChange={(e) => handleFileUpload(e, setPdfExit, setPdfExitSize)} className="text-[10px] font-bold" />
                   )}
                 </div>

                 <div className="space-y-4 pt-6 border-t">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Identificação das Partes</label>
                    <input className="w-full bg-slate-50 p-4 rounded-2xl text-[10px] font-black border border-slate-200 uppercase" placeholder="Locador / Cliente" value={current.clientName} onChange={(e) => updateCurrent({ clientName: e.target.value })} />
                    <input className="w-full bg-slate-50 p-4 rounded-2xl text-[10px] font-black border border-slate-200 uppercase" placeholder="Locatário / Proponente" value={current.tenantName} onChange={(e) => updateCurrent({ tenantName: e.target.value })} />
                    <input className="w-full bg-slate-50 p-4 rounded-2xl text-[10px] font-black border border-slate-200 uppercase" placeholder="Endereço do Imóvel" value={current.address} onChange={(e) => updateCurrent({ address: e.target.value })} />
                 </div>

                 <div className="space-y-3 pt-4">
                   <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Foco da Perícia (Observações)</label>
                   <textarea className="w-full bg-slate-50 p-6 rounded-[2rem] border border-slate-200 text-xs h-36 focus:ring-4 focus:ring-red-50 outline-none transition-all" placeholder="Aponte focos específicos para a perícia..." value={manualComparisonObs} onChange={(e) => setManualComparisonObs(e.target.value)} />
                 </div>
               </div>

               <button onClick={handleRunComparison} disabled={isBusy || !pdfEntry || !pdfExit} className="w-full mt-10 bg-slate-900 text-white py-6 rounded-[2rem] font-black uppercase text-xs shadow-2xl disabled:opacity-50 hover:bg-slate-800 transition-colors">
                 {isBusy ? "David Oliveira Periciando..." : "Gerar Perícia Comparativa"}
               </button>
               <button onClick={() => setView('list')} className="w-full mt-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cancelar</button>
             </div>
          </div>
        )}

        {view === 'editor' && current && (
          <div className="space-y-6 pb-40 animate-in fade-in duration-500">
            <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1 h-full bg-red-600"></div>
              <input className="w-full text-2xl font-black border-none focus:ring-0 p-0 uppercase tracking-tighter mb-6 bg-transparent" placeholder="Endereço do Imóvel" value={current.address} onChange={(e) => updateCurrent({ address: e.target.value })} />
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Locador / Proprietário</label>
                  <input className="w-full bg-slate-50 p-4 rounded-2xl text-xs font-bold border-none" value={current.clientName} onChange={(e) => updateCurrent({ clientName: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Locatário / Proponente</label>
                  <input className="w-full bg-slate-50 p-4 rounded-2xl text-xs font-bold border-none" value={current.tenantName} onChange={(e) => updateCurrent({ tenantName: e.target.value })} />
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center px-4">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Checklist por Ambientes</h3>
                <select className="bg-slate-900 text-white text-[10px] font-black px-6 py-3 rounded-2xl shadow-xl border-none cursor-pointer" onChange={(e) => e.target.value && addRoom(e.target.value)} value="">
                  <option value="" disabled>+ NOVO AMBIENTE</option>
                  {COMMON_ROOMS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              {current.rooms.map(room => (
                <div key={room.id} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm group hover:border-red-500 transition-all">
                  <div className="p-6 flex justify-between items-center cursor-pointer" onClick={() => setEditingRoom(editingRoom === room.id ? null : room.id)}>
                    <div className="flex items-center gap-5">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black shadow-lg ${getStatusColor(room.condition)}`}>
                        {room.condition.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 uppercase text-xs">{room.customName || room.type}</h4>
                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{room.photos.length} Fotos • {room.condition}</span>
                      </div>
                    </div>
                    {processingRoomId === room.id ? (
                      <span className="text-[9px] font-black text-red-600 animate-pulse uppercase tracking-widest">Analisando...</span>
                    ) : (
                      <svg className={`w-4 h-4 text-slate-300 transition-transform duration-300 ${editingRoom === room.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                    )}
                  </div>

                  {editingRoom === room.id && (
                    <div className="p-8 border-t border-slate-50 space-y-8 bg-slate-50/20">
                      <div className="grid grid-cols-2 gap-8">
                        <input className="w-full bg-white p-4 rounded-2xl text-xs font-bold border border-slate-200" placeholder="Nome do Ambiente" value={room.customName || ''} onChange={(e) => updateRoom(room.id, { customName: e.target.value })} />
                        <div className="flex gap-1.5 p-1 bg-white rounded-2xl border border-slate-200">
                          {(['Ótimo', 'Bom', 'Regular', 'Ruim'] as const).map(s => (
                            <button key={s} onClick={() => updateRoom(room.id, { condition: s })} className={`flex-1 text-[8px] font-black py-2.5 rounded-xl uppercase transition-all ${room.condition === s ? getStatusColor(s) + ' text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>{s}</button>
                          ))}
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-6">
                        <PhotoUploader onPhotosAdded={(newPhotos) => updateRoom(room.id, { photos: [...room.photos, ...newPhotos] })} />
                        <VideoUploader onVideosAdded={(newVideos) => updateRoom(room.id, { videos: [...room.videos, ...newVideos] })} />
                      </div>

                      {/* Grade de Fotos */}
                      {room.photos.length > 0 && (
                        <div className="grid grid-cols-5 gap-3">
                          {room.photos.map(photo => (
                            <div key={photo.id} className="relative group aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                               <img src={photo.data} className="w-full h-full object-cover" />
                               <button onClick={() => updateRoom(room.id, { photos: room.photos.filter(p => p.id !== photo.id) })} className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-lg opacity-0 group-hover:opacity-100 transition-all shadow-lg">
                                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                               </button>
                            </div>
                          ))}
                        </div>
                      )}

                      <div className="space-y-4">
                        <div className="flex gap-3 bg-slate-900 p-2.5 rounded-2xl shadow-xl items-center">
                           <VoiceTranscription settings={settings} onTranscriptionComplete={(text) => updateRoom(room.id, { description: (room.description + '\n' + text).trim() })} />
                           <button onClick={() => handleManualRoomAnalysis(room.id)} disabled={processingRoomId === room.id} className="px-5 py-2.5 bg-red-600 text-white rounded-xl text-[9px] font-black uppercase transition-all active:scale-95 disabled:opacity-50 hover:bg-red-700">Análise Pericial IA</button>
                        </div>
                        <textarea className="w-full bg-white p-6 rounded-[2rem] border border-slate-200 text-xs h-64 leading-relaxed font-medium outline-none focus:ring-4 focus:ring-red-50 transition-all" placeholder="A IA David Oliveira gerará o laudo técnico..." value={room.description} onChange={(e) => updateRoom(room.id, { description: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50 to-transparent no-print pointer-events-none z-40">
              <div className="max-w-md mx-auto grid grid-cols-2 gap-4 pointer-events-auto">
                <button onClick={() => setView('list')} className="bg-slate-200 text-slate-700 py-5 rounded-[2.5rem] font-black uppercase text-[10px] tracking-widest shadow-lg">Pausar</button>
                <button onClick={() => { updateCurrent({ status: 'completed', date: new Date().toISOString() }); setView('report'); }} className="bg-slate-900 text-white py-5 rounded-[2.5rem] font-black uppercase text-[10px] tracking-widest shadow-2xl">Gerar Laudo Final</button>
              </div>
            </div>
          </div>
        )}

        {view === 'report' && current && (
          <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl mb-24 animate-in zoom-in-95 duration-700">
            <div className="mb-10 no-print flex justify-between items-center">
              <button onClick={() => setView(current.type === 'Comparação' ? 'comparison' : 'editor')} className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Voltar</button>
              <button onClick={() => window.print()} className="bg-red-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl">Imprimir PDF</button>
            </div>
            <InspectionReport inspection={current} />
          </div>
        )}
      </main>

      {isBusy && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-10 animate-in fade-in duration-500">
          <div className="bg-white p-16 rounded-[4rem] max-w-sm w-full text-center shadow-2xl border border-red-50">
            <div className="w-24 h-24 border-4 border-red-600 border-t-transparent rounded-full animate-spin mx-auto mb-10"></div>
            <h3 className="font-black text-slate-900 uppercase text-xl mb-4 tracking-tighter">Perícia David Oliveira</h3>
            <p className="text-[11px] text-slate-400 font-bold uppercase leading-relaxed tracking-widest">Processando mídias e sincronizando com o servidor...</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import localforage from 'localforage';
import { Inspection, Room, COMMON_ROOMS, Photo, Video, AppSettings } from './types';
import PhotoUploader from './components/PhotoUploader';
import VideoUploader from './components/VideoUploader';
import VoiceTranscription from './components/VoiceTranscription';
import InspectionReport from './components/InspectionReport';
import { performComparisonAI, analyzeRoomMediaAI } from './services/geminiService';

const DEFAULT_INSPECTOR = "David Oliveira - Creci 84926-F";
const DEFAULT_SETTINGS: AppSettings = {
  detailLevel: 'Normal',
  defaultSeverity: 'Média',
  tone: 'Técnico'
};

const MAX_TOTAL_PDF_SIZE_MB = 15;

// Helper function to return CSS background classes based on room condition
const getStatusColor = (status: Room['condition']) => {
  switch (status) {
    case 'Ótimo': return 'bg-emerald-500';
    case 'Bom': return 'bg-blue-500';
    case 'Regular': return 'bg-amber-500';
    case 'Ruim': return 'bg-red-500';
    default: return 'bg-slate-500';
  }
};

const App: React.FC = () => {
  const [inspections, setInspections] = useState<Inspection[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [current, setCurrent] = useState<Inspection | null>(null);
  const [view, setView] = useState<'list' | 'editor' | 'report' | 'comparison' | 'type_selector' | 'settings'>('list');
  const [isBusy, setIsBusy] = useState(false);
  const [editingRoom, setEditingRoom] = useState<string | null>(null);
  const [processingRoomId, setProcessingRoomId] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [pdfEntry, setPdfEntry] = useState<string | null>(null);
  const [pdfExit, setPdfExit] = useState<string | null>(null);
  const [pdfEntrySize, setPdfEntrySize] = useState(0);
  const [pdfExitSize, setPdfExitSize] = useState(0);
  const [manualComparisonObs, setManualComparisonObs] = useState('');

  useEffect(() => {
    Promise.all([
      localforage.getItem<Inspection[]>('qdez_rascunhos'),
      localforage.getItem<AppSettings>('qdez_settings')
    ]).then(([storedInspections, storedSettings]) => {
      if (storedInspections) setInspections(storedInspections);
      if (storedSettings) setSettings(storedSettings);
      setIsLoaded(true);
    });
  }, []);

  useEffect(() => {
    if (isLoaded) {
      localforage.setItem('qdez_rascunhos', inspections);
      localforage.setItem('qdez_settings', settings);
    }
  }, [inspections, settings, isLoaded]);

  const saveToGlobalList = (updatedIns: Inspection) => {
    setInspections(prev => {
      const filtered = prev.filter(i => i.id !== updatedIns.id);
      return [updatedIns, ...filtered];
    });
    setLastSaved(new Date().toLocaleTimeString());
  };

  // Simulação da função Python upload_midia_vistoria
  const handleSyncToCloud = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const ins = inspections.find(i => i.id === id);
    if (!ins) return;

    setIsBusy(true);
    // Simulando delay de upload de mídia (fotos/vídeos) para o bucket
    await new Promise(resolve => setTimeout(resolve, 2000));

    const updated = { ...ins, isSynced: true };
    saveToGlobalList(updated);
    setIsBusy(false);
    alert(`Vistoria ${id} sincronizada com sucesso no Storage Qdez!`);
  };

  const deleteInspection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Deseja excluir esta vistoria?")) {
      setInspections(prev => prev.filter(ins => ins.id !== id));
      if (current?.id === id) setCurrent(null);
    }
  };

  const updateCurrent = (updates: Partial<Inspection>) => {
    if (!current) return;
    const updated = { ...current, ...updates };
    setCurrent(updated);
    saveToGlobalList(updated);
  };

  const updateRoom = (roomId: string, updates: Partial<Room>) => {
    if (!current) return;
    const updatedRooms = current.rooms.map(r => r.id === roomId ? { ...r, ...updates } : r);
    const updatedIns = { ...current, rooms: updatedRooms };
    setCurrent(updatedIns);
    saveToGlobalList(updatedIns);
  };

  const handleManualRoomAnalysis = async (roomId: string) => {
    if (!current) return;
    const room = current.rooms.find(r => r.id === roomId);
    if (!room || (room.photos.length === 0 && room.videos.length === 0)) {
      alert("Adicione mídias para análise.");
      return;
    }
    setProcessingRoomId(roomId);
    try {
      const media = [
        ...room.photos.map(p => ({ data: p.data, mimeType: p.mimeType })),
        ...room.videos.map(v => ({ data: v.data, mimeType: v.mimeType }))
      ];
      const result = await analyzeRoomMediaAI(room.customName || room.type, current.type, media.slice(-10), settings);
      if (result) {
        const itemsText = result.itensIdentificados.map((i: any) => `- ${i.item}: ${i.estado}. ${i.detalhes}`).join('\n');
        updateRoom(roomId, { 
          description: `${result.descricaoGeral}\n\nITENS IDENTIFICADOS:\n${itemsText}`,
          condition: result.estadoConservacao,
        });
      }
    } catch (error) {
      alert("Erro na análise.");
    } finally {
      setProcessingRoomId(null);
    }
  };

  const addRoom = (type: string) => {
    if (!current) return;
    const newRoom: Room = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: '',
      photos: [],
      videos: [],
      condition: 'Bom'
    };
    updateCurrent({ rooms: [...current.rooms, newRoom] });
    setEditingRoom(newRoom.id);
  };

  const confirmNewInspection = (type: Inspection['type']) => {
    const id = 'VST-' + Math.random().toString(36).substr(2, 6).toUpperCase();
    const newIns: Inspection = {
      id,
      clientName: '',
      tenantName: '',
      inspectorName: DEFAULT_INSPECTOR,
      type,
      address: '',
      date: new Date().toISOString(),
      rooms: [],
      status: 'draft',
      isSynced: false
    };
    setCurrent(newIns);
    saveToGlobalList(newIns);
    setView(type === 'Comparação' ? 'comparison' : 'editor');
  };

  const handleRunComparison = async () => {
    if (!pdfEntry || !pdfExit || !current) return;
    if ((pdfEntrySize + pdfExitSize) / (1024 * 1024) > MAX_TOTAL_PDF_SIZE_MB) {
      alert("Arquivos muito grandes.");
      return;
    }
    setIsBusy(true);
    try {
      const res = await performComparisonAI(pdfEntry, pdfExit, settings, manualComparisonObs);
      const updated: Inspection = { 
        ...current, 
        comparisonResult: { analysis: res.analysis, sources: res.sources, budget: "", manualObservations: manualComparisonObs }, 
        status: 'completed',
        date: new Date().toISOString()
      };
      setCurrent(updated);
      saveToGlobalList(updated);
      setView('report');
    } catch (e) {
      alert("Erro na perícia.");
    } finally { setIsBusy(false); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string) => void, sizeSetter: (size: number) => void) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      sizeSetter(file.size);
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        setter(result.includes(',') ? result.split(',')[1] : result);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-slate-900 text-white p-4 sticky top-0 z-50 shadow-lg no-print">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
